// --- UTILS & SHARED LOGIC ---

const toTitleCase = (str) => {
  if (!str) return '';
  return str.toLowerCase().split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(' ');
};

const capitalizeFirst = (str) => {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1);
};

const capitalizeFirstPreservingSpacing = (str = '') => {
  const rawValue = `${str}`;
  const firstVisibleCharIndex = rawValue.search(/\S/);
  if (firstVisibleCharIndex < 0) return rawValue;
  return `${rawValue.slice(0, firstVisibleCharIndex)}${rawValue.charAt(firstVisibleCharIndex).toUpperCase()}${rawValue.slice(firstVisibleCharIndex + 1)}`;
};

const toTitleCasePreservingSpacing = (str = '') => `${str || ''}`.replace(/[^\s]+/g, word => (
  `${word.charAt(0).toUpperCase()}${word.slice(1).toLowerCase()}`
));

const normalizeLeadingLabel = (str = '') => capitalizeFirst(`${str}`.trim());
const normalizeProductGroups = (groups = []) => {
  const seen = new Set();
  return (Array.isArray(groups) ? groups : [])
    .map(group => normalizeLeadingLabel(group))
    .filter(group => {
      const key = normalizeLookupText(group);
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    });
};
const normalizeWarehouseStockVisibilitySettings = (settings = {}) => {
  const hiddenGroupKeys = Array.from(new Set(
    (Array.isArray(settings?.hiddenGroupKeys) ? settings.hiddenGroupKeys : [])
      .map(key => `${key || ''}`.trim())
      .filter(Boolean)
  ));
  const hiddenUnitKeysByGroup = Object.entries(settings?.hiddenUnitKeysByGroup || {}).reduce((acc, [groupKey, unitKeys]) => {
    const safeGroupKey = `${groupKey || ''}`.trim();
    if (!safeGroupKey || !Array.isArray(unitKeys)) return acc;
    const normalizedUnitKeys = Array.from(new Set(
      unitKeys.map(unitKey => normalizeLookupText(unitKey)).filter(Boolean)
    ));
    if (normalizedUnitKeys.length > 0) acc[safeGroupKey] = normalizedUnitKeys;
    return acc;
  }, {});
  return { hiddenGroupKeys, hiddenUnitKeysByGroup };
};
const normalizeExpenseCategoryLabel = (str = '') => normalizeLeadingLabel(str);
const resolveSalaryMonthDays = (employee = {}, monthKey = getTodayString().substring(0, 7)) => {
  const parsed = parseInt(employee?.salaryMonthDays, 10);
  return parsed > 0 ? parsed : getActualCalendarDaysInMonth(monthKey);
};

const formatInputCurrency = (val) => {
  if (val === '' || val === undefined || val === null) return '';
  const num = parseInt(val.toString().replace(/\D/g, ''), 10);
  return isNaN(num) ? '' : new Intl.NumberFormat('vi-VN').format(num);
};

const parseInputCurrency = (val) => {
  if (val === '' || val === undefined || val === null) return '';
  const num = parseInt(val.toString().replace(/\D/g, ''), 10);
  return isNaN(num) ? '' : num;
};

const parseMinutesInput = (val, fallback = 0) => {
  if (val === '' || val === undefined || val === null) return fallback;
  const parsed = parseInt(val, 10);
  return Number.isNaN(parsed) ? fallback : parsed;
};

const normalizeLatePenaltyTiers = (tiers = DEFAULT_LATE_PENALTY_TIERS) => {
  const source = Array.isArray(tiers) && tiers.length > 0 ? tiers : DEFAULT_LATE_PENALTY_TIERS;
  return source
    .map((tier, index) => {
      const lateMinutes = Math.max(0, parseMinutesInput(tier?.lateMinutes ?? tier?.minutes, 0));
      const action = tier?.action === 'no_salary' ? 'no_salary' : 'fine';
      const penaltyAmount = action === 'no_salary' ? 0 : (parseInputCurrency(tier?.penaltyAmount ?? tier?.amount ?? 0) || 0);
      return {
        id: tier?.id || `late_${lateMinutes || index}`,
        lateMinutes,
        penaltyAmount,
        action
      };
    })
    .filter(tier => tier.lateMinutes > 0)
    .sort((a, b) => a.lateMinutes - b.lateMinutes);
};

const getEmployeeLatePenaltyTiers = (employee = {}) => normalizeLatePenaltyTiers(
  Object.prototype.hasOwnProperty.call(employee || {}, 'latePenaltyTiers')
    ? employee.latePenaltyTiers
    : DEFAULT_LATE_PENALTY_TIERS
);

const resolveLatePenaltyForMinutes = (lateMinutes = 0, tiers = DEFAULT_LATE_PENALTY_TIERS) => {
  const normalizedMinutes = Math.max(0, parseMinutesInput(lateMinutes, 0));
  if (normalizedMinutes <= 0) return { lateMinutes: normalizedMinutes, penaltyAmount: 0, noSalaryDay: false, matchedTier: null };
  const normalizedTiers = normalizeLatePenaltyTiers(tiers);
  // Each row is the lower bound of a range. The selected row is the
  // highest configured bound that the actual late duration reaches.
  let matchedTierIndex = -1;
  normalizedTiers.forEach((tier, index) => {
    if (normalizedMinutes >= tier.lateMinutes) matchedTierIndex = index;
  });
  const matchedTier = matchedTierIndex >= 0 ? normalizedTiers[matchedTierIndex] : null;
  if (!matchedTier) return { lateMinutes: normalizedMinutes, penaltyAmount: 0, noSalaryDay: false, matchedTier: null };
  const nextTier = normalizedTiers[matchedTierIndex + 1] || null;
  return {
    lateMinutes: normalizedMinutes,
    penaltyAmount: matchedTier.action === 'fine' ? roundMoneyValue(matchedTier.penaltyAmount || 0) : 0,
    noSalaryDay: matchedTier.action === 'no_salary',
    matchedTier: {
      ...matchedTier,
      maxLateMinutes: nextTier ? nextTier.lateMinutes - 1 : null
    }
  };
};

const parseAttendanceTimestamp = (value = null) => {
  if (!value) return null;
  const parsed = value instanceof Date ? value : new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};

const calculateAttendanceTiming = (employee = {}, entry = {}) => {
  const normalizedEntry = normalizeAttendanceRecordForWorkDate(entry, employee, entry?.date);
  const checkInDate = parseAttendanceTimestamp(normalizedEntry?.checkIn);
  const checkOutDate = parseAttendanceTimestamp(normalizedEntry?.checkOut);
  if (!checkInDate || !entry?.date) {
    return { lateMinutes: 0, earlyOvertimeMinutes: 0, afterShiftOvertimeMinutes: 0, autoOvertimeMinutes: 0, latePenaltyAmount: 0, noSalaryDay: false, matchedLateTier: null };
  }
  const shiftPolicy = resolveEmployeeShiftPolicy(employee);
  const { start: shiftStart, end: shiftEnd } = buildShiftRangeDateTimes(entry.date, shiftPolicy.shiftStart, shiftPolicy.shiftEnd);
  if (Number.isNaN(shiftStart.getTime()) || Number.isNaN(shiftEnd.getTime())) {
    return { lateMinutes: 0, earlyOvertimeMinutes: 0, afterShiftOvertimeMinutes: 0, autoOvertimeMinutes: 0, latePenaltyAmount: 0, noSalaryDay: false, matchedLateTier: null };
  }
  const diffMinutes = Math.round((checkInDate.getTime() - shiftStart.getTime()) / 60000);
  const lateMinutes = Math.max(0, diffMinutes);
  const earlyOvertimeMinutes = employee?.autoEarlyOvertimeEnabled === false ? 0 : Math.max(0, -diffMinutes);
  const afterShiftOvertimeMinutes = employee?.autoLateCheckoutOvertimeEnabled === false || !checkOutDate
    ? 0
    : Math.max(0, Math.round((checkOutDate.getTime() - shiftEnd.getTime()) / 60000));
  const latePenalty = resolveLatePenaltyForMinutes(lateMinutes, getEmployeeLatePenaltyTiers(employee));
  return {
    lateMinutes,
    earlyOvertimeMinutes,
    afterShiftOvertimeMinutes,
    autoOvertimeMinutes: earlyOvertimeMinutes + afterShiftOvertimeMinutes,
    latePenaltyAmount: latePenalty.penaltyAmount || 0,
    noSalaryDay: latePenalty.noSalaryDay,
    matchedLateTier: latePenalty.matchedTier
  };
};

const formatCurrency = (amount) => {
  if (amount === undefined || amount === null || isNaN(amount)) return '0';
  return new Intl.NumberFormat('vi-VN').format(Math.round(Number(amount) || 0));
};

const roundMoneyValue = (amount) => {
  if (amount === undefined || amount === null || Number.isNaN(Number(amount))) return 0;
  return Math.round(Number(amount) || 0);
};

const DEFAULT_SALARY_ADVANCE_PERCENT = 30;

const normalizeSalaryAdvancePercent = (value) => {
  if (value === undefined || value === null || value === '') return DEFAULT_SALARY_ADVANCE_PERCENT;
  const parsed = parseFloat(`${value}`.replace(',', '.').replace(/[^\d.]/g, ''));
  if (!Number.isFinite(parsed)) return DEFAULT_SALARY_ADVANCE_PERCENT;
  return Math.max(0, Math.min(100, parsed));
};

const normalizeSalaryAdvancePercentOrNull = (value) => {
  if (value === undefined || value === null || `${value}`.trim() === '') return null;
  const parsed = parseFloat(`${value}`.replace(',', '.').replace(/[^\d.]/g, ''));
  if (!Number.isFinite(parsed)) return null;
  return Math.max(0, Math.min(100, parsed));
};

const getCompanySalaryAdvancePercent = (company = null) => normalizeSalaryAdvancePercent(
  company?.salaryAdvancePercent ?? company?.payrollAdvancePercent ?? DEFAULT_SALARY_ADVANCE_PERCENT
);

const normalizeCompanySalaryAdvancePercentByDepartment = (source = {}, fallbackPercent = DEFAULT_SALARY_ADVANCE_PERCENT) => {
  const fallback = normalizeSalaryAdvancePercent(fallbackPercent);
  return SALARY_ADVANCE_DEPARTMENT_OPTIONS.reduce((acc, department) => {
    const hasExplicitValue = Object.prototype.hasOwnProperty.call(source || {}, department.key);
    if (!hasExplicitValue) {
      acc[department.key] = fallback;
    } else {
      acc[department.key] = normalizeSalaryAdvancePercentOrNull(source?.[department.key]);
    }
    return acc;
  }, {});
};

const getCompanySalaryAdvancePercentByDepartment = (company = null) => normalizeCompanySalaryAdvancePercentByDepartment(
  company?.salaryAdvancePercentByDepartment || company?.salaryAdvancePercentsByDepartment || {},
  getCompanySalaryAdvancePercent(company)
);

const getEmployeeSalaryAdvancePercent = (company = null, employee = null, currentUser = null) => {
  const departmentKey = getEmployeeRolePermissionKey(employee, currentUser);
  if (departmentKey === 'owner') return getCompanySalaryAdvancePercent(company);
  const byDepartment = getCompanySalaryAdvancePercentByDepartment(company);
  return normalizeSalaryAdvancePercent(byDepartment?.[departmentKey] ?? getCompanySalaryAdvancePercent(company));
};

const getEmployeeSalaryAdvanceLimitConfig = (company = null, employee = null, currentUser = null) => {
  const departmentKey = getEmployeeRolePermissionKey(employee, currentUser);
  const byDepartment = company?.salaryAdvancePercentByDepartment || company?.salaryAdvancePercentsByDepartment || {};
  const hasDepartmentLimit = Object.prototype.hasOwnProperty.call(byDepartment, departmentKey);
  if (departmentKey !== 'owner' && hasDepartmentLimit) {
    const departmentPercent = normalizeSalaryAdvancePercentOrNull(byDepartment?.[departmentKey]);
    return departmentPercent === null
      ? { isUnlimited: true, percent: null, source: 'department' }
      : { isUnlimited: false, percent: departmentPercent, source: 'department' };
  }
  const hasCompanyLimit = company && (
    Object.prototype.hasOwnProperty.call(company, 'salaryAdvancePercent')
    || Object.prototype.hasOwnProperty.call(company, 'payrollAdvancePercent')
  );
  if (!hasCompanyLimit) return { isUnlimited: true, percent: null, source: 'none' };
  const companyPercent = normalizeSalaryAdvancePercentOrNull(company?.salaryAdvancePercent ?? company?.payrollAdvancePercent);
  return companyPercent === null
    ? { isUnlimited: true, percent: null, source: 'company' }
    : { isUnlimited: false, percent: companyPercent, source: 'company' };
};

const formatPercentValue = (value) => new Intl.NumberFormat('vi-VN', {
  maximumFractionDigits: 2
}).format(normalizeSalaryAdvancePercent(value));

const parseSalaryAdvancePercentSettingInput = (value) => {
  const text = `${value ?? ''}`.trim();
  if (!text) return { isUnlimited: true, percent: null, invalid: false };
  const parsed = parseFloat(text.replace(',', '.').replace(/[^\d.]/g, ''));
  if (!Number.isFinite(parsed)) return { isUnlimited: false, percent: null, invalid: true };
  return { isUnlimited: false, percent: Math.max(0, Math.min(100, parsed)), invalid: false };
};

const stringifySalaryAdvancePercentInput = (value) => (
  value === undefined || value === null || `${value}`.trim() === ''
    ? ''
    : `${normalizeSalaryAdvancePercent(value)}`
);

const buildSalaryAdvanceSettingsForm = (company = {}) => {
  const hasCompanyPercent = company && (
    Object.prototype.hasOwnProperty.call(company, 'salaryAdvancePercent')
    || Object.prototype.hasOwnProperty.call(company, 'payrollAdvancePercent')
  );
  const companyPercent = hasCompanyPercent
    ? (company?.salaryAdvancePercent ?? company?.payrollAdvancePercent)
    : '';
  const byDepartment = company?.salaryAdvancePercentByDepartment || company?.salaryAdvancePercentsByDepartment || {};
  return {
    salaryAdvancePercent: stringifySalaryAdvancePercentInput(companyPercent),
    salaryAdvancePercentByDepartment: SALARY_ADVANCE_DEPARTMENT_OPTIONS.reduce((acc, department) => {
      acc[department.key] = Object.prototype.hasOwnProperty.call(byDepartment || {}, department.key)
        ? stringifySalaryAdvancePercentInput(byDepartment?.[department.key])
        : '';
      return acc;
    }, {})
  };
};

const describeSalaryAdvanceLimitInput = (value) => {
  const parsed = parseSalaryAdvancePercentSettingInput(value);
  if (parsed.isUnlimited) return 'Không giới hạn, chờ duyệt';
  if (parsed.invalid) return 'Cần nhập số % hợp lệ';
  return `Tối đa ${new Intl.NumberFormat('vi-VN', { maximumFractionDigits: 2 }).format(parsed.percent)}% lương`;
};

const formatNumber = (value) => {
  if (value === undefined || value === null || Number.isNaN(value)) return '0';
  return new Intl.NumberFormat('vi-VN').format(value);
};

const isDateOnlyString = (value = '') => /^\d{4}-\d{2}-\d{2}$/.test(`${value || ''}`.trim());
const VIETNAM_TIME_ZONE = 'Asia/Ho_Chi_Minh';
const VIETNAM_DATE_FORMAT_OPTIONS = { timeZone: VIETNAM_TIME_ZONE };
const VIETNAM_TIME_FORMAT_OPTIONS = { hour: '2-digit', minute: '2-digit', timeZone: VIETNAM_TIME_ZONE };

const toLocalDateTimeString = (date = new Date()) => {
  const safeDate = date instanceof Date && !Number.isNaN(date.getTime()) ? date : new Date();
  const offsetMs = safeDate.getTimezoneOffset() * 60000;
  return new Date(safeDate.getTime() - offsetMs).toISOString().slice(0, 19);
};

const buildDateTimeFromDateKey = (dateKey = '', baseDate = new Date()) => {
  const text = `${dateKey || ''}`.trim();
  const safeBaseDate = baseDate instanceof Date && !Number.isNaN(baseDate.getTime()) ? baseDate : new Date();
  if (isDateOnlyString(text)) {
    const hour = String(safeBaseDate.getHours()).padStart(2, '0');
    const minute = String(safeBaseDate.getMinutes()).padStart(2, '0');
    const second = String(safeBaseDate.getSeconds()).padStart(2, '0');
    return `${text}T${hour}:${minute}:${second}`;
  }
  return text || toLocalDateTimeString(safeBaseDate);
};

const getDateKeyFromDateTime = (value = '') => {
  const match = `${value || ''}`.trim().match(/^(\d{4}-\d{2}-\d{2})/);
  return match ? match[1] : getTodayString();
};

const formatTime = (dateObj) => {
  if (!dateObj) return '--:--';
  if (typeof dateObj === 'string') {
    if (isDateOnlyString(dateObj)) return '--:--';
    const parsed = new Date(dateObj);
    if (!Number.isNaN(parsed.getTime())) {
      return parsed.toLocaleTimeString('vi-VN', VIETNAM_TIME_FORMAT_OPTIONS);
    }
    return dateObj.substring(11, 16) || '--:--';
  }
  return dateObj.toLocaleTimeString('vi-VN', VIETNAM_TIME_FORMAT_OPTIONS);
};

const formatDateLabel = (value) => {
  if (!value) return '--';
  if (typeof value === 'string' && isDateOnlyString(value)) return formatCompactDateLabel(value);
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? `${value}` : parsed.toLocaleDateString('vi-VN', VIETNAM_DATE_FORMAT_OPTIONS);
};

const formatCompactDateLabel = (value) => {
  if (!value) return '--';
  const text = `${value}`.trim();
  const dateOnlyMatch = text.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (dateOnlyMatch) {
    return `${dateOnlyMatch[3]}/${dateOnlyMatch[2]}/${dateOnlyMatch[1]}`;
  }
  return formatDateLabel(value);
};

const buildMonthKeyFromDate = (value = '') => {
  const text = `${value || ''}`.trim();
  const dateOnlyMatch = text.match(/^(\d{4})-(\d{2})/);
  if (dateOnlyMatch) return `${dateOnlyMatch[1]}-${dateOnlyMatch[2]}`;
  const parsed = new Date(text || `${getTodayString()}T12:00:00`);
  if (Number.isNaN(parsed.getTime())) return getTodayString().slice(0, 7);
  return `${parsed.getFullYear()}-${String(parsed.getMonth() + 1).padStart(2, '0')}`;
};

const formatMonthYearLabel = (monthKey = '') => {
  const safeMonthKey = buildMonthKeyFromDate(monthKey);
  const [year, month] = safeMonthKey.split('-');
  return `Tháng ${month}/${year}`;
};

const buildCalendarMonthCells = (monthKey = '') => {
  const safeMonthKey = buildMonthKeyFromDate(monthKey);
  const [yearText, monthText] = safeMonthKey.split('-');
  const year = parseInt(yearText, 10) || new Date().getFullYear();
  const monthIndex = Math.max(0, Math.min(11, (parseInt(monthText, 10) || 1) - 1));
  const firstDay = new Date(year, monthIndex, 1);
  const daysInMonth = new Date(year, monthIndex + 1, 0).getDate();
  const leadingDays = (firstDay.getDay() + 6) % 7;
  const totalCells = Math.ceil((leadingDays + daysInMonth) / 7) * 7;
  const cells = [];

  for (let cellIndex = 0; cellIndex < totalCells; cellIndex += 1) {
    const calendarDate = new Date(year, monthIndex, cellIndex - leadingDays + 1);
    cells.push({
      dateKey: toDateInputString(calendarDate),
      dayNumber: calendarDate.getDate(),
      isCurrentMonth: calendarDate.getMonth() === monthIndex,
      isToday: toDateInputString(calendarDate) === getTodayString()
    });
  }

  return cells;
};

const formatDateTimeLabel = (value) => {
  if (!value) return '--';
  if (typeof value === 'string' && isDateOnlyString(value)) return formatCompactDateLabel(value);
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime())
    ? `${value}`
    : `${parsed.toLocaleDateString('vi-VN', VIETNAM_DATE_FORMAT_OPTIONS)} ${parsed.toLocaleTimeString('vi-VN', VIETNAM_TIME_FORMAT_OPTIONS)}`;
};

const formatAttendanceMoment = (value) => {
  const parsed = parseAttendanceTimestamp(value);
  if (!parsed) return '--';
  return `${parsed.toLocaleTimeString('vi-VN', VIETNAM_TIME_FORMAT_OPTIONS)} • ${parsed.toLocaleDateString('vi-VN', VIETNAM_DATE_FORMAT_OPTIONS)}`;
};

const getAttendanceMethodDisplay = (record = {}, direction = 'checkIn') => {
  if (!record?.[direction]) return '-';
  const method = `${record?.[`${direction}Method`] || ''}`;
  const meta = record?.[`${direction}MethodMeta`] || {};
  const isProxy = Boolean(
    meta?.proxyAttendance
      || meta?.type === 'proxy'
      || /chấm hộ|điều chỉnh/i.test(method)
  );

  if (isProxy) {
    const proxyName = [
      meta?.proxyByName,
      meta?.checkedByName,
      meta?.performedByName,
      meta?.actorName,
      meta?.byName,
      meta?.proxyName
    ].find(value => `${value || ''}`.trim());
    return proxyName ? `Chấm hộ: ${proxyName}` : 'Chấm hộ: Chưa xác định người chấm';
  }

  if (hasAttendanceGpsMeta(meta)) {
    return `GPS: ${formatAttendanceGpsSummary(meta)}`;
  }

  if (meta?.type === 'wifi') {
    const wifiName = meta?.ssid || meta?.networkLabel || '--';
    return `WiFi: ${wifiName}`;
  }

  return /gps/i.test(method) ? 'GPS: Chưa có tọa độ' : (method || 'GPS: Chưa có tọa độ');
};

const getAttendanceCompactSource = (record = {}, direction = 'checkIn') => {
  if (!record?.[direction]) return '';
  const method = `${record?.[`${direction}Method`] || ''}`;
  const meta = record?.[`${direction}MethodMeta`] || {};
  const isProxy = Boolean(
    meta?.proxyAttendance
      || meta?.type === 'proxy'
      || /chấm hộ|điều chỉnh/i.test(method)
  );

  if (isProxy) {
    const proxyName = [
      meta?.proxyByName,
      meta?.checkedByName,
      meta?.performedByName,
      meta?.actorName,
      meta?.byName,
      meta?.proxyName
    ].find(value => `${value || ''}`.trim());
    return `Chấm hộ - ${proxyName || 'Chưa xác định người chấm'}`;
  }

  return hasAttendanceGpsMeta(meta)
    ? `Định vị: ${formatAttendanceGpsSummary(meta)}`
    : '';
};

const formatOrderCode = (orderId = '') => `HD${String(orderId || '').slice(-6).toUpperCase()}`;
const getLedgerOrderDisplayCode = (order = {}) => (
  order?.isOpeningDebt
    ? 'Nợ cũ'
    : (order?.orderCode || order?.code || formatOrderCode(order?.id))
);
const getOrderPaymentDisplayCode = (order = {}) => (
  order?.paymentCode
  || order?.matchedOrderCode
  || order?.orderCode
  || order?.code
  || formatOrderCode(order?.id)
);
const stripTransferMemoPrefix = (value = '') => `${value || ''}`.replace(/^TT\s*/i, '').trim();
const getOrderInvoiceCode = (orderOrId = {}) => {
  if (typeof orderOrId === 'string') {
    const normalized = normalizeTransferMemoToken(stripTransferMemoPrefix(orderOrId));
    return /^HD[A-Z0-9]{4,20}$/.test(normalized) ? normalized : formatOrderCode(orderOrId);
  }
  const rawCodes = [
    orderOrId?.invoiceCode,
    orderOrId?.orderCode,
    orderOrId?.code,
    orderOrId?.matchedOrderCode,
    orderOrId?.paymentCode
  ].filter(Boolean);
  for (const rawCode of rawCodes) {
    const normalized = normalizeTransferMemoToken(stripTransferMemoPrefix(rawCode));
    if (/^HD[A-Z0-9]{4,20}$/.test(normalized)) return normalized;
  }
  return formatOrderCode(orderOrId?.id);
};
const buildOrderTransferMemo = (orderOrId = {}) => {
  const invoiceCode = getOrderInvoiceCode(orderOrId);
  return invoiceCode ? `TT ${invoiceCode}` : '';
};
const normalizeTransferMemoToken = (value = '') => `${value}`
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'D')
  .toUpperCase()
  .replace(/[^A-Z0-9]/g, '');
const buildOrderMemoCandidates = (order = {}) => {
  const rawCodes = [
    order.id,
    order.orderId,
    order.orderCode,
    order.code,
    order.invoiceCode,
    order.paymentCode,
    order.paymentOrderCode,
    order.payosOrderCode,
    order.referenceCode,
    order.transferCode,
    order.matchedOrderCode
  ].filter(Boolean);
  const formattedCodes = rawCodes.map(code => formatOrderCode(code)).filter(Boolean);
  return [...new Set([...rawCodes, ...formattedCodes]
    .map(normalizeTransferMemoToken)
    .filter(token => token.length >= 6))];
};
const isOrderCodeAutoMatchEnabled = (company = null) => company?.autoReconcileByOrderCode !== false;
const getWarehouseOrderAutoCancelDays = (company = null) => {
  const rawValue = company?.warehouseOrderAutoCancelDays
    ?? company?.orderRequestAutoCancelDays
    ?? company?.dispatchOrderAutoCancelDays
    ?? 0;
  return Math.max(0, parseInt(rawValue, 10) || 0);
};
const resolveMatchedOrderFromTransfer = ({ paymentData = {}, orders = [], company = null } = {}) => {
  const activeOrders = orders.filter(order => !order?.isArchived);
  if (paymentData?.orderId) {
    return activeOrders.find(order => order.id === paymentData.orderId) || null;
  }
  if (!isOrderCodeAutoMatchEnabled(company)) return null;

  const searchableText = normalizeTransferMemoToken([
    paymentData?.note,
    paymentData?.bankContent,
    paymentData?.transferMemo,
    paymentData?.referenceCode
  ].filter(Boolean).join(' '));

  if (!searchableText) return null;

  return [...activeOrders]
    .sort((a, b) => (getEntityTimestamp(b) || 0) - (getEntityTimestamp(a) || 0))
    .find(order => buildOrderMemoCandidates(order).some(token => searchableText.includes(token))) || null;
};
const isOrderGeneratedExpense = (expense = {}) => {
  const note = `${expense?.note || ''}`.trim();
  return expense?.sourceType === 'order_extra_expense' || /^Phụ phí đơn hàng\b/i.test(note);
};
const isAccountingAddedExpense = (expense = {}) => !isOrderGeneratedExpense(expense);

const escapeHtml = (value = '') => `${value}`
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

