const normalizeVietQrBankCode = (value = '') => `${value || ''}`
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^A-Za-z0-9]/g, '')
  .trim()
  .toUpperCase();

const resolveVietQrBankBin = (bankValue = '') => {
  const normalized = normalizeVietQrBankCode(bankValue);
  if (/^\d{6}$/.test(normalized)) return normalized;
  if (VIETNAM_BANK_BINS[normalized]) return VIETNAM_BANK_BINS[normalized];
  const compact = normalized;
  const fuzzyMatches = [
    { bin: '970418', pattern: /BIDV|DAUTUVAPHATTRIEN|DAUTUPHATTRIEN|NHDTPT/ },
    { bin: '970403', pattern: /SACOMBANK|SAIGONTHUONGTIN|\bSTB\b/ },
    { bin: '970436', pattern: /VIETCOMBANK|NGOAITTHUONG|\bVCB\b/ },
    { bin: '970415', pattern: /VIETINBANK|CONGTHUONG|\bCTG\b|\bICB\b/ },
    { bin: '970405', pattern: /AGRIBANK|NONGNGHIEP|\bVBA\b/ },
    { bin: '970407', pattern: /TECHCOMBANK|\bTCB\b/ },
    { bin: '970422', pattern: /MBBANK|\bMBB\b|\bMB\b/ },
    { bin: '970416', pattern: /\bACB\b/ },
    { bin: '970432', pattern: /VPBANK|\bVPB\b/ },
    { bin: '970441', pattern: /\bVIB\b/ },
    { bin: '970426', pattern: /\bMSB\b/ }
  ];
  return fuzzyMatches.find(item => item.pattern.test(compact))?.bin || '';
};

const buildEmvField = (id = '', value = '') => {
  const safeValue = `${value || ''}`;
  if (!id || !safeValue) return '';
  return `${id}${String(safeValue.length).padStart(2, '0')}${safeValue}`;
};

const crc16CcittFalse = (value = '') => {
  let crc = 0xffff;
  for (let index = 0; index < value.length; index += 1) {
    crc ^= value.charCodeAt(index) << 8;
    for (let bit = 0; bit < 8; bit += 1) {
      crc = (crc & 0x8000) ? ((crc << 1) ^ 0x1021) : (crc << 1);
      crc &= 0xffff;
    }
  }
  return crc.toString(16).toUpperCase().padStart(4, '0');
};

const sanitizeVietQrText = (value = '', maxLength = 80) => `${value || ''}`
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^\w\s.-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, maxLength);

const buildVietQrEmvPayload = ({ bankCode = '', accountNumber = '', accountName = '', amount = 0, description = '' } = {}) => {
  const bankBin = resolveVietQrBankBin(bankCode);
  const safeAccountNumber = normalizePaymentAccountNumber(accountNumber);
  if (!bankBin || !safeAccountNumber) return '';
  const amountValue = Math.max(0, Math.round(parseLooseMoneyValue(amount)));
  const consumerAccount = buildEmvField('00', bankBin) + buildEmvField('01', safeAccountNumber);
  const merchantAccountInfo = buildEmvField('00', 'A000000727')
    + buildEmvField('01', consumerAccount)
    + buildEmvField('02', 'QRIBFTTA');
  const additionalData = buildEmvField('08', sanitizeVietQrText(description, 50));
  const accountNameField = buildEmvField('59', sanitizeVietQrText(accountName, 25));
  const payloadWithoutCrc = [
    buildEmvField('00', '01'),
    buildEmvField('01', '12'),
    buildEmvField('38', merchantAccountInfo),
    buildEmvField('53', '704'),
    amountValue > 0 ? buildEmvField('54', `${amountValue}`) : '',
    buildEmvField('58', 'VN'),
    accountNameField,
    additionalData ? buildEmvField('62', additionalData) : '',
    '6304'
  ].filter(Boolean).join('');
  return `${payloadWithoutCrc}${crc16CcittFalse(payloadWithoutCrc)}`;
};

const parseVietQrImageUrlToPayload = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!/^https?:\/\//i.test(raw)) return '';
  try {
    const parsed = new URL(raw);
    const host = parsed.hostname.toLowerCase();
    if (host === 'api.qrserver.com') {
      const nestedData = parsed.searchParams.get('data') || '';
      return nestedData && nestedData !== raw ? parseVietQrImageUrlToPayload(decodeURIComponent(nestedData)) : '';
    }
    if (host === 'vietqr.app' || host.endsWith('.vietqr.app')) {
      return buildVietQrEmvPayload({
        bankCode: parsed.searchParams.get('bank') || parsed.searchParams.get('bankCode') || '',
        accountNumber: parsed.searchParams.get('acc') || parsed.searchParams.get('account') || parsed.searchParams.get('accountNumber') || '',
        accountName: parsed.searchParams.get('holder') || parsed.searchParams.get('accountName') || '',
        amount: parsed.searchParams.get('amount') || '',
        description: parsed.searchParams.get('des') || parsed.searchParams.get('addInfo') || parsed.searchParams.get('description') || ''
      });
    }
    if (host === 'img.vietqr.io' || host.endsWith('.vietqr.io')) {
      const match = parsed.pathname.match(/\/image\/([A-Za-z0-9]+)-([A-Za-z0-9]+)-[^/]*$/i);
      if (!match) return '';
      return buildVietQrEmvPayload({
        bankCode: match[1],
        accountNumber: match[2],
        accountName: parsed.searchParams.get('accountName') || '',
        amount: parsed.searchParams.get('amount') || '',
        description: parsed.searchParams.get('addInfo') || parsed.searchParams.get('des') || ''
      });
    }
  } catch (error) {
    return '';
  }
  return '';
};

const buildCompanyMonogram = (companyName = '') => {
  const words = `${companyName}`.trim().split(/\s+/).filter(Boolean);
  if (words.length === 0) return 'HD';
  if (words.length === 1) return words[0].slice(0, 2).toUpperCase();
  return `${words[0][0] || ''}${words[words.length - 1][0] || ''}`.toUpperCase();
};

const getCompanyDisplayName = (company = null) => `${company?.displayName || company?.name || 'Doanh nghiệp'}`.trim() || 'Doanh nghiệp';
const getCompanyLogoUrl = (company = null) => `${company?.logoUrl || company?.logo || ''}`.trim();
const getCompanySlogan = (company = null) => `${company?.slogan || company?.companySlogan || ''}`.trim();
const getEmployeeAvatarUrl = (employee = null) => `${employee?.avatarUrl || employee?.photoUrl || employee?.avatar || ''}`.trim();

const getInvoiceTransferProfile = (company = null) => {
  const accountNumber = `${company?.bankAccountNumber || company?.invoiceAccountNumber || DEFAULT_INVOICE_TRANSFER_PROFILE.accountNumber || ''}`.replace(/[^\dA-Za-z]/g, '').trim().toUpperCase();
  const virtualAccountNumber = `${company?.sepayVirtualAccountNumber
    || company?.sepayVaAccountNumber
    || company?.sepayVaNumber
    || company?.sepayVirtualAccount
    || company?.sepayReceivingAccountNumber
    || company?.bankVirtualAccountNumber
    || company?.virtualBankAccountNumber
    || company?.vaAccountNumber
    || company?.virtualAccountNumber
    || ''}`.replace(/[^\dA-Za-z]/g, '').trim().toUpperCase();
  const sepayUseVirtualAccount = company?.sepayUseVirtualAccount !== false && Boolean(virtualAccountNumber);
  return {
    bankId: company?.bankId || company?.invoiceBankId || DEFAULT_INVOICE_TRANSFER_PROFILE.bankId,
    bankName: company?.bankName || company?.invoiceBankName || company?.bankId || DEFAULT_INVOICE_TRANSFER_PROFILE.bankName,
    accountName: company?.bankAccountName || company?.invoiceAccountName || DEFAULT_INVOICE_TRANSFER_PROFILE.accountName,
    accountNumber,
    sepayVirtualAccountNumber: virtualAccountNumber,
    sepayUseVirtualAccount,
    sepayReceivingAccountNumber: sepayUseVirtualAccount ? virtualAccountNumber : accountNumber,
    template: company?.invoiceQrTemplate || DEFAULT_INVOICE_TRANSFER_PROFILE.template
  };
};

const buildCustomerPaymentReference = (customer = null) => {
  const rawId = `${customer?.code || customer?.customerCode || customer?.id || customer?.phone || 'KH'}`.replace(/[^a-zA-Z0-9]+/g, '').toUpperCase();
  return `TT ${rawId || 'KH'} ${getTodayString().replaceAll('-', '')}`;
};

const openExternalPaymentUrl = async (url = '', fallbackUrl = '') => {
  const safeUrl = `${url || ''}`.trim();
  if (!safeUrl) return false;
  const safeFallbackUrl = `${fallbackUrl || ''}`.trim();
  if (Capacitor?.isNativePlatform?.()) {
    try {
      const result = await ExternalLauncher.open({ url: safeUrl, fallbackUrl: safeFallbackUrl });
      if (result?.opened) return true;
    } catch (error) {
      console.warn('Khong mo duoc bang native launcher, thu cach web.', error);
    }
  }
  try {
    const opened = window.open(safeUrl, '_blank', 'noopener,noreferrer');
    if (opened) return true;
  } catch (error) {
    console.warn('Khong mo duoc cua so thanh toan moi, thu dieu huong truc tiep.', error);
  }
  try {
    window.location.href = safeUrl;
    return true;
  } catch (error) {
    console.warn('Khong dieu huong duoc link thanh toan.', error);
  }
  if (safeFallbackUrl) {
    try {
      window.location.href = safeFallbackUrl;
      return true;
    } catch (error) {
      console.warn('Khong dieu huong duoc link QR du phong.', error);
    }
  }
  return false;
};

const isDirectQrImageSource = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!raw) return false;
  if (/^data:image\//i.test(raw)) return true;
  if (!/^https?:\/\//i.test(raw)) return false;
  return /\.(png|jpe?g|webp|gif)(\?|#|$)/i.test(raw)
    || /api\.qrserver\.com/i.test(raw)
    || /vietqr\.app\/img/i.test(raw);
};

const buildQrImageSource = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!raw) return '';
  if (isDirectQrImageSource(raw)) return raw;
  return `https://api.qrserver.com/v1/create-qr-code/?size=520x520&margin=12&data=${encodeURIComponent(raw)}`;
};

const isLegacyVietQrPaymentSource = (value = '') => /img\.vietqr\.io/i.test(`${value || ''}`);

const LOCAL_PAYMENT_QR_DATA_URL_CACHE_LIMIT = 160;
const LOCAL_PAYMENT_QR_DATA_URL_CACHE_TTL_MS = 10 * 60 * 1000;
const localPaymentQrDataUrlCache = new Map();
let qrCodeModulePromise = null;

const getQRCodeModule = async () => {
  if (!qrCodeModulePromise) {
    qrCodeModulePromise = import('qrcode').then((module) => module.default || module);
  }
  return qrCodeModulePromise;
};

const rememberLocalPaymentQrDataUrl = (key = '', dataUrl = '') => {
  if (!key || !dataUrl) return;
  if (localPaymentQrDataUrlCache.has(key)) {
    localPaymentQrDataUrlCache.delete(key);
  }
  localPaymentQrDataUrlCache.set(key, {
    dataUrl,
    createdAt: Date.now()
  });
  while (localPaymentQrDataUrlCache.size > LOCAL_PAYMENT_QR_DATA_URL_CACHE_LIMIT) {
    const oldestKey = localPaymentQrDataUrlCache.keys().next().value;
    if (!oldestKey) break;
    localPaymentQrDataUrlCache.delete(oldestKey);
  }
};

const buildLocalPaymentQrDataUrl = async (value = '', options = {}) => {
  const raw = `${value || ''}`.trim();
  if (!raw || /^data:image\//i.test(raw)) return '';
  const payload = parseVietQrImageUrlToPayload(raw) || raw;
  if (!payload || (isDirectQrImageSource(payload) && !parseVietQrImageUrlToPayload(payload))) return '';
  const width = Number(options?.width) || 520;
  // The cache key is the full QR payload. Each invoice/payment code therefore has its own QR entry.
  const cacheKey = `${width}|${payload}`;
  const cachedEntry = localPaymentQrDataUrlCache.get(cacheKey);
  if (cachedEntry?.dataUrl && Date.now() - cachedEntry.createdAt <= LOCAL_PAYMENT_QR_DATA_URL_CACHE_TTL_MS) {
    localPaymentQrDataUrlCache.delete(cacheKey);
    localPaymentQrDataUrlCache.set(cacheKey, cachedEntry);
    return cachedEntry.dataUrl;
  }
  if (cachedEntry) {
    localPaymentQrDataUrlCache.delete(cacheKey);
  }
  try {
    const QRCode = await getQRCodeModule();
    const dataUrl = await QRCode.toDataURL(payload, {
      errorCorrectionLevel: 'M',
      margin: 1,
      width,
      color: {
        dark: '#000000',
        light: '#ffffff'
      }
    });
    rememberLocalPaymentQrDataUrl(cacheKey, dataUrl);
    return dataUrl;
  } catch (error) {
    console.warn('Khong tao duoc QR noi bo, se dung anh QR du phong.', error);
    return '';
  }
};

const warmLocalPaymentQrDataUrlCache = (value = '', options = {}) => {
  buildLocalPaymentQrDataUrl(value, options).catch(() => {});
};

const buildCodeOnlyPaymentQrImageSource = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!raw || !/^https?:\/\//i.test(raw)) return raw;
  try {
    const parsed = new URL(raw);
    const host = parsed.hostname.toLowerCase();
    if (host === 'img.vietqr.io' || host.endsWith('.vietqr.io')) {
      parsed.pathname = parsed.pathname.replace(/-(compact2|compact|print|qr_only)\.png$/i, '-qr_only.png');
      parsed.searchParams.delete('accountName');
      return parsed.toString();
    }
    if (host === 'api.qrserver.com') {
      parsed.searchParams.set('size', '520x520');
      parsed.searchParams.set('margin', '1');
      return parsed.toString();
    }
    if (host === 'vietqr.app' || host.endsWith('.vietqr.app')) {
      parsed.searchParams.set('template', 'qr_only');
      parsed.searchParams.delete('accountName');
      return parsed.toString();
    }
    return raw;
  } catch (error) {
    return raw;
  }
};

const normalizePaymentAccountNumber = (value = '') => `${value || ''}`.replace(/[^\dA-Za-z]/g, '').trim().toUpperCase();

const extractPaymentAccountNumberFromQrSource = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!raw) return '';
  try {
    const parsed = new URL(raw);
    const queryAccount = parsed.searchParams.get('acc')
      || parsed.searchParams.get('account')
      || parsed.searchParams.get('accountNumber')
      || parsed.searchParams.get('bankAccount');
    if (queryAccount) return normalizePaymentAccountNumber(queryAccount);
    const legacyMatch = parsed.pathname.match(/\/image\/[^/]*?-([A-Za-z0-9]+)-[^/]*$/i);
    if (legacyMatch?.[1]) return normalizePaymentAccountNumber(legacyMatch[1]);
  } catch (error) {
    const queryMatch = raw.match(/[?&](?:acc|account|accountNumber|bankAccount)=([^&#]+)/i);
    if (queryMatch?.[1]) return normalizePaymentAccountNumber(decodeURIComponent(queryMatch[1]));
  }
  return '';
};

const extractPaymentBankCodeFromQrSource = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!raw) return '';
  try {
    const parsed = new URL(raw);
    const queryBank = parsed.searchParams.get('bank')
      || parsed.searchParams.get('bankCode')
      || parsed.searchParams.get('bankBin')
      || parsed.searchParams.get('bin');
    if (queryBank) return `${queryBank}`.trim();
    const legacyMatch = parsed.pathname.match(/\/image\/([A-Za-z0-9]+)-[A-Za-z0-9]+-[^/]*$/i);
    if (legacyMatch?.[1]) return `${legacyMatch[1]}`.trim();
  } catch (error) {
    const queryMatch = raw.match(/[?&](?:bank|bankCode|bankBin|bin)=([^&#]+)/i);
    if (queryMatch?.[1]) return decodeURIComponent(queryMatch[1]).trim();
  }
  return '';
};

const normalizePaymentBankBin = (value = '') => resolveVietQrBankBin(value) || normalizeVietQrBankCode(value);

const getOrderPayosPaymentSource = (order = {}) => {
  const provider = `${order?.paymentProvider || ''}`.toLowerCase();
  const hasPayosMeta = ['sepay', 'payos'].includes(provider)
    || Boolean(order?.paymentLinkId || order?.sepayPaymentCode || order?.payosOrderCode || order?.paymentOrderCode || order?.checkoutUrl || order?.paymentCheckoutUrl || order?.sepayQrCode || order?.payosQrCode);
  if (!hasPayosMeta) return '';
  const candidates = provider === 'sepay'
    ? [
      order.paymentQrPayload,
      order.qrCode,
      order.sepayQrCode,
      order.paymentQrImageUrl,
      order.paymentQrUrl,
      order.checkoutUrl,
      order.paymentCheckoutUrl,
      order.payosQrCode
    ]
    : [
      order.paymentQrPayload,
      order.qrCode,
      order.paymentQrImageUrl,
      order.sepayQrCode,
      order.payosQrCode,
      order.paymentQrUrl,
      order.checkoutUrl,
      order.paymentCheckoutUrl
    ];
  return candidates
    .map(value => `${value || ''}`.trim())
    .find(value => Boolean(value)) || '';
};

const getOrderPaymentQrAmount = (order = {}) => {
  const preferredAmount = [
    order?.currentPaymentDueAmount,
    order?.paymentDueAmount,
    order?.finalDebtAmount,
    order?.totalToCollect,
    order?.outstandingAmount,
    order?.remainingAmount,
    order?.paymentAmount
  ].find(value => parseLooseMoneyValue(value) > 0);
  if (preferredAmount !== undefined) {
    return Math.max(0, Math.round(parseLooseMoneyValue(preferredAmount)));
  }
  const orderAmount = parseLooseMoneyValue(order?.amount ?? order?.totalAmount ?? order?.finalAmount ?? order?.grandTotal ?? 0);
  const paidAmount = parseLooseMoneyValue(order?.paidAmount ?? order?.appliedAmount ?? order?.collectedAmount ?? 0);
  return Math.max(0, Math.round(orderAmount - paidAmount));
};

const buildOrderLocalPaymentQrPayload = (order = {}, company = null, options = {}) => {
  if (!order) return '';
  const { preferStoredSource = true } = options || {};
  const transferProfile = getInvoiceTransferProfile(company);
  const orderPaymentSource = getOrderPayosPaymentSource(order);
  if (preferStoredSource) {
    const parsedSourcePayload = parseVietQrImageUrlToPayload(orderPaymentSource);
    if (parsedSourcePayload) return parsedSourcePayload;
    if (orderPaymentSource && !isDirectQrImageSource(orderPaymentSource) && !/^https?:\/\//i.test(orderPaymentSource)) {
      return orderPaymentSource;
    }
  }

  const preferredAccountNumber = order?.receivingBankIsVirtualAccount
    ? (order?.receivingBankVirtualAccountNumber || order?.receivingBankAccountNumber)
    : (order?.receivingBankAccountNumber || order?.receivingBankVirtualAccountNumber);
  const transferAccountNumber = normalizePaymentAccountNumber(
    transferProfile.sepayReceivingAccountNumber || transferProfile.accountNumber || ''
  );
  const storedAccountNumber = normalizePaymentAccountNumber(
    preferredAccountNumber
      || order?.companyBankAccountNumber
      || order?.bankAccountNumber
      || ''
  );
  const useStoredReceivingProfile = storedAccountNumber && (!transferAccountNumber || storedAccountNumber === transferAccountNumber);
  const accountNumber = useStoredReceivingProfile
    ? storedAccountNumber
    : (transferAccountNumber || storedAccountNumber);
  const bankCode = useStoredReceivingProfile
    ? (order?.receivingBankCode
      || order?.receivingBankName
      || transferProfile.bankId
      || transferProfile.bankName
      || '')
    : (transferProfile.bankId
      || transferProfile.bankName
      || order?.receivingBankCode
      || order?.receivingBankName
      || '');
  const accountName = order?.receivingBankAccountName
    || transferProfile.accountName
    || '';
  const description = order?.sepayPaymentCode
    || order?.paymentCode
    || buildOrderTransferMemo(order)
    || `TT ${formatOrderCode(order?.id)}`;

  return buildVietQrEmvPayload({
    bankCode,
    accountNumber,
    accountName,
    amount: getOrderPaymentQrAmount(order),
    description
  });
};

const isOrderPaymentSourceAlignedWithTransferProfile = (order = {}, company = null) => {
  const transferProfile = getInvoiceTransferProfile(company);
  const expectedAccountNumber = normalizePaymentAccountNumber(
    transferProfile.sepayReceivingAccountNumber || transferProfile.accountNumber || ''
  );
  const expectedBankBin = normalizePaymentBankBin(transferProfile.bankId || transferProfile.bankName || '');
  if (!expectedAccountNumber && !expectedBankBin) return true;
  const storedAccountNumber = normalizePaymentAccountNumber(
    order?.receivingBankAccountNumber
      || order?.companyBankAccountNumber
      || order?.bankAccountNumber
      || ''
  );
  if (expectedAccountNumber && storedAccountNumber && storedAccountNumber !== expectedAccountNumber) return false;
  const paymentSource = getOrderPayosPaymentSource(order);
  const sourceAccountNumber = extractPaymentAccountNumberFromQrSource(paymentSource);
  if (expectedAccountNumber && sourceAccountNumber && sourceAccountNumber !== expectedAccountNumber) return false;
  const storedBankBin = normalizePaymentBankBin(
    order?.receivingBankCode
      || order?.paymentBankCode
      || order?.companyBankCode
      || order?.bankCode
      || order?.receivingBankName
      || order?.companyBankName
      || ''
  );
  if (expectedBankBin && storedBankBin && storedBankBin !== expectedBankBin) return false;
  const sourceBankBin = normalizePaymentBankBin(extractPaymentBankCodeFromQrSource(paymentSource));
  if (expectedBankBin && sourceBankBin && sourceBankBin !== expectedBankBin) return false;
  return Boolean(storedAccountNumber || sourceAccountNumber || storedBankBin || sourceBankBin);
};

const buildPayosPaymentQrImageSource = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!raw) return '';
  const payload = parseVietQrImageUrlToPayload(raw) || raw;
  return buildCodeOnlyPaymentQrImageSource(buildQrImageSource(payload));
};

const DEFAULT_PAYOS_API_BASE_URL = 'https://hd-manager-c5839.web.app';
const getPayosApiBaseUrl = () => {
  const envBaseUrl = `${import.meta.env.VITE_SEPAY_API_BASE_URL || import.meta.env.VITE_PAYOS_API_BASE_URL || ''}`.trim();
  if (envBaseUrl) return envBaseUrl.replace(/\/+$/, '');
  if (typeof window === 'undefined') return '';
  const origin = `${window.location?.origin || ''}`.trim();
  const isLocalAppOrigin = /^(https?:\/\/)?(localhost|127\.0\.0\.1|0\.0\.0\.0)(:\d+)?$/i.test(origin)
    || /^capacitor:\/\//i.test(origin)
    || /^file:\/\//i.test(origin);
  return isLocalAppOrigin ? DEFAULT_PAYOS_API_BASE_URL : '';
};
const PAYOS_API_BASE_URL = getPayosApiBaseUrl();
const buildPayosApiUrl = (path = '') => `${PAYOS_API_BASE_URL}${path.startsWith('/') ? path : `/${path}`}`;

const requestPayosPaymentLink = async ({ firebaseUser, appId, orderId, receivingProfile = null, amount = 0 }) => {
  if (!firebaseUser || !orderId) {
    throw new Error('Thiếu phiên đăng nhập hoặc mã đơn để tạo thanh toán SePay.');
  }

  const idToken = await firebaseUser.getIdToken();
  const requestedAmount = Math.max(0, Math.round(parseLooseMoneyValue(amount)));
  let response = null;
  try {
    response = await fetch(buildPayosApiUrl('/api/sepay/create-payment-request'), {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${idToken}`
      },
      body: JSON.stringify({
        appId,
        orderId,
        receivingProfile,
        ...(requestedAmount > 0 ? { amount: requestedAmount } : {})
      })
    });
  } catch (error) {
    console.warn('SePay payment request failed.', error);
    throw new Error('Không kết nối được SePay để tạo QR tự đối soát. Vui lòng kiểm tra mạng hoặc cấu hình SePay.');
  }

  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload?.success === false) {
    console.warn('SePay payment request rejected.', payload);
    throw new Error(payload?.message || 'SePay từ chối tạo QR thanh toán cho hóa đơn này.');
  }

  const payment = payload.payment || payload;
  if (!payment?.checkoutUrl && !payment?.qrCode && !payment?.paymentLinkId) {
    throw new Error('SePay chưa trả về mã QR thanh toán hợp lệ.');
  }
  return payment;
};

const buildSepayReceivingProfilePayload = (company = null) => {
  const transferProfile = getInvoiceTransferProfile(company);
  const accountNumber = `${transferProfile.sepayReceivingAccountNumber || transferProfile.accountNumber || ''}`.replace(/[^\dA-Za-z]/g, '').trim().toUpperCase();
  return {
    bankCode: transferProfile.bankId || transferProfile.bankName || '',
    bankName: transferProfile.bankName || transferProfile.bankId || '',
    accountName: transferProfile.accountName || '',
    accountNumber,
    mainAccountNumber: `${transferProfile.accountNumber || ''}`.replace(/[^\dA-Za-z]/g, '').trim().toUpperCase(),
    virtualAccountNumber: `${transferProfile.sepayVirtualAccountNumber || ''}`.replace(/[^\dA-Za-z]/g, '').trim().toUpperCase(),
    useVirtualAccount: Boolean(transferProfile.sepayUseVirtualAccount && transferProfile.sepayVirtualAccountNumber)
  };
};

const requestPayosPaymentSync = async ({ firebaseUser, appId, orderId }) => {
  if (!firebaseUser || !orderId) {
    throw new Error('Thiếu phiên đăng nhập hoặc mã đơn để kiểm tra SePay.');
  }

  const idToken = await firebaseUser.getIdToken();
  const response = await fetch(buildPayosApiUrl('/api/sepay/sync-payment'), {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${idToken}`
    },
    body: JSON.stringify({ appId, orderId })
  });

  const payload = await response.json().catch(() => ({}));
  if (!response.ok || payload?.success === false) {
    throw new Error(payload?.message || 'Không kiểm tra được trạng thái SePay.');
  }

  return payload;
};

const appendPayosPaymentLines = (messageText = '', payment = {}, orderCode = '') => {
  const checkoutUrl = `${payment?.checkoutUrl || ''}`.trim();
  const qrCode = `${payment?.qrCode || payment?.paymentQrUrl || ''}`.trim();
  const hasQrImage = Boolean(buildQrImageSource(qrCode));
  const cleanedBaseMessage = `${messageText || ''}`
    .split('\n')
    .filter((line) => {
      const lowerLine = `${line || ''}`.toLowerCase();
      const plainLine = lowerLine.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
      if (plainLine.includes('vietqr') || plainLine.includes('payos') || plainLine.includes('sepay') || plainLine.includes('qr thanh') || plainLine.includes('ma qr')) return false;
      if (orderCode && line.includes(orderCode) && (plainLine.includes('tt ') || plainLine.includes('chuyen khoan'))) return false;
      return true;
    })
    .join('\n')
    .trim();
  const lines = [cleanedBaseMessage];
  if (orderCode) lines.push('', `Mã hóa đơn: ${orderCode}`);
  if (hasQrImage) {
    lines.push('Vui lòng quét mã QR SePay được gửi kèm bên dưới để app tự đối soát công nợ.');
  } else if (checkoutUrl) {
    lines.push(`Link thanh toán SePay: ${checkoutUrl}`);
  }
  return lines.filter(line => line !== '').join('\n');
};

const resolveBankTransactionContent = (transaction = {}) => [
  transaction.bankContent,
  transaction.content,
  transaction.description,
  transaction.memo,
  transaction.addInfo,
  transaction.transferMemo,
  transaction.referenceCode,
  transaction.note
].filter(Boolean).join(' ').trim();

const resolveBankTransactionAmount = (transaction = {}) => {
  const rawValue = transaction.amount
    ?? transaction.creditAmount
    ?? transaction.inAmount
    ?? transaction.transactionAmount
    ?? transaction.value
    ?? transaction.money;
  return Math.max(0, parseLooseMoneyValue(rawValue));
};

const resolveBankTransactionDate = (transaction = {}) => {
  const rawDate = transaction.date
    || transaction.transactionDate
    || transaction.bookingDate
    || transaction.createdAt
    || transaction.timestamp;
  if (!rawDate) return getTodayString();
  if (typeof rawDate === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(rawDate)) return rawDate;
  const parsedDate = rawDate?.toDate ? rawDate.toDate() : new Date(rawDate);
  if (Number.isNaN(parsedDate.getTime())) return getTodayString();
  return `${parsedDate.getFullYear()}-${String(parsedDate.getMonth() + 1).padStart(2, '0')}-${String(parsedDate.getDate()).padStart(2, '0')}`;
};

const copyTextToClipboard = async (text = '') => {
  try {
    if (typeof navigator !== 'undefined' && navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(text);
      return true;
    }
  } catch (error) {
    // Fall through to the legacy clipboard path below.
  }

  if (typeof document === 'undefined') return false;

  try {
    const textarea = document.createElement('textarea');
    textarea.value = text;
    textarea.setAttribute('readonly', 'readonly');
    textarea.style.position = 'fixed';
    textarea.style.opacity = '0';
    document.body.appendChild(textarea);
    textarea.select();
    const copied = document.execCommand('copy');
    document.body.removeChild(textarea);
    return copied;
  } catch (error) {
    return false;
  }
};

const downloadContentFile = (filename, content, mimeType = 'text/plain;charset=utf-8') => {
  if (typeof window === 'undefined' || typeof document === 'undefined') return false;
  const blob = new Blob([content], { type: mimeType });
  const objectUrl = window.URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = objectUrl;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  window.URL.revokeObjectURL(objectUrl);
  return true;
};

const saveContentFile = async (filename, content, mimeType = 'text/plain;charset=utf-8') => {
  if (Capacitor.getPlatform() !== 'web') {
    try {
      const path = `HDManager/${filename}`;
      await Filesystem.writeFile({
        path,
        data: content,
        directory: Directory.Documents,
        encoding: Encoding.UTF8,
        recursive: true
      });
      const fileUri = await Filesystem.getUri({
        path,
        directory: Directory.Documents
      });
      return { status: 'saved', path, uri: fileUri?.uri || '' };
    } catch (error) {
      // Fall back to browser download below when native write is unavailable.
    }
  }

  const downloaded = downloadContentFile(filename, content, mimeType);
  return { status: downloaded ? 'downloaded' : 'unsupported', path: filename };
};

const shareContentFile = async ({ filename, content, mimeType = 'text/plain;charset=utf-8', title = '', text = '', dialogTitle = '' }) => {
  if (Capacitor.getPlatform() !== 'web') {
    try {
      const path = `HDManager/${filename}`;
      await Filesystem.writeFile({
        path,
        data: content,
        directory: Directory.Documents,
        encoding: Encoding.UTF8,
        recursive: true
      });
      const fileUri = await Filesystem.getUri({
        path,
        directory: Directory.Documents
      });
      const capability = await CapacitorShare.canShare().catch(() => ({ value: false }));
      if (capability?.value && fileUri?.uri) {
        await CapacitorShare.share({
          title,
          text,
          dialogTitle: dialogTitle || title,
          files: [fileUri.uri]
        });
        return { status: 'shared', path, uri: fileUri.uri };
      }
      return { status: 'saved', path, uri: fileUri?.uri || '' };
    } catch (error) {
      if (`${error?.message || ''}`.toLowerCase().includes('cancel')) {
        return { status: 'cancelled' };
      }
    }
  }

  const downloaded = downloadContentFile(filename, content, mimeType);
  return { status: downloaded ? 'downloaded' : 'unsupported', path: filename };
};

const shareTextContent = async ({ title = '', text = '', dialogTitle = '' }) => {
  try {
    const capability = await CapacitorShare.canShare().catch(() => ({ value: false }));
    if (capability?.value) {
      await withTimeout(CapacitorShare.share({ title, text, dialogTitle: dialogTitle || title }), 12000, 'share-timeout');
      return { status: 'shared' };
    }
  } catch (error) {
    if (`${error?.message || ''}`.toLowerCase().includes('cancel')) {
      return { status: 'cancelled' };
    }
  }

  try {
    if (typeof navigator !== 'undefined' && typeof navigator.share === 'function') {
      await withTimeout(navigator.share({ title, text }), 12000, 'share-timeout');
      return { status: 'shared' };
    }
  } catch (error) {
    if (`${error?.message || ''}`.toLowerCase().includes('cancel')) {
      return { status: 'cancelled' };
    }
  }

  const copied = await copyTextToClipboard(text);
  return { status: copied ? 'copied' : 'unsupported' };
};

const blobToBase64 = async (blob) => {
  const arrayBuffer = await blob.arrayBuffer();
  const bytes = new Uint8Array(arrayBuffer);
  const chunkSize = 0x8000;
  let binary = '';
  for (let index = 0; index < bytes.length; index += chunkSize) {
    const chunk = bytes.subarray(index, index + chunkSize);
    binary += String.fromCharCode(...chunk);
  }
  return btoa(binary);
};

const sanitizeShareFileName = (filename = 'hd-manager-file') => {
  const safeName = `${filename || 'hd-manager-file'}`
    .replace(/[\\/:*?"<>|]+/g, '-')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 140);
  return safeName || 'hd-manager-file';
};

const writeBlobToShareCache = async (filename, blob) => {
  const safeName = sanitizeShareFileName(filename);
  const path = `HDManagerShare/${safeName}`;
  const base64Data = await blobToBase64(blob);
  const writeResult = await Filesystem.writeFile({
    path,
    data: base64Data,
    directory: Directory.Cache,
    recursive: true
  });
  const fileUri = writeResult?.uri
    ? writeResult
    : await Filesystem.getUri({
        path,
        directory: Directory.Cache
      });
  return { path, uri: fileUri?.uri || '' };
};

const isProxyablePaymentQrUrl = (url = '') => {
  const raw = `${url || ''}`.trim();
  if (!raw || !/^https?:\/\//i.test(raw)) return false;
  try {
    const parsed = new URL(raw);
    const host = parsed.hostname.toLowerCase();
    return host === 'vietqr.app'
      || host.endsWith('.vietqr.app')
      || host === 'img.vietqr.io'
      || host.endsWith('.vietqr.io')
      || host === 'api.qrserver.com';
  } catch (error) {
    return false;
  }
};

const buildPaymentQrProxyUrl = (url = '') => {
  const raw = `${url || ''}`.trim();
  if (!isProxyablePaymentQrUrl(raw)) return '';
  return buildPayosApiUrl(`/api/sepay/qr-image?url=${encodeURIComponent(raw)}`);
};

const PAYMENT_QR_IMAGE_CACHE_LIMIT = 80;
const PAYMENT_QR_IMAGE_FETCH_TIMEOUT_MS = 2600;
const PAYMENT_QR_IMAGE_DECODE_TIMEOUT_MS = 1800;
const PAYMENT_QR_IMAGE_FAST_FETCH_TIMEOUT_MS = 900;
const PAYMENT_QR_IMAGE_FAST_DECODE_TIMEOUT_MS = 900;
const paymentQrImageDataUrlCache = new Map();
const paymentQrImagePendingCache = new Map();

const rememberPaymentQrImageDataUrl = (url = '', dataUrl = '') => {
  const cacheKey = `${url || ''}`.trim();
  const safeDataUrl = `${dataUrl || ''}`.trim();
  if (!cacheKey || !safeDataUrl) return;
  if (paymentQrImageDataUrlCache.has(cacheKey)) {
    paymentQrImageDataUrlCache.delete(cacheKey);
  }
  paymentQrImageDataUrlCache.set(cacheKey, safeDataUrl);
  while (paymentQrImageDataUrlCache.size > PAYMENT_QR_IMAGE_CACHE_LIMIT) {
    const oldestKey = paymentQrImageDataUrlCache.keys().next().value;
    paymentQrImageDataUrlCache.delete(oldestKey);
  }
};

const getCachedPaymentQrImageDataUrl = async (url = '', options = {}) => {
  const cacheKey = `${url || ''}`.trim();
  if (!cacheKey) return '';
  const cached = paymentQrImageDataUrlCache.get(cacheKey);
  if (cached) {
    paymentQrImageDataUrlCache.delete(cacheKey);
    paymentQrImageDataUrlCache.set(cacheKey, cached);
    return cached;
  }
  const pending = paymentQrImagePendingCache.get(cacheKey);
  if (pending) return pending;
  const loadPromise = fetchImageAsDataUrl(cacheKey, {
    timeoutMs: PAYMENT_QR_IMAGE_FETCH_TIMEOUT_MS,
    ...options
  }).then((dataUrl) => {
    rememberPaymentQrImageDataUrl(cacheKey, dataUrl);
    return dataUrl;
  }).finally(() => {
    paymentQrImagePendingCache.delete(cacheKey);
  });
  paymentQrImagePendingCache.set(cacheKey, loadPromise);
  return loadPromise;
};

const warmPaymentQrImageDataUrlCache = (url = '', options = {}) => {
  const cacheKey = `${url || ''}`.trim();
  if (!cacheKey || paymentQrImageDataUrlCache.has(cacheKey) || paymentQrImagePendingCache.has(cacheKey)) return;
  getCachedPaymentQrImageDataUrl(cacheKey, options).catch(() => {});
};

const fetchImageAsDataUrl = async (url = '', options = {}) => {
  if (!url) return '';
  const {
    allowPaymentQrProxy = true,
    timeoutMs = PAYMENT_QR_IMAGE_FETCH_TIMEOUT_MS
  } = options || {};
  const controller = typeof AbortController !== 'undefined' ? new AbortController() : null;
  const timeoutId = controller && timeoutMs > 0
    ? setTimeout(() => controller.abort(), timeoutMs)
    : null;
  try {
    const response = await fetch(url, {
      mode: 'cors',
      cache: 'force-cache',
      signal: controller?.signal
    });
    if (!response.ok) {
      throw new Error('Không thể tải ảnh từ đường dẫn này.');
    }
    const blob = await response.blob();
    const base64Data = await blobToBase64(blob);
    return `data:${blob.type || 'image/png'};base64,${base64Data}`;
  } catch (error) {
    const isAbortError = error?.name === 'AbortError';
    const proxyUrl = !isAbortError && allowPaymentQrProxy ? buildPaymentQrProxyUrl(url) : '';
    if (proxyUrl && proxyUrl !== url) {
      return fetchImageAsDataUrl(proxyUrl, {
        allowPaymentQrProxy: false,
        timeoutMs
      });
    }
    if (isAbortError) {
      throw new Error('Tải mã QR SePay quá thời gian, vui lòng thử lại khi mạng ổn định.');
    }
    throw error;
  } finally {
    if (timeoutId) clearTimeout(timeoutId);
  }
};

const canvasToBlob = (canvas, type = 'image/png', quality) => new Promise((resolve, reject) => {
  canvas.toBlob((blob) => {
    if (blob) resolve(blob);
    else reject(new Error('Không thể tạo file ảnh từ hóa đơn.'));
  }, type, quality);
});

const loadImageElement = (src = '', options = {}) => new Promise((resolve, reject) => {
  if (!src) {
    resolve(null);
    return;
  }
  const { timeoutMs = PAYMENT_QR_IMAGE_DECODE_TIMEOUT_MS } = options || {};
  const image = new Image();
  let settled = false;
  let timeoutId = null;
  const finish = (callback, value) => {
    if (settled) return;
    settled = true;
    if (timeoutId) clearTimeout(timeoutId);
    callback(value);
  };
  image.crossOrigin = 'anonymous';
  image.decoding = 'async';
  image.onload = () => finish(resolve, image);
  image.onerror = () => finish(reject, new Error(`Không thể tải ảnh: ${src}`));
  if (timeoutMs > 0) {
    timeoutId = setTimeout(() => {
      image.src = '';
      finish(reject, new Error('Tải ảnh quá thời gian.'));
    }, timeoutMs);
  }
  image.src = src;
});

const drawRoundedRect = (ctx, x, y, width, height, radius = 24) => {
  const safeRadius = Math.min(radius, width / 2, height / 2);
  ctx.beginPath();
  ctx.moveTo(x + safeRadius, y);
  ctx.arcTo(x + width, y, x + width, y + height, safeRadius);
  ctx.arcTo(x + width, y + height, x, y + height, safeRadius);
  ctx.arcTo(x, y + height, x, y, safeRadius);
  ctx.arcTo(x, y, x + width, y, safeRadius);
  ctx.closePath();
};

const wrapCanvasText = (ctx, text = '', maxWidth) => {
  const words = `${text}`.split(/\s+/).filter(Boolean);
  if (!words.length) return [''];
  const lines = [];
  let currentLine = words[0];

  for (let index = 1; index < words.length; index += 1) {
    const candidate = `${currentLine} ${words[index]}`;
    if (ctx.measureText(candidate).width <= maxWidth) {
      currentLine = candidate;
    } else {
      lines.push(currentLine);
      currentLine = words[index];
    }
  }

  lines.push(currentLine);
  return lines;
};

const withTimeout = (promise, timeoutMs = 12000, errorMessage = 'timeout') => Promise.race([
  promise,
  new Promise((_, reject) => setTimeout(() => {
    const timeoutError = new Error(errorMessage);
    timeoutError.code = 'HD_TIMEOUT';
    reject(timeoutError);
  }, timeoutMs))
]);

const getErrorText = (error) => `${error?.code || ''} ${error?.message || error || ''}`;

const isFirestoreInternalAssertionError = (error) => {
  const normalized = getErrorText(error).toLowerCase();
  return normalized.includes('internal assertion failed')
    || normalized.includes('unexpected state')
    || normalized.includes('firebase_firestore.js');
};

const isTimeoutLikeError = (error) => {
  if (error?.code === 'HD_TIMEOUT') return true;
  if (isFirestoreInternalAssertionError(error)) return true;
  const normalized = getErrorText(error)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/đ/g, 'd')
    .replace(/Đ/g, 'D')
    .toLowerCase();
  return normalized.includes('qua thoi gian')
    || normalized.includes('timeout')
    || normalized.includes('timed out')
    || normalized.includes('deadline')
    || normalized.includes('network')
    || (normalized.includes('luu') && normalized.includes('don') && normalized.includes('khoa thao tac'));
};

const isFirebaseQuotaError = (error) => {
  const normalized = getErrorText(error)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/đ/g, 'd')
    .replace(/Đ/g, 'D')
    .toLowerCase();
  return normalized.includes('429')
    || normalized.includes('quota exceeded')
    || normalized.includes('resource_exhausted')
    || normalized.includes('too many requests');
};

const getFriendlyFirebaseErrorMessage = (error, fallback = 'Thao tác chưa hoàn tất, vui lòng thử lại.') => {
  const rawMessage = `${error?.message || error || ''}`.trim();
  if (isFirestoreInternalAssertionError(error)) {
    return 'App đã ghi nhận thao tác và đang đồng bộ nền. Bạn không cần bấm gửi nhiều lần.';
  }
  if (isFirebaseQuotaError(error)) {
    return 'Firebase đang quá tải/hết hạn mức tạm thời. App đã giữ lệnh lại và sẽ tự đồng bộ khi hệ thống ổn định.';
  }
  if (isTimeoutLikeError(error)) {
    return 'Kết nối Firebase phản hồi chậm. App đã ghi nhận thao tác và sẽ tự đồng bộ lại.';
  }
  if (
    rawMessage.includes('__PRIVATE_')
    || rawMessage.includes('firebase_firestore')
    || rawMessage.length > 320
  ) {
    return fallback;
  }
  return rawMessage || fallback;
};

const normalizeRecoverableNoticeText = (value = '') => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'D')
  .toLowerCase();

const isRecoverableSyncNoticeMessage = (message = '') => {
  const normalized = normalizeRecoverableNoticeText(message?.message || message || '');
  return (
    (normalized.includes('app da ghi nhan thao tac') && normalized.includes('dong bo'))
    || normalized.includes('ban khong can bam gui nhieu lan')
    || normalized.includes('firebase dang tu phuc hoi ket noi realtime')
    || normalized.includes('ket noi firebase phan hoi cham')
    || normalized.includes('firebase sdk phan hoi cham')
  );
};

const getRecoverableSyncNoticeMessage = (message = '') => {
  const raw = `${message?.message || message || ''}`.trim();
  if (!raw) return 'App đã ghi nhận thao tác và đang đồng bộ nền.';
  if (raw.length <= 140) return raw;
  return 'App đã ghi nhận thao tác và đang đồng bộ nền.';
};

const emitRecoverableSyncNotice = (message = '') => {
  if (typeof window === 'undefined') return;
  window.dispatchEvent(new CustomEvent('hd-manager:recoverable-sync-notice', {
    detail: { message: getRecoverableSyncNoticeMessage(message) }
  }));
};

const installRecoverableSyncAlertGuard = () => {
  if (typeof window === 'undefined' || window.__hdManagerRecoverableAlertGuardInstalled) return;
  const originalAlert = window.alert;
  window.__hdManagerRecoverableAlertGuardInstalled = true;
  window.alert = (message) => {
    if (isRecoverableSyncNoticeMessage(message)) {
      emitRecoverableSyncNotice(message);
      return;
    }
    originalAlert.call(window, message);
  };
};

installRecoverableSyncAlertGuard();

