const levenshteinDistance = (source = '', target = '') => {
  const a = `${source}`;
  const b = `${target}`;
  if (!a.length) return b.length;
  if (!b.length) return a.length;

  const matrix = Array.from({ length: a.length + 1 }, () => Array(b.length + 1).fill(0));
  for (let i = 0; i <= a.length; i += 1) matrix[i][0] = i;
  for (let j = 0; j <= b.length; j += 1) matrix[0][j] = j;

  for (let i = 1; i <= a.length; i += 1) {
    for (let j = 1; j <= b.length; j += 1) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      );
    }
  }

  return matrix[a.length][b.length];
};

const buildTranscriptSearchCandidates = (value = '', maxWordsPerCandidate = 5) => {
  const normalized = normalizeLookupText(value);
  if (!normalized) return [];

  const tokens = normalized.split(' ').filter(Boolean);
  const candidates = new Set([normalized, collapseLookupText(normalized)]);

  tokens.forEach((token) => {
    if (token) candidates.add(token);
  });

  for (let start = 0; start < tokens.length; start += 1) {
    let buffer = '';
    for (let end = start; end < tokens.length && end < start + maxWordsPerCandidate; end += 1) {
      buffer = buffer ? `${buffer} ${tokens[end]}` : tokens[end];
      candidates.add(buffer);
      candidates.add(collapseLookupText(buffer));
    }
  }

  return [...candidates].filter(Boolean);
};

const scoreLookupTextMatch = (keyword = '', label = '') => {
  const needle = normalizeLookupText(keyword);
  const haystack = normalizeLookupText(label);
  if (!needle || !haystack) return 0;
  if (needle === haystack) return 1;

  const collapsedNeedle = collapseLookupText(needle);
  const collapsedHaystack = collapseLookupText(haystack);
  if (collapsedNeedle && collapsedNeedle === collapsedHaystack) return 0.99;

  let bestScore = 0;

  if (haystack.includes(needle) || needle.includes(haystack)) {
    const lengthPenalty = Math.abs(haystack.length - needle.length) / Math.max(haystack.length, needle.length, 1);
    bestScore = Math.max(bestScore, 0.92 - (lengthPenalty * 0.2));
  }

  if (collapsedHaystack.includes(collapsedNeedle) || collapsedNeedle.includes(collapsedHaystack)) {
    const lengthPenalty = Math.abs(collapsedHaystack.length - collapsedNeedle.length) / Math.max(collapsedHaystack.length, collapsedNeedle.length, 1);
    bestScore = Math.max(bestScore, 0.9 - (lengthPenalty * 0.18));
  }

  const needleTokens = tokenizeLookupText(needle);
  const haystackTokens = tokenizeLookupText(haystack);
  if (needleTokens.length && haystackTokens.length) {
    const uniqueNeedleTokens = [...new Set(needleTokens)];
    const matchedTokenCount = uniqueNeedleTokens.filter((token) => haystackTokens.includes(token)).length;
    const tokenCoverage = matchedTokenCount / Math.max(uniqueNeedleTokens.length, haystackTokens.length, 1);
    const tokenRecall = matchedTokenCount / Math.max(uniqueNeedleTokens.length, 1);
    bestScore = Math.max(bestScore, Math.max(tokenCoverage * 0.86, tokenRecall * 0.78));
  }

  if (collapsedNeedle.length >= 3 && collapsedHaystack.length >= 3) {
    const distance = levenshteinDistance(collapsedNeedle, collapsedHaystack);
    const normalizedDistanceScore = 1 - (distance / Math.max(collapsedNeedle.length, collapsedHaystack.length, 1));
    bestScore = Math.max(bestScore, normalizedDistanceScore * 0.84);
  }

  return Math.max(0, Math.min(1, bestScore));
};

const findBestEntityMatch = (
  keyword = '',
  collection = [],
  getLabel = (item) => item?.name || '',
  getAliases = () => []
) => {
  const normalizedCandidates = [
    ...(Array.isArray(keyword) ? keyword : [keyword]),
    ...buildTranscriptSearchCandidates(keyword)
  ].filter(Boolean);
  if (!normalizedCandidates.length) return null;

  let bestMatch = null;
  let bestScore = 0;

  collection.forEach((item) => {
    const labels = [getLabel(item), ...(getAliases(item) || [])]
      .map((value) => `${value || ''}`.trim())
      .filter(Boolean);
    if (!labels.length) return;

    labels.forEach((label) => {
      normalizedCandidates.forEach((candidate) => {
        const score = scoreLookupTextMatch(candidate, label);
        if (score > bestScore) {
          bestScore = score;
          bestMatch = item;
        }
      });
    });
  });

  return bestScore >= 0.46 ? bestMatch : null;
};

const fitCanvasFontSize = (ctx, text = '', { weight = 900, family = 'Arial', maxSize = 28, minSize = 12, maxWidth = 120 } = {}) => {
  let size = maxSize;
  while (size > minSize) {
    ctx.font = `${weight} ${size}px ${family}`;
    if (ctx.measureText(`${text || ''}`).width <= maxWidth) break;
    size -= 1;
  }
  return size;
};

const parseLooseQuantityValue = (value) => {
  if (value === undefined || value === null || value === '') return 0;
  if (typeof value === 'number') return Number.isFinite(value) ? Math.max(0, value) : 0;
  const matched = `${value}`.replace(/\s+/g, '').replace(',', '.').match(/-?\d+(?:\.\d+)?/);
  return matched ? Math.max(0, parseFloat(matched[0]) || 0) : 0;
};

const parseLooseMoneyValue = (value) => {
  if (value === undefined || value === null || value === '') return 0;
  if (typeof value === 'number') return Math.max(0, Math.round(value));
  const digits = `${value}`.replace(/[^\d]/g, '');
  return digits ? parseInt(digits, 10) : 0;
};

const getOrderLineUnitPriceValue = (item = {}) => parseLooseMoneyValue(
  item?.unitPrice
  ?? item?.price
  ?? item?.sellingPrice
  ?? item?.salePrice
  ?? item?.unitPriceVnd
  ?? item?.unit_price_vnd
  ?? item?.unit_price
);

const getOrderLineQuantityValue = (item = {}) => parseLooseQuantityValue(
  item?.quantity
  ?? item?.quantityValue
  ?? item?.quantityCount
  ?? item?.qty
  ?? item?.count
  ?? item?.pieceCount
);

const getOrderLineWeightKgValue = (item = {}) => parseLooseQuantityValue(
  item?.weightKg
  ?? item?.totalKg
  ?? item?.kg
  ?? item?.weight
  ?? (['kg', 'ky', 'ki', 'kilo'].includes(normalizeLookupText(item?.quantityUnit || item?.unit || '')) ? item?.quantity : 0)
);

const getOrderLineSizeLabel = (item = {}) => `${item?.size || item?.sizeLabel || item?.productSize || item?.variantSize || ''}`.trim();

const getOrderLineAttributeLabel = (item = {}) => `${item?.attributeLabel || item?.attribute || item?.variantLabel || item?.packaging || item?.packageUnit || ''}`.trim();

const areLooseQuantityValuesClose = (left, right, tolerance = 0.05) => {
  const leftValue = parseLooseQuantityValue(left);
  const rightValue = parseLooseQuantityValue(right);
  if (leftValue <= 0 || rightValue <= 0) return false;
  const allowedDelta = Math.max(tolerance, Math.max(leftValue, rightValue) * 0.01);
  return Math.abs(leftValue - rightValue) <= allowedDelta;
};

const RETURN_GOODS_STATUS_LABELS = {
  pending_pickup: 'Chưa lấy về kho',
  retrieved: 'Đã lấy về kho',
  discounted_sale: 'Giảm giá bán luôn'
};

const normalizeReturnGoodsStatus = (record = {}) => {
  if (record.status) return record.status;
  if (record.discountedSale) return 'discounted_sale';
  if (record.isRetrievedToWarehouse || record.retrievedToWarehouse) return 'retrieved';
  return 'pending_pickup';
};

const getOrderReturnGoodsRecords = (order = {}) => {
  const records = Array.isArray(order?.returnGoods)
    ? order.returnGoods
    : (Array.isArray(order?.returnedGoods) ? order.returnedGoods : []);
  return records.filter(record => record && record.isArchived !== true);
};

const summarizeOrderReturnGoods = (order = {}) => getOrderReturnGoodsRecords(order).reduce((acc, record) => {
  const pieces = parseLooseQuantityValue(record.pieces ?? record.quantity ?? record.returnPieces ?? 0);
  const weightKg = parseLooseQuantityValue(record.weightKg ?? record.returnWeightKg ?? 0);
  const discountAmount = parseLooseMoneyValue(record.discountAmount ?? record.discount ?? 0);
  const status = normalizeReturnGoodsStatus(record);

  acc.count += 1;
  acc.pieces += pieces;
  acc.weightKg += weightKg;
  acc.discountAmount += discountAmount;
  if (status === 'pending_pickup') {
    acc.pendingCount += 1;
    acc.pendingPieces += pieces;
    acc.pendingWeightKg += weightKg;
  }
  if (status === 'retrieved') {
    acc.retrievedCount += 1;
    acc.retrievedPieces += pieces;
    acc.retrievedWeightKg += weightKg;
  }
  if (status === 'discounted_sale') acc.discountedCount += 1;
  return acc;
}, {
  count: 0,
  pieces: 0,
  weightKg: 0,
  discountAmount: 0,
  pendingCount: 0,
  pendingPieces: 0,
  pendingWeightKg: 0,
  retrievedCount: 0,
  retrievedPieces: 0,
  retrievedWeightKg: 0,
  discountedCount: 0
});

const formatReturnGoodsQty = (summary = {}) => {
  const pieces = parseLooseQuantityValue(summary.pieces ?? summary.quantity ?? summary.returnPieces ?? 0);
  const weightKg = parseLooseQuantityValue(summary.weightKg ?? summary.returnWeightKg ?? 0);
  const parts = [];
  if (pieces > 0) parts.push(`${formatNumber(pieces)} con`);
  if (weightKg > 0) parts.push(`${formatNumber(weightKg)} kg`);
  return parts.join(' • ') || 'Chưa rõ số lượng';
};

const getOrderReturnProductSummary = (order = {}) => (Array.isArray(order.items) ? order.items : [])
  .map(item => item.description || item.productName || item.name)
  .filter(Boolean)
  .join(', ');

const drawSalesInvoiceShareImage = async ({
  order,
  company,
  customers = [],
  orders = [],
  payments = []
} = {}) => {
  if (!order) throw new Error('Chưa chọn hóa đơn để chia sẻ.');

  const customer = order.customer || customers.find(item => item.id === order.customerId) || {};
  const transferProfile = getInvoiceTransferProfile(company);
  const orderCode = formatOrderCode(order.id);
  const items = Array.isArray(order.items) ? order.items : [];
  const itemSubtotal = items.reduce((sum, item) => (
    sum + (parseLooseQuantityValue(item.quantity) * parseLooseMoneyValue(item.unitPrice))
  ), 0);
  const ledger = customer?.id ? buildCustomerLedger(customer, orders, payments) : null;
  const ledgerOrder = ledger?.orders?.find(item => item.id === order.id) || null;
  const explicitCustomerFee = parseLooseMoneyValue(order.customerExtraExpense ?? 0);
  const fallbackCustomerFee = order.extraExpensePayer === 'buyer'
    ? parseLooseMoneyValue(order.extraExpenseAmount ?? 0)
    : 0;
  const customerFeeAmount = explicitCustomerFee > 0 ? explicitCustomerFee : fallbackCustomerFee;
  const customerFeeName = `${order.extraExpenseName || 'Phụ phí'}`.trim() || 'Phụ phí';
  const orderAmount = parseLooseMoneyValue(ledgerOrder?.amount ?? order.amount ?? itemSubtotal);
  const ledgerOutstandingAmount = ledgerOrder
    ? parseLooseMoneyValue(ledgerOrder.outstandingAmount)
    : null;
  const storedPaidAmount = Math.max(
    parseLooseMoneyValue(order.appliedAmount),
    parseLooseMoneyValue(order.paidAmount),
    parseLooseMoneyValue(order.collectedAmount)
  );
  const paidAmount = Math.max(
    parseLooseMoneyValue(ledgerOrder?.appliedAmount),
    storedPaidAmount,
    Math.max(0, orderAmount - Math.max(0, ledgerOutstandingAmount ?? parseLooseMoneyValue(order.outstandingAmount ?? (orderAmount - storedPaidAmount))))
  );
  const outstandingAmount = Math.max(0, ledgerOutstandingAmount ?? parseLooseMoneyValue(order.outstandingAmount ?? (orderAmount - paidAmount)));
  const currentDebt = ledger ? Math.max(0, parseLooseMoneyValue(ledger.currentDebt)) : outstandingAmount;
  const oldDebt = Math.max(0, currentDebt - outstandingAmount);
  const totalToCollect = Math.max(0, outstandingAmount + oldDebt);
  const customerForDisplay = {
    ...customer,
    name: customer.name || order.customerNameSnapshot || order.customer?.name || '',
    customerName: customer.customerName || order.customerNameSnapshot || order.customer?.name || '',
    customerHonorific: customer.customerHonorific || order.customerHonorificSnapshot || order.customer?.customerHonorific || '',
    honorific: customer.honorific || order.honorificSnapshot || order.customer?.honorific || ''
  };
  const plainCustomerName = getCustomerPlainName(customerForDisplay) || 'Khách lẻ';
  const normalizedHonorific = getCustomerHonorific(customerForDisplay);
  const customerHonorificLabel = normalizedHonorific === 'anh'
    ? 'Anh'
    : normalizedHonorific === 'chi'
      ? 'Chị'
      : 'Anh/chị';
  const customerName = `${customerHonorificLabel} ${plainCustomerName}`.replace(/\s+/g, ' ').trim();
  const customerTitleLine = `Khách hàng - ${customerHonorificLabel} - ${plainCustomerName}`.replace(/\s+/g, ' ').trim();
  const customerPhone = customer.phone || customer.phoneNumber || order.customerPhoneSnapshot || order.customer?.phone || 'Chưa có số điện thoại';
  const customerAddress = customer.address || customer.shippingAddress || order.customerAddressSnapshot || order.customer?.address || 'Chưa có địa chỉ';
  const savedPaymentSourceForQr = getOrderPayosPaymentSource(order);
  const savedPaymentAmount = Math.max(0, Math.round(parseLooseMoneyValue(order.paymentAmount || 0)));
  const canUseSavedPaymentSourceForQr = Boolean(savedPaymentSourceForQr)
    && savedPaymentAmount > 0
    && Math.abs(savedPaymentAmount - Math.round(totalToCollect)) <= 1;
  const paymentOrderForQr = {
    ...order,
    currentPaymentDueAmount: totalToCollect,
    paymentDueAmount: totalToCollect,
    finalDebtAmount: totalToCollect,
    totalToCollect,
    paymentAmount: totalToCollect,
    outstandingAmount: totalToCollect
  };
  const localPaymentSourceForQr = buildOrderLocalPaymentQrPayload(paymentOrderForQr, company, { preferStoredSource: false });
  const paymentSourceForQr = localPaymentSourceForQr || (canUseSavedPaymentSourceForQr ? savedPaymentSourceForQr : '');
  const remotePaymentSourceForQr = (canUseSavedPaymentSourceForQr ? savedPaymentSourceForQr : '') || localPaymentSourceForQr;
  const qrAccountNumber = extractPaymentAccountNumberFromQrSource(remotePaymentSourceForQr);
  const transferAccountNumber = qrAccountNumber
    || normalizePaymentAccountNumber(order.receivingBankAccountNumber || order.companyBankAccountNumber || order.bankAccountNumber || '')
    || transferProfile.sepayReceivingAccountNumber
    || transferProfile.accountNumber;
  const transferBankName = order.receivingBankName || order.receivingBankCode || transferProfile.bankName || transferProfile.bankId || 'Ngân hàng';
  const transferAccountName = order.receivingBankAccountName || transferProfile.accountName || 'Chưa cài đặt chủ tài khoản';
  const qrUrl = buildPayosPaymentQrImageSource(remotePaymentSourceForQr);
  const codeOnlyQrUrl = buildCodeOnlyPaymentQrImageSource(qrUrl);
  if (!paymentSourceForQr && !qrUrl) {
    throw new Error('Hóa đơn chưa có mã QR SePay. Vui lòng tạo QR SePay trước khi chia sẻ.');
  }

  let qrImage = null;
  let qrImageIsLocal = false;
  const localQrDataUrl = await buildLocalPaymentQrDataUrl(paymentSourceForQr, { width: 520 });
  if (localQrDataUrl) {
    try {
      qrImage = await loadImageElement(localQrDataUrl, { timeoutMs: PAYMENT_QR_IMAGE_FAST_DECODE_TIMEOUT_MS });
      qrImageIsLocal = Boolean(qrImage);
    } catch (error) {
      qrImage = null;
      qrImageIsLocal = false;
    }
  }

  if (!qrImage && qrUrl) {
    const qrCandidates = Array.from(new Set([codeOnlyQrUrl, qrUrl].filter(Boolean)));
    for (const qrCandidate of qrCandidates) {
      const useFastTimeout = qrCandidate === codeOnlyQrUrl;
      try {
        const qrDataUrl = await getCachedPaymentQrImageDataUrl(qrCandidate, {
          timeoutMs: useFastTimeout ? PAYMENT_QR_IMAGE_FAST_FETCH_TIMEOUT_MS : PAYMENT_QR_IMAGE_FETCH_TIMEOUT_MS
        });
        qrImage = await loadImageElement(qrDataUrl, {
          timeoutMs: useFastTimeout ? PAYMENT_QR_IMAGE_FAST_DECODE_TIMEOUT_MS : PAYMENT_QR_IMAGE_DECODE_TIMEOUT_MS
        });
        qrImageIsLocal = false;
        if (qrImage) break;
      } catch (fallbackError) {
        try {
          qrImage = await loadImageElement(qrCandidate, {
            timeoutMs: useFastTimeout ? PAYMENT_QR_IMAGE_FAST_DECODE_TIMEOUT_MS : PAYMENT_QR_IMAGE_DECODE_TIMEOUT_MS
          });
          qrImageIsLocal = false;
          if (qrImage) break;
        } catch (directError) {
          qrImage = null;
          qrImageIsLocal = false;
        }
      }
    }
  }

  if (!qrImage) {
    throw new Error('Không tải được mã QR SePay để đưa vào ảnh hóa đơn. Vui lòng kiểm tra mạng rồi chia sẻ lại.');
  }

  const width = 1080;
  const margin = 34;
  const contentX = 58;
  const contentW = width - (contentX * 2);
  const headerH = 220;
  const customerH = 0;
  const rowHeights = items.length
    ? items.map(item => {
        const name = `${item.description || item.productName || 'Sản phẩm'}`.trim();
        return name.length > 34 ? 82 : 58;
      })
    : [58];
  const tableH = 64 + rowHeights.reduce((sum, height) => sum + height, 0);
  const summaryH = (4 + (customerFeeAmount > 0 ? 1 : 0)) * 38 + 6;
  const qrBlockH = 300;
  const footerH = 120;
  const height = Math.max(980, margin * 2 + headerH + customerH + 34 + tableH + summaryH + qrBlockH + footerH);

  const canvas = document.createElement('canvas');
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext('2d');
  if (!ctx) throw new Error('Không thể tạo ảnh hóa đơn trên thiết bị này.');

  const fontFamily = '"Segoe UI", Arial, sans-serif';
  const setFont = (size, weight = 700) => {
    ctx.font = `${weight} ${size}px ${fontFamily}`;
  };
  const drawText = (text, x, y, size = 24, weight = 700, color = '#111827') => {
    setFont(size, weight);
    ctx.fillStyle = color;
    ctx.fillText(`${text || ''}`, x, y);
  };
  const drawCentered = (text, x, y, boxW, size = 24, weight = 700, color = '#111827') => {
    setFont(size, weight);
    ctx.fillStyle = color;
    ctx.textAlign = 'center';
    ctx.fillText(`${text || ''}`, x + boxW / 2, y);
    ctx.textAlign = 'left';
  };
  const drawRight = (text, x, y, boxW, size = 24, weight = 700, color = '#111827') => {
    setFont(size, weight);
    ctx.fillStyle = color;
    ctx.textAlign = 'right';
    ctx.fillText(`${text || ''}`, x + boxW, y);
    ctx.textAlign = 'left';
  };
  const drawWrapped = (text, x, y, maxW, size = 24, weight = 700, color = '#111827', maxLines = 2, lineHeight = 28) => {
    setFont(size, weight);
    ctx.fillStyle = color;
    const lines = wrapCanvasText(ctx, text, maxW).slice(0, maxLines);
    lines.forEach((line, index) => ctx.fillText(line, x, y + index * lineHeight));
  };
  const getQrCodeCropBox = (image, isCleanQr = false) => {
    const sourceW = Math.max(1, image?.naturalWidth || image?.width || 1);
    const sourceH = Math.max(1, image?.naturalHeight || image?.height || 1);
    if (isCleanQr) {
      const square = Math.min(sourceW, sourceH);
      return {
        sx: Math.max(0, (sourceW - square) / 2),
        sy: Math.max(0, (sourceH - square) / 2),
        sw: square,
        sh: square
      };
    }

    try {
      const probeSize = 220;
      const probeCanvas = document.createElement('canvas');
      probeCanvas.width = probeSize;
      probeCanvas.height = probeSize;
      const probeCtx = probeCanvas.getContext('2d', { willReadFrequently: true });
      if (!probeCtx) throw new Error('Không đọc được ảnh QR.');
      probeCtx.fillStyle = '#ffffff';
      probeCtx.fillRect(0, 0, probeSize, probeSize);
      probeCtx.drawImage(image, 0, 0, sourceW, sourceH, 0, 0, probeSize, probeSize);
      const pixels = probeCtx.getImageData(0, 0, probeSize, probeSize).data;
      const denseRows = [];
      const denseCols = [];
      for (let row = 0; row < probeSize; row += 1) {
        let dark = 0;
        for (let col = 0; col < probeSize; col += 1) {
          const offset = (row * probeSize + col) * 4;
          const r = pixels[offset];
          const g = pixels[offset + 1];
          const b = pixels[offset + 2];
          if ((r + g + b) / 3 < 185) dark += 1;
        }
        if (dark > probeSize * 0.18) denseRows.push(row);
      }
      for (let col = 0; col < probeSize; col += 1) {
        let dark = 0;
        for (let row = 0; row < probeSize; row += 1) {
          const offset = (row * probeSize + col) * 4;
          const r = pixels[offset];
          const g = pixels[offset + 1];
          const b = pixels[offset + 2];
          if ((r + g + b) / 3 < 185) dark += 1;
        }
        if (dark > probeSize * 0.18) denseCols.push(col);
      }
      if (denseRows.length > 8 && denseCols.length > 8) {
        const minRow = Math.max(0, Math.min(...denseRows) - 10);
        const maxRow = Math.min(probeSize - 1, Math.max(...denseRows) + 10);
        const minCol = Math.max(0, Math.min(...denseCols) - 10);
        const maxCol = Math.min(probeSize - 1, Math.max(...denseCols) + 10);
        const centerX = ((minCol + maxCol) / 2) / probeSize * sourceW;
        const centerY = ((minRow + maxRow) / 2) / probeSize * sourceH;
        const moduleW = (maxCol - minCol + 1) / probeSize * sourceW;
        const moduleH = (maxRow - minRow + 1) / probeSize * sourceH;
        const square = Math.min(sourceW, sourceH, Math.max(moduleW, moduleH) * 1.04);
        return {
          sx: Math.max(0, Math.min(sourceW - square, centerX - square / 2)),
          sy: Math.max(0, Math.min(sourceH - square, centerY - square / 2)),
          sw: square,
          sh: square
        };
      }
    } catch (error) {
      // Some remote QR images cannot be sampled; use a safe crop that removes template text below the QR.
    }

    const square = Math.min(sourceW, sourceH);
    return {
      sx: Math.max(0, (sourceW - square) / 2),
      sy: 0,
      sw: square,
      sh: square
    };
  };
  const drawQrCodeOnly = (image, x, y, size, isCleanQr = false) => {
    const { sx, sy, sw, sh } = getQrCodeCropBox(image, isCleanQr);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(x, y, size, size);
    ctx.drawImage(image, sx, sy, sw, sh, x, y, size, size);
  };

  ctx.fillStyle = '#f8fafc';
  ctx.fillRect(0, 0, width, height);

  ctx.fillStyle = '#ffffff';
  ctx.strokeStyle = '#d1d5db';
  ctx.lineWidth = 2;
  drawRoundedRect(ctx, margin, margin, width - margin * 2, height - margin * 2, 28);
  ctx.fill();
  ctx.stroke();

  const customerCardX = contentX;
  const customerCardY = 72;
  const customerCardW = 450;
  const customerCardH = 128;
  ctx.fillStyle = '#f8fafc';
  ctx.strokeStyle = '#e5e7eb';
  ctx.lineWidth = 2;
  drawRoundedRect(ctx, customerCardX, customerCardY, customerCardW, customerCardH, 24);
  ctx.fill();
  ctx.stroke();
  drawWrapped(customerTitleLine, customerCardX + 28, customerCardY + 38, customerCardW - 56, 21, 900, '#059669', 1, 26);
  drawText(`ĐT: ${customerPhone}`, customerCardX + 28, customerCardY + 76, 19, 800, '#374151');
  drawWrapped(`Địa chỉ: ${customerAddress}`, customerCardX + 28, customerCardY + 108, customerCardW - 56, 19, 800, '#374151', 1, 24);

  drawCentered('HÓA ĐƠN BÁN HÀNG', 500, 125, 420, 34, 900, '#111827');
  drawCentered(`${orderCode} - ${formatDateTimeLabel(order.date)}`, 500, 168, 420, 18, 800, '#4b5563');

  let y = margin + headerH + 34;
  const tableX = contentX;
  const tableY = y;
  const colProduct = 500;
  const colPrice = 155;
  const colQty = 130;
  const colTotal = contentW - colProduct - colPrice - colQty;
  const tableHeaderH = 64;
  ctx.fillStyle = '#f8fafc';
  ctx.strokeStyle = '#111827';
  ctx.lineWidth = 2;
  drawRoundedRect(ctx, tableX, tableY, contentW, tableH, 20);
  ctx.fill();
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(tableX, tableY + tableHeaderH);
  ctx.lineTo(tableX + contentW, tableY + tableHeaderH);
  ctx.stroke();

  drawCentered('Sản phẩm', tableX, tableY + 42, colProduct, 22, 900);
  drawCentered('Giá', tableX + colProduct, tableY + 42, colPrice, 22, 900);
  drawCentered('SL', tableX + colProduct + colPrice, tableY + 42, colQty, 22, 900);
  drawCentered('TT', tableX + colProduct + colPrice + colQty, tableY + 42, colTotal, 22, 900);

  let rowY = tableY + tableHeaderH;
  const tableRows = items.length ? items : [{ description: 'Chưa có sản phẩm', quantity: 0, unitPrice: 0 }];
  tableRows.forEach((item, index) => {
    const rowH = rowHeights[index] || 58;
    if (index > 0) {
      ctx.strokeStyle = '#d1d5db';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(tableX, rowY);
      ctx.lineTo(tableX + contentW, rowY);
      ctx.stroke();
    }
    const quantity = parseLooseQuantityValue(item.quantity);
    const unitPrice = parseLooseMoneyValue(item.unitPrice);
    const lineTotal = quantity * unitPrice;
    const rowTextY = rowY + Math.min(40, rowH - 18);
    drawWrapped(item.description || item.productName || 'Sản phẩm', tableX + 24, rowTextY, colProduct - 48, 21, 800, '#111827', 2, 25);
    drawCentered(formatCurrency(unitPrice), tableX + colProduct, rowTextY, colPrice, 21, 800);
    drawCentered(formatNumber(quantity), tableX + colProduct + colPrice, rowTextY, colQty, 21, 800);
    drawRight(formatCurrency(lineTotal), tableX + colProduct + colPrice + colQty, rowTextY, colTotal - 26, 21, 800);
    rowY += rowH;
  });

  y += tableH + 28;
  const summaryRows = [
    ['Đã thu', `${formatCurrency(paidAmount)} đ`, 900],
    ...(customerFeeAmount > 0
      ? [[customerFeeName, `${formatCurrency(customerFeeAmount)} đ`, 800, '#2563eb']]
      : []),
    ['Còn nợ đơn này', `${formatCurrency(outstandingAmount)} đ`, 700],
    ['Công nợ cũ', `${formatCurrency(oldDebt)} đ`, 700],
    ['Còn phải thu', `${formatCurrency(totalToCollect)} đ`, 900]
  ];
  summaryRows.forEach(([label, value, weight, color = '#111827'], index) => {
    const lineY = y + index * 38;
    drawText(label, contentX, lineY, 24, weight, color);
    drawRight(value, contentX, lineY, contentW, 25, weight, color);
  });

  y += summaryH;
  ctx.strokeStyle = '#111827';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.moveTo(contentX, y - 22);
  ctx.lineTo(contentX + contentW, y - 22);
  ctx.stroke();

  const paymentY = y + 6;
  const qrSize = 170;
  const qrX = contentX + 42;
  const qrY = paymentY;
  drawQrCodeOnly(qrImage, qrX, qrY, qrSize, qrImageIsLocal);
  const bankX = qrX + qrSize + 54;
  const bankW = 315;
  const transferX = bankX + bankW + 36;
  const transferW = contentX + contentW - transferX - 18;
  const transferMemo = buildOrderTransferMemo(order);
  drawText(transferBankName, bankX, paymentY + 48, 30, 900);
  drawWrapped(transferAccountName, bankX, paymentY + 100, bankW, 22, 900, '#111827', 2, 28);
  drawText(transferAccountNumber || 'Chưa cài đặt số tài khoản', bankX, paymentY + 154, 22, 900);
  drawText('Nội dung chuyển khoản', transferX, paymentY + 48, 18, 800, '#6b7280');
  drawWrapped(transferMemo || orderCode, transferX, paymentY + 96, transferW, 28, 900, '#111827', 2, 34);

  const paymentBottomY = Math.max(qrY + qrSize, paymentY + 170);
  const footerY = paymentBottomY + 48;
  ctx.strokeStyle = '#d1d5db';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(contentX, footerY);
  ctx.lineTo(contentX + contentW, footerY);
  ctx.stroke();
  const thanksY = footerY + 58;
  const footerLogoSize = 48;
  const footerCompanyName = (company?.name || 'HD Manager').toUpperCase();
  setFont(25, 900);
  const footerText = `${footerCompanyName} - Xin cảm ơn!`;
  const footerTotalW = footerLogoSize + 16 + ctx.measureText(footerText).width;
  const footerStartX = contentX + Math.max(0, (contentW - footerTotalW) / 2);
  ctx.fillStyle = '#ecfdf5';
  ctx.strokeStyle = '#d1fae5';
  ctx.lineWidth = 2;
  drawRoundedRect(ctx, footerStartX, thanksY - 34, footerLogoSize, footerLogoSize, footerLogoSize / 2);
  ctx.fill();
  ctx.stroke();
  drawCentered(buildCompanyMonogram(company?.name || 'HD'), footerStartX, thanksY - 3, footerLogoSize, 18, 900, '#059669');
  drawText(footerText, footerStartX + footerLogoSize + 16, thanksY, 25, 900, '#111827');

  return canvasToBlob(canvas, 'image/png');
};

const normalizeWarehouseMeasureUnit = (unit = '') => {
  const normalized = normalizeLookupText(unit || '').replace(/\s+/g, '');
  const unitMap = {
    con: 'Con',
    cai: 'Cái',
    bo: 'Bộ',
    boc: 'Bọc',
    bao: 'Bao',
    thung: 'Thùng',
    can: 'Can',
    tui: 'Túi',
    ro: 'Rổ',
    kg: 'Kg',
    ky: 'Kg',
    ki: 'Kg',
    kilo: 'Kg'
  };
  return unitMap[normalized] || normalizeLeadingLabel(unit || 'Đơn vị');
};

const WAREHOUSE_STABLE_STOCK_UNITS = ['Con', 'Cái', 'Bộ', 'Bao', 'Bọc', 'Thùng', 'Can', 'Túi', 'Rổ'];
const WAREHOUSE_MEASURE_SORT_ORDER = [...WAREHOUSE_STABLE_STOCK_UNITS, 'Kg'];
const WAREHOUSE_IMPORT_SOURCE_OPTIONS = [
  { value: 'purchase_resale', label: 'Mua ngoài bán lại' },
  { value: 'production_input', label: 'Nguyên liệu sản xuất' },
  { value: 'internal_production', label: 'Thành phẩm sản xuất' },
  { value: 'opening_balance', label: 'Tồn đầu kỳ' },
  { value: 'adjustment', label: 'Điều chỉnh tồn' }
];
const normalizeWarehouseImportSourceType = (sourceType = '') => {
  const normalized = `${sourceType || ''}`.trim();
  return WAREHOUSE_IMPORT_SOURCE_OPTIONS.some(option => option.value === normalized)
    ? normalized
    : 'purchase_resale';
};
const getWarehouseImportSourceLabel = (sourceType = '') => (
  WAREHOUSE_IMPORT_SOURCE_OPTIONS.find(option => option.value === normalizeWarehouseImportSourceType(sourceType))?.label
  || 'Mua ngoài bán lại'
);

const isWarehouseWeightUnit = (unit = '') => normalizeLookupText(normalizeWarehouseMeasureUnit(unit || '')) === normalizeLookupText('Kg');

const isWarehouseStableStockUnit = (unit = '') => {
  const normalizedKey = normalizeLookupText(normalizeWarehouseMeasureUnit(unit || ''));
  return WAREHOUSE_STABLE_STOCK_UNITS.some(stableUnit => normalizeLookupText(stableUnit) === normalizedKey);
};

const getWarehouseMeasureSortRank = (unit = '') => {
  const normalizedKey = normalizeLookupText(normalizeWarehouseMeasureUnit(unit || ''));
  const index = WAREHOUSE_MEASURE_SORT_ORDER.findIndex(item => normalizeLookupText(item) === normalizedKey);
  return index === -1 ? 99 : index;
};

const sortWarehouseMeasureRows = (rows = []) => [...(rows || [])].sort((a, b) => {
  const rankDiff = getWarehouseMeasureSortRank(a?.unit) - getWarehouseMeasureSortRank(b?.unit);
  if (rankDiff !== 0) return rankDiff;
  return `${a?.unit || ''}`.localeCompare(`${b?.unit || ''}`, 'vi');
});

const hasWarehouseMeaningfulMeasure = (measure = {}) => (
  parseLooseQuantityValue(measure.imported) > 0
  || parseLooseQuantityValue(measure.exported) > 0
  || Math.abs(parseLooseQuantityValue(measure.remaining)) > 0.0001
  || parseLooseQuantityValue(measure.actual) > 0
  || parseLooseQuantityValue(measure.quantity) > 0
);

const getWarehousePrimaryMeasureRows = (measureRows = []) => {
  const rows = Array.isArray(measureRows) ? measureRows : [];
  const meaningfulRows = rows.filter(hasWarehouseMeaningfulMeasure);
  const stableRows = meaningfulRows.filter(measure => isWarehouseStableStockUnit(measure.unit));
  if (stableRows.length > 0) return sortWarehouseMeasureRows(stableRows);
  const nonWeightRows = meaningfulRows.filter(measure => !isWarehouseWeightUnit(measure.unit));
  if (nonWeightRows.length > 0) return sortWarehouseMeasureRows(nonWeightRows);
  return sortWarehouseMeasureRows(meaningfulRows.length > 0 ? meaningfulRows : rows);
};

const annotateWarehouseMeasureRows = (measureRows = []) => {
  const sortedRows = sortWarehouseMeasureRows(measureRows || []);
  const primaryRows = getWarehousePrimaryMeasureRows(sortedRows);
  const primaryKeys = new Set(primaryRows.map(measure => normalizeLookupText(measure.unit)));
  return sortedRows.map(measure => ({
    ...measure,
    isPrimaryStockUnit: primaryKeys.has(normalizeLookupText(measure.unit)),
    isReferenceStockUnit: !primaryKeys.has(normalizeLookupText(measure.unit))
  }));
};

const normalizeWarehouseMeasureEntries = (entries = []) => {
  const grouped = new Map();
  (entries || []).forEach((entry) => {
    const quantity = parseLooseQuantityValue(entry?.quantity ?? entry?.value ?? entry?.amount ?? entry?.total);
    const unit = normalizeWarehouseMeasureUnit(entry?.unit || entry?.label || '');
    if (quantity <= 0 || !unit) return;
    const key = normalizeLookupText(unit);
    const current = grouped.get(key) || { unit, quantity: 0 };
    current.quantity += quantity;
    grouped.set(key, current);
  });
  return Array.from(grouped.values());
};

const buildWarehouseImportMeasureEntries = ({ totalKg = 0, quantity = 0, quantityUnit = 'Con', extraMeasures = [] } = {}) => normalizeWarehouseMeasureEntries([
  totalKg > 0 ? { unit: 'Kg', quantity: totalKg } : null,
  quantity > 0 ? { unit: quantityUnit || 'Con', quantity } : null,
  ...(extraMeasures || [])
].filter(Boolean));

const buildStoredWarehouseMeasureEntries = (item = {}) => {
  const totalKg = parseLooseQuantityValue(item.totalKg ?? item.weightKg);
  const quantity = parseLooseQuantityValue(item.quantity ?? item.totalQuantity);
  const quantityUnit = normalizeWarehouseMeasureUnit(item.quantityUnit || item.unit || 'Con');
  const primaryUnitKey = normalizeLookupText(quantityUnit);
  const kgKey = normalizeLookupText('Kg');
  if (totalKg <= 0 && quantity <= 0 && Array.isArray(item.measures) && item.measures.length > 0) {
    return normalizeWarehouseMeasureEntries(item.measures);
  }
  const extraSource = Array.isArray(item.extraMeasures) && item.extraMeasures.length > 0
    ? item.extraMeasures
    : Array.isArray(item.measures)
      ? item.measures.filter((measure) => {
        const unitKey = normalizeLookupText(normalizeWarehouseMeasureUnit(measure?.unit || measure?.label || ''));
        return unitKey && unitKey !== kgKey && unitKey !== primaryUnitKey;
      })
      : [];
  return buildWarehouseImportMeasureEntries({
    totalKg,
    quantity,
    quantityUnit,
    extraMeasures: extraSource
  });
};

const sumWarehouseWeightEntries = (entries = []) => {
  if (!Array.isArray(entries)) return 0;
  return entries.reduce((sum, entry) => {
    const rawValue = typeof entry === 'object'
      ? entry?.quantity ?? entry?.value ?? entry?.weightKg ?? entry?.kg ?? entry?.total
      : entry;
    return sum + parseLooseQuantityValue(rawValue);
  }, 0);
};

const buildWarehouseDispatchMeasureEntries = (item = {}, product = null) => {
  const quantity = parseLooseQuantityValue(
    item.pieceCount
    ?? item.quantity
    ?? item.quantityCount
    ?? item.totalQuantity
    ?? item.count
    ?? item.actualQuantity
  );
  const quantityUnit = normalizeWarehouseMeasureUnit(
    item.quantityUnit
    || item.unit
    || item.countUnit
    || item.actualQuantityUnit
    || product?.unit
    || (quantity > 0 ? 'Con' : 'Đơn vị')
  );
  const weightFromEntries = sumWarehouseWeightEntries(item.weightEntries);
  const weightKg = parseLooseQuantityValue(
    item.weightKg
    ?? item.totalKg
    ?? item.kg
    ?? item.actualWeightKg
    ?? item.weight
  ) || weightFromEntries;
  const quantityUnitKey = normalizeLookupText(quantityUnit);
  const shouldAddWeightKg = weightKg > 0 && (quantity <= 0 || quantityUnitKey !== normalizeLookupText('Kg'));
  return normalizeWarehouseMeasureEntries([
    quantity > 0 ? { unit: quantityUnit, quantity } : null,
    shouldAddWeightKg ? { unit: 'Kg', quantity: weightKg } : null
  ].filter(Boolean));
};

const normalizeCustomerHonorific = (value = '') => {
  const normalized = normalizeLookupText(value || '').replace(/\s+/g, '');
  if (['a', 'anh', 'ong', 'chu', 'bacnam'].includes(normalized)) return 'anh';
  if (['c', 'chi', 'co', 'bacnu'].includes(normalized)) return 'chi';
  return '';
};

const CUSTOMER_HONORIFIC_OPTIONS = [
  { value: '', label: '--' },
  { value: 'anh', label: 'Anh' },
  { value: 'chi', label: 'Chị' }
];

const inferCustomerHonorificFromName = (name = '') => {
  const firstToken = normalizeLookupText(`${name || ''}`.trim().split(/\s+/)[0] || '').replace(/[.:,-]/g, '');
  return normalizeCustomerHonorific(firstToken);
};

const stripCustomerHonorificPrefix = (name = '') => {
  const text = `${name || ''}`.trim();
  if (!text) return '';
  const parts = text.split(/\s+/);
  const firstToken = normalizeLookupText(parts[0] || '').replace(/[.:,-]/g, '');
  return normalizeCustomerHonorific(firstToken) ? parts.slice(1).join(' ') : text;
};

const formatCustomerNameDraft = (name = '') => toTitleCasePreservingSpacing(`${name || ''}`);

const getCustomerHonorific = (customer = {}) => (
  normalizeCustomerHonorific(customer?.customerHonorific || customer?.honorific)
  || inferCustomerHonorificFromName(customer?.name || customer?.customerName || '')
);

const getCustomerPlainName = (customer = {}) => {
  const rawName = `${customer?.plainName || customer?.customerName || customer?.name || ''}`.trim();
  return toTitleCase(stripCustomerHonorificPrefix(rawName)).trim();
};

const getCustomerDisplayName = (customer = {}) => {
  const plainName = getCustomerPlainName(customer);
  const honorific = getCustomerHonorific(customer);
  if (!plainName) return '';
  if (honorific === 'anh') return `Anh ${plainName}`;
  if (honorific === 'chi') return `Chị ${plainName}`;
  return plainName;
};

const buildCustomerNameAliases = (customer = {}) => {
  const rawName = `${customer?.name || customer?.customerName || customer?.fullName || ''}`.trim();
  const plainName = getCustomerPlainName(customer);
  const displayName = getCustomerDisplayName(customer);
  return [...new Set([rawName, plainName, displayName].filter(Boolean))];
};

const formatCustomerLocationForDisplay = (location = null) => {
  if (!location) return '';
  if (typeof location === 'string') return location;
  const lat = location.lat ?? location.latitude;
  const lng = location.lng ?? location.longitude;
  if (Number.isFinite(Number(lat)) && Number.isFinite(Number(lng))) {
    return `${Number(lat).toFixed(6)}, ${Number(lng).toFixed(6)}`;
  }
  return location.url || location.address || '';
};

const buildCustomerMapsUrlFromLocation = (location = null, fallbackAddress = '') => {
  if (!location && !fallbackAddress) return '';
  if (typeof location === 'string') {
    const text = location.trim();
    if (/^https?:\/\//i.test(text)) return text;
    if (text) return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(text)}`;
  }
  const lat = location?.lat ?? location?.latitude;
  const lng = location?.lng ?? location?.longitude;
  if (Number.isFinite(Number(lat)) && Number.isFinite(Number(lng))) {
    return `https://www.google.com/maps/search/?api=1&query=${Number(lat)},${Number(lng)}`;
  }
  if (location?.url) return location.url;
  const address = location?.address || fallbackAddress;
  return address ? `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}` : '';
};

const parseCustomerLocationInput = (input = '') => {
  const raw = `${input || ''}`.trim();
  if (!raw) return null;
  const decoded = (() => {
    try { return decodeURIComponent(raw); } catch (error) { return raw; }
  })();
  const candidates = [
    decoded.match(/@(-?\d+(?:[\.,]\d+)?)\s*,\s*(-?\d+(?:[\.,]\d+)?)/),
    decoded.match(/[?&](?:q|query)=(-?\d+(?:[\.,]\d+)?)\s*,\s*(-?\d+(?:[\.,]\d+)?)/),
    decoded.match(/(-?\d{1,3}(?:[\.,]\d+)?)\s*[,;]\s*(-?\d{1,3}(?:[\.,]\d+)?)/)
  ].filter(Boolean);

  for (const match of candidates) {
    const lat = Number(`${match[1]}`.replace(',', '.'));
    const lng = Number(`${match[2]}`.replace(',', '.'));
    if (Number.isFinite(lat) && Number.isFinite(lng) && Math.abs(lat) <= 90 && Math.abs(lng) <= 180) {
      return {
        type: 'gps',
        lat: Number(lat.toFixed(6)),
        lng: Number(lng.toFixed(6)),
        url: `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`
      };
    }
  }

  if (/^https?:\/\//i.test(raw)) {
    return { type: 'maps_url', url: raw };
  }

  return { type: 'address', address: raw, url: buildCustomerMapsUrlFromLocation(raw) };
};

const buildCustomerLocationFromPosition = (position = null) => {
  const lat = position?.coords?.latitude;
  const lng = position?.coords?.longitude;
  if (!Number.isFinite(Number(lat)) || !Number.isFinite(Number(lng))) return null;
  return {
    type: 'gps',
    lat: Number(Number(lat).toFixed(6)),
    lng: Number(Number(lng).toFixed(6)),
    accuracy: Number.isFinite(Number(position?.coords?.accuracy)) ? Math.round(Number(position.coords.accuracy)) : null,
    url: `https://www.google.com/maps/search/?api=1&query=${Number(lat)},${Number(lng)}`
  };
};

const normalizeCustomerLocationFields = (rawLocation = null, fallbackAddress = '', source = 'manual') => {
  const address = `${fallbackAddress || ''}`.trim();
  const parsedLocation = rawLocation && typeof rawLocation === 'object'
    ? rawLocation
    : parseCustomerLocationInput(rawLocation || '');

  if (!parsedLocation) {
    return {
      location: null,
      locationUrl: address ? buildCustomerMapsUrlFromLocation(null, address) : '',
      locationInput: address,
      locationLat: null,
      locationLng: null,
      mapLocation: null,
      locationUpdatedAt: new Date().toISOString(),
      locationSource: source
    };
  }

  const rawLat = parsedLocation.lat ?? parsedLocation.latitude;
  const rawLng = parsedLocation.lng ?? parsedLocation.longitude;
  const lat = Number(rawLat);
  const lng = Number(rawLng);
  const hasGps = Number.isFinite(lat) && Number.isFinite(lng) && Math.abs(lat) <= 90 && Math.abs(lng) <= 180;
  const normalizedLocation = hasGps
    ? {
        ...parsedLocation,
        type: parsedLocation.type || 'gps',
        lat: Number(lat.toFixed(6)),
        lng: Number(lng.toFixed(6)),
        latitude: Number(lat.toFixed(6)),
        longitude: Number(lng.toFixed(6)),
        address: parsedLocation.address || address,
        url: parsedLocation.url || buildCustomerMapsUrlFromLocation({ lat, lng }, address)
      }
    : {
        ...parsedLocation,
        address: parsedLocation.address || address,
        url: parsedLocation.url || buildCustomerMapsUrlFromLocation(parsedLocation, address)
      };
  const locationUrl = buildCustomerMapsUrlFromLocation(normalizedLocation, address);
  const locationInput = locationUrl || normalizedLocation.address || address;
  const mapLocation = hasGps
    ? {
        lat: normalizedLocation.lat,
        lng: normalizedLocation.lng,
        latitude: normalizedLocation.latitude,
        longitude: normalizedLocation.longitude
      }
    : null;

  return {
    location: normalizedLocation,
    locationUrl,
    locationInput,
    locationLat: hasGps ? normalizedLocation.lat : null,
    locationLng: hasGps ? normalizedLocation.lng : null,
    mapLocation,
    locationUpdatedAt: new Date().toISOString(),
    locationSource: source
  };
};

const getCustomerLocationDisplayText = (customer = {}) => (
  formatCustomerLocationForDisplay(customer?.location)
  || customer?.locationUrl
  || customer?.address
  || ''
);

const getCustomerLocationShareText = (customer = {}) => (
  buildCustomerMapsUrlFromLocation(customer?.location, customer?.address)
  || customer?.locationUrl
  || customer?.address
  || ''
);

const normalizeCustomerPriceOverrides = (source = {}) => {
  const rawOverrides = source?.priceOverrides || source?.customPrices || {};
  const entries = Array.isArray(rawOverrides)
    ? rawOverrides.map(item => [item.productId || item.id, item])
    : Object.entries(rawOverrides);

  const normalizeVariantConfig = (variant = {}, index = 0) => {
    if (!variant || typeof variant !== 'object') return null;
    const price = parseLooseMoneyValue(variant.price ?? variant.unitPrice ?? variant.sellingPrice);
    const size = `${variant.size ?? variant.sizeLabel ?? variant.weightKg ?? ''}`.trim();
    const attributeLabel = `${variant.attributeLabel ?? variant.productAttribute ?? variant.attribute ?? variant.variant ?? ''}`.trim();
    if (price <= 0 && !size && !attributeLabel) return null;
    return {
      id: `${variant.id || variant.localId || `variant_${index + 1}`}`,
      price,
      size,
      attributeLabel
    };
  };

  return entries.reduce((acc, [productId, config]) => {
    const cleanProductId = `${productId || ''}`.trim();
    const rawPrice = typeof config === 'object' && config !== null
      ? config.price ?? config.unitPrice ?? config.sellingPrice
      : config;
    const cleanPrice = parseLooseMoneyValue(rawPrice);
    const cleanSize = typeof config === 'object' && config !== null
      ? `${config.size ?? config.sizeLabel ?? config.weightKg ?? ''}`.trim()
      : '';
    const cleanAttributeLabel = typeof config === 'object' && config !== null
      ? `${config.attributeLabel ?? config.productAttribute ?? config.attribute ?? config.variant ?? ''}`.trim()
      : '';
    const variants = typeof config === 'object' && config !== null && Array.isArray(config.variants)
      ? config.variants.map(normalizeVariantConfig).filter(Boolean)
      : [];
    if (cleanProductId && (cleanPrice > 0 || cleanSize || cleanAttributeLabel || variants.length > 0)) {
      acc[cleanProductId] = { price: cleanPrice, size: cleanSize, attributeLabel: cleanAttributeLabel, variants };
    }
    return acc;
  }, {});
};

const normalizeCustomerProductIds = (customer = {}, products = []) => {
  const validProductIds = new Set((products || []).map(product => product.id).filter(Boolean));
  const savedIds = Array.isArray(customer?.customerProductIds)
    ? customer.customerProductIds
    : (Array.isArray(customer?.quotedProductIds) ? customer.quotedProductIds : []);
  const priceOverrideIds = Object.keys(normalizeCustomerPriceOverrides(customer || {}));
  const candidateIds = savedIds.length > 0 ? savedIds : priceOverrideIds;
  return [...new Set(candidateIds.map(productId => `${productId || ''}`.trim()).filter(Boolean))]
    .filter(productId => validProductIds.size === 0 || validProductIds.has(productId));
};

const getCustomerFixedProductIds = (customer = {}, products = []) => normalizeCustomerProductIds(customer || {}, products || []);

const createCustomerBranchId = () => `branch_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`;

const normalizeCustomerBranches = (customer = {}, products = []) => {
  const rawBranches = Array.isArray(customer?.branches)
    ? customer.branches
    : (Array.isArray(customer?.customerBranches) ? customer.customerBranches : []);

  return rawBranches
    .map((branch = {}, index) => {
      const id = `${branch.id || branch.branchId || branch.code || `branch_${index + 1}`}`.trim();
      const name = `${branch.name || branch.branchName || branch.label || ''}`.trim();
      const address = `${branch.address || branch.deliveryAddress || branch.locationText || ''}`.trim();
      const phone = `${branch.phone || branch.contactPhone || ''}`.trim();
      const note = `${branch.note || branch.description || ''}`.trim();
      const customerProductIds = normalizeCustomerProductIds(branch, products);
      return {
        ...branch,
        id: id || `branch_${index + 1}`,
        name,
        address,
        phone,
        note,
        customerProductIds
      };
    })
    .filter(branch => branch.name || branch.address || branch.phone || branch.note || branch.customerProductIds.length > 0);
};

const getCustomerBranchById = (customer = {}, branchId = '', products = []) => {
  const cleanBranchId = `${branchId || ''}`.trim();
  if (!cleanBranchId) return null;
  return normalizeCustomerBranches(customer, products).find(branch => branch.id === cleanBranchId) || null;
};

const getCustomerBranchDisplayName = (branch = {}, index = 0) => {
  const name = `${branch.name || branch.branchName || branch.label || ''}`.trim();
  if (name) return name;
  return `Chi nhánh ${index + 1}`;
};

const getCustomerBranchFixedProductIds = (customer = {}, branchId = '', products = []) => {
  const branch = getCustomerBranchById(customer, branchId, products);
  const branchProductIds = branch ? normalizeCustomerProductIds(branch, products) : [];
  return branchProductIds.length > 0 ? branchProductIds : getCustomerFixedProductIds(customer, products);
};

const getCustomerBranchProductConfigSource = (customer = null, branchId = '', products = []) => {
  const branch = branchId ? getCustomerBranchById(customer, branchId, products) : null;
  if (!branch) return customer;
  const customerFixedProducts = Array.isArray(customer?.fixedProducts) ? customer.fixedProducts : [];
  const branchFixedProducts = Array.isArray(branch?.fixedProducts) ? branch.fixedProducts : [];
  const customerProductIds = normalizeCustomerProductIds(customer || {}, products || []);
  const branchProductIds = normalizeCustomerProductIds(branch || {}, products || []);
  return {
    ...(customer || {}),
    ...branch,
    fixedProducts: [...customerFixedProducts, ...branchFixedProducts],
    customerProductIds: [...new Set([...customerProductIds, ...branchProductIds])]
  };
};

const getCustomerProductConfig = (customer = null, product = null) => {
  const productId = product?.id || '';
  const customerPrices = normalizeCustomerPriceOverrides(customer || {});
  return productId ? customerPrices[productId] || null : null;
};

const getCustomerProductPrice = (customer = null, product = null) => {
  const customPrice = getCustomerProductConfig(customer, product)?.price || 0;
  return customPrice > 0 ? customPrice : parseLooseMoneyValue(product?.sellingPrice || 0);
};

const getCustomerProductSize = (customer = null, product = null) => getCustomerProductConfig(customer, product)?.size || '';

const getCustomerProductAttribute = (customer = null, product = null) => {
  const configuredAttribute = `${getCustomerProductConfig(customer, product)?.attributeLabel || ''}`.trim();
  if (!configuredAttribute) return '';
  const productAttributes = getProductAttributes(product);
  if (productAttributes.length === 0) return '';
  return productAttributes.find(attribute => normalizeLookupText(attribute) === normalizeLookupText(configuredAttribute)) || '';
};

const getCustomerProductVariants = (customer = null, product = null) => {
  const config = getCustomerProductConfig(customer, product);
  const productAttributes = getProductAttributes(product);
  const normalizeAttribute = (attribute = '') => {
    const raw = `${attribute || ''}`.trim();
    if (!raw) return '';
    if (productAttributes.length === 0) return raw;
    return productAttributes.find(option => normalizeLookupText(option) === normalizeLookupText(raw)) || raw;
  };
  const normalizeVariant = (variant = {}, index = 0) => {
    const price = parseLooseMoneyValue(variant.price ?? variant.unitPrice ?? variant.sellingPrice);
    const size = `${variant.size ?? variant.sizeLabel ?? variant.weightKg ?? ''}`.trim();
    const attributeLabel = normalizeAttribute(variant.attributeLabel ?? variant.productAttribute ?? variant.attribute ?? variant.variant ?? '');
    if (price <= 0 && !size && !attributeLabel) return null;
    return {
      id: `${variant.id || variant.localId || `${product?.id || 'product'}_variant_${index}`}`,
      price,
      size,
      attributeLabel
    };
  };
  const variants = [];
  const baseVariant = normalizeVariant(config || {}, 0);
  if (baseVariant) variants.push({ ...baseVariant, id: `${product?.id || 'product'}_default` });
  (Array.isArray(config?.variants) ? config.variants : []).forEach((variant, index) => {
    const normalized = normalizeVariant(variant, index + 1);
    if (normalized) variants.push(normalized);
  });
  const unique = new Map();
  variants.forEach((variant) => {
    const key = `${normalizeLookupText(variant.size)}__${normalizeLookupText(variant.attributeLabel)}__${roundMoneyValue(variant.price)}`;
    if (!unique.has(key)) unique.set(key, variant);
  });
  if (unique.size > 0) return Array.from(unique.values());
  return [{
    id: `${product?.id || 'product'}_default`,
    price: getCustomerProductPrice(customer, product),
    size: '',
    attributeLabel: ''
  }];
};

const hasCustomerProductPrice = (customer = null, productId = '') => {
  const customerPrices = normalizeCustomerPriceOverrides(customer || {});
  return Boolean(productId && customerPrices[productId]?.price > 0);
};

const hasCustomerProductConfig = (customer = null, productId = '') => {
  const customerPrices = normalizeCustomerPriceOverrides(customer || {});
  const config = productId ? customerPrices[productId] : null;
  return Boolean(config && (config.price > 0 || config.size || config.attributeLabel || (Array.isArray(config.variants) && config.variants.length > 0)));
};

const getQuoteCustomerHonorificLabel = (customer = null) => {
  const honorific = getCustomerHonorific(customer || {});
  if (honorific === 'anh') return 'Anh';
  if (honorific === 'chi') return 'Chị';
  return 'Quý khách';
};

const buildCustomerQuoteShareText = ({
  customer = null,
  quoteProducts = [],
  currentCompany = null,
  employees = [],
  employee = null,
  orders = [],
  payments = [],
  priceOverrides = null
} = {}) => {
  const companyName = (currentCompany?.displayName || currentCompany?.name || 'HD Manager').trim();
  const plainCustomerName = customer ? (getCustomerPlainName(customer) || customer.name || customer.customerName || '') : '';
  const honorificLabel = getQuoteCustomerHonorificLabel(customer);
  const contactPerson = employees.find(item => item.id === customer?.empId) || employee || {};
  const contactLine = [contactPerson?.name, contactPerson?.phone].filter(Boolean).join(' - ') || companyName;
  const normalizedOverrides = priceOverrides ? normalizeCustomerPriceOverrides({ priceOverrides }) : null;
  const ledger = customer?.id ? buildCustomerLedger(customer, orders, payments) : null;
  const debtAmount = Math.max(0, ledger?.currentDebt || customer?.currentDebt || 0);
  const productLines = (quoteProducts || []).flatMap((product) => {
    const overrideConfig = normalizedOverrides?.[product.id] || null;
    const quoteVariants = overrideConfig
      ? getCustomerProductVariants({ ...customer, priceOverrides: { ...(customer?.priceOverrides || {}), [product.id]: overrideConfig } }, product)
      : getCustomerProductVariants(customer, product);
    const unit = product.unit || 'đv';
    return quoteVariants.map((variant) => {
      const finalPrice = parseLooseMoneyValue(variant.price) > 0 ? parseLooseMoneyValue(variant.price) : getCustomerProductPrice(customer, product);
      const sizeText = variant.size ? ` | Size: ${variant.size}` : '';
      const attributeText = variant.attributeLabel ? ` | Thuộc tính: ${variant.attributeLabel}` : '';
      return `${product.name}: ${formatCurrency(finalPrice)} đ/${unit}${sizeText}${attributeText}`;
    });
  }).map((line, index) => `${index + 1}. ${line}`);

  return [
    `Kính gửi: ${honorificLabel}${plainCustomerName ? ` - ${plainCustomerName}` : ''}.`,
    '',
    companyName.toUpperCase(),
    '',
    'Danh sách sản phẩm cần báo:',
    ...(productLines.length > 0 ? productLines : ['Chưa có sản phẩm cần báo.']),
    ...(debtAmount > 0 ? [
      '',
      `Công nợ hiện tại của khách: ${formatCurrency(debtAmount)} đ.`,
      'Công ty xin nhắc nhẹ để Quý khách tiện đối chiếu và thanh toán khi thuận tiện.'
    ] : []),
    '',
    'Nếu cần đặt hàng, Quý khách vui lòng phản hồi lại tin nhắn này.',
    `Liên hệ: ${contactLine}`
  ].join('\n');
};

const normalizeAiOrderDate = (value) => {
  if (!value) return getTodayString();
  const raw = `${value}`.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;

  const slashMatch = raw.match(/^(\d{1,2})[\/\-](\d{1,2})(?:[\/\-](\d{2,4}))?$/);
  if (slashMatch) {
    const day = parseInt(slashMatch[1], 10);
    const month = parseInt(slashMatch[2], 10);
    let year = slashMatch[3] ? parseInt(slashMatch[3], 10) : new Date().getFullYear();
    if (year < 100) year += 2000;
    const parsed = new Date(year, month - 1, day);
    if (!Number.isNaN(parsed.getTime())) return toDateInputString(parsed);
  }

  const parsed = new Date(raw);
  return Number.isNaN(parsed.getTime()) ? getTodayString() : toDateInputString(parsed);
};

const readFileAsGeminiInlineData = (file) => new Promise((resolve, reject) => {
  const reader = new FileReader();
  reader.onload = () => {
    const raw = `${reader.result || ''}`;
    const [, data = ''] = raw.split(',');
    resolve({
      mimeType: file?.type || 'image/jpeg',
      data
    });
  };
  reader.onerror = () => reject(new Error('Không thể đọc ảnh để gửi cho AI.'));
  reader.readAsDataURL(file);
});

const readFileAsDataUrl = (file) => new Promise((resolve, reject) => {
  const reader = new FileReader();
  reader.onload = () => resolve(`${reader.result || ''}`);
  reader.onerror = () => reject(new Error('Không thể đọc ảnh để gửi cho AI.'));
  reader.readAsDataURL(file);
});

const readFileAsText = (file) => new Promise((resolve, reject) => {
  if (!file) {
    reject(new Error('Chưa chọn file sao lưu.'));
    return;
  }
  const reader = new FileReader();
  reader.onload = () => resolve(`${reader.result || ''}`);
  reader.onerror = () => reject(new Error('Không thể đọc file sao lưu.'));
  reader.readAsText(file, 'utf-8');
});

