const normalizeResetDateKey = (value) => {
  if (value === null || value === undefined || value === '') return '';
  if (typeof value === 'number') {
    const parsed = new Date(value);
    return Number.isNaN(parsed.getTime()) ? '' : parsed.toISOString().slice(0, 10);
  }
  const raw = `${value || ''}`.trim();
  if (!raw) return '';
  const isoMatch = raw.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) return `${isoMatch[1]}-${isoMatch[2]}-${isoMatch[3]}`;
  const slashMatch = raw.match(/^(\d{1,2})[/-](\d{1,2})[/-](\d{4})/);
  if (slashMatch) {
    return `${slashMatch[3]}-${slashMatch[2].padStart(2, '0')}-${slashMatch[1].padStart(2, '0')}`;
  }
  const parsed = new Date(raw);
  return Number.isNaN(parsed.getTime()) ? '' : parsed.toISOString().slice(0, 10);
};

const getResetRecordDateKey = (data = {}, id = '') => {
  const candidates = [
    data.date,
    data.orderDate,
    data.createdDate,
    data.deliveryDate,
    data.dispatchDate,
    data.paymentDate,
    data.paidAt,
    data.requestedAt,
    data.receivedAt,
    data.sentAt,
    data.createdAt,
    data.updatedAt,
    id
  ];
  for (const candidate of candidates) {
    const dateKey = normalizeResetDateKey(candidate);
    if (dateKey) return dateKey;
  }
  return '';
};

const isResetRecordInDateRange = (data = {}, id = '', range = {}) => {
  const dateFrom = normalizeResetDateKey(range?.dateFrom);
  const dateTo = normalizeResetDateKey(range?.dateTo);
  if (!dateFrom && !dateTo) return true;
  const dateKey = getResetRecordDateKey(data, id);
  if (!dateKey) return false;
  return (!dateFrom || dateKey >= dateFrom) && (!dateTo || dateKey <= dateTo);
};

const normalizeBackupCollectionItems = (collectionValue) => {
  if (Array.isArray(collectionValue)) {
    return collectionValue.filter(item => item && typeof item === 'object');
  }
  if (collectionValue && typeof collectionValue === 'object') {
    return Object.entries(collectionValue)
      .filter(([, item]) => item && typeof item === 'object')
      .map(([id, item]) => ({ id: item.id || id, ...item }));
  }
  return [];
};

const countBackupRecords = (backup = {}) => {
  const collections = backup?.collections || {};
  return BACKUP_DATA_COLLECTIONS.reduce((total, collectionName) => (
    total + normalizeBackupCollectionItems(collections[collectionName]).length
  ), 0);
};

const buildBackupFilename = (companyName = 'HD Manager') => {
  const safeCompanyName = sanitizeShareFileName(companyName || 'HD-Manager');
  return `hd-manager-backup-${safeCompanyName}-${getTodayString()}.json`;
};

const AUTO_BACKUP_STORAGE_KEY = 'hd-manager-auto-backup-state-v1';
const AUTO_BACKUP_NATIVE_DIR = 'HDManager/AutoBackups';
const AUTO_BACKUP_DELAY_MS = isNativeAppShellRuntime() ? 5 * 60 * 1000 : 45000;

const normalizeBackupSerializableValue = (value) => {
  if (value === undefined) return null;
  if (value === null) return null;
  if (value instanceof Date) return value.toISOString();
  if (value && typeof value.toDate === 'function') {
    try {
      return value.toDate().toISOString();
    } catch (_) {
      return String(value);
    }
  }
  if (Array.isArray(value)) return value.map(normalizeBackupSerializableValue);
  if (value && typeof value === 'object') {
    return Object.fromEntries(
      Object.entries(value).map(([key, nestedValue]) => [key, normalizeBackupSerializableValue(nestedValue)])
    );
  }
  return value;
};

const buildAutoBackupStateKey = (companyId = '', dateKey = getTodayString()) => `${companyId || 'no-company'}:${dateKey}`;

const loadAutoBackupState = () => {
  if (typeof window === 'undefined' || !window.localStorage) return {};
  try {
    return JSON.parse(window.localStorage.getItem(AUTO_BACKUP_STORAGE_KEY) || '{}') || {};
  } catch (_) {
    return {};
  }
};

const saveAutoBackupState = (state = {}) => {
  if (typeof window === 'undefined' || !window.localStorage) return;
  try {
    window.localStorage.setItem(AUTO_BACKUP_STORAGE_KEY, JSON.stringify(state || {}));
  } catch (_) {
    // Sao lưu tự động không được làm gián đoạn nghiệp vụ chính.
  }
};

const getAutoBackupStateForCompany = (companyId = '', dateKey = getTodayString()) => {
  const state = loadAutoBackupState();
  return state[buildAutoBackupStateKey(companyId, dateKey)] || null;
};

const setAutoBackupStateForCompany = (companyId = '', dateKey = getTodayString(), info = {}) => {
  const state = loadAutoBackupState();
  state[buildAutoBackupStateKey(companyId, dateKey)] = {
    ...(state[buildAutoBackupStateKey(companyId, dateKey)] || {}),
    ...info,
    companyId,
    dateKey,
    updatedAt: new Date().toISOString()
  };
  saveAutoBackupState(state);
};

const saveAutomaticBackupFile = async ({ filename, content }) => {
  if (!filename || !content) return { status: 'skipped' };
  if (Capacitor.getPlatform() !== 'web') {
    const path = `${AUTO_BACKUP_NATIVE_DIR}/${filename}`;
    await Filesystem.writeFile({
      path,
      data: content,
      directory: Directory.Documents,
      encoding: Encoding.UTF8,
      recursive: true
    });
    return { status: 'saved', path };
  }
  return { status: 'manual_required' };
};

const readImageFileAsDataUrl = (file, maxSize = 512, quality = 0.82) => new Promise((resolve, reject) => {
  if (!file) {
    reject(new Error('Chưa chọn ảnh.'));
    return;
  }
  const reader = new FileReader();
  reader.onload = () => {
    const image = new Image();
    image.onload = () => {
      const scale = Math.min(1, maxSize / Math.max(image.width || maxSize, image.height || maxSize));
      const width = Math.max(1, Math.round((image.width || maxSize) * scale));
      const height = Math.max(1, Math.round((image.height || maxSize) * scale));
      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        reject(new Error('Không thể xử lý ảnh đại diện.'));
        return;
      }
      ctx.drawImage(image, 0, 0, width, height);
      resolve(canvas.toDataURL('image/jpeg', quality));
    };
    image.onerror = () => reject(new Error('Không thể đọc ảnh đại diện.'));
    image.src = `${reader.result || ''}`;
  };
  reader.onerror = () => reject(new Error('Không thể đọc ảnh đại diện.'));
  reader.readAsDataURL(file);
});

const DELIVERY_WEIGHT_TOLERANCE = 0.01;
const getDeliveryReportWeightStatus = (report = {}) => {
  const expectedWeight = parseLooseQuantityValue(report.expectedWeightKg ?? report.expectedWeight ?? report.dispatchWeightKg);
  const actualWeight = parseLooseQuantityValue(report.actualWeightKg ?? report.actualWeight);
  if (actualWeight <= 0) {
    return { status: 'not_measured', expectedWeight, actualWeight: 0, diff: 0, isMismatch: false };
  }
  if (expectedWeight <= 0) {
    return { status: 'reported', expectedWeight: 0, actualWeight, diff: actualWeight, isMismatch: false };
  }
  const diff = Number((actualWeight - expectedWeight).toFixed(2));
  const isMismatch = Math.abs(diff) > DELIVERY_WEIGHT_TOLERANCE;
  return {
    status: isMismatch ? (diff > 0 ? 'over' : 'short') : 'matched',
    expectedWeight,
    actualWeight,
    diff,
    isMismatch
  };
};

const CASHFLOW_APPROVAL_STATUS = {
  pending: 'pending_handover',
  approved: 'approved',
  rejected: 'rejected'
};
const requiresCashflowApproval = (item = {}) => Boolean(
  item.requiresApproval ||
  item.approvalStatus === CASHFLOW_APPROVAL_STATUS.pending ||
  item.approvalStatus === CASHFLOW_APPROVAL_STATUS.rejected ||
  item.handoverStatus === 'pending' ||
  item.handoverStatus === 'handed_over' ||
  item.sourceType === 'driver_delivery_expense' ||
  item.sourceType === 'employee_reported_expense' ||
  item.sourceType === 'employee_reported_income' ||
  (item.sourceType === 'driver_cash' && item.createdByRole === 'driver')
);
const isCashflowOfficial = (item = {}) => (
  !requiresCashflowApproval(item) ||
  item.approvalStatus === CASHFLOW_APPROVAL_STATUS.approved
);
const getCashflowApprovalMeta = (item = {}) => {
  if (!requiresCashflowApproval(item)) {
    return { status: CASHFLOW_APPROVAL_STATUS.approved, label: 'Đã xác nhận', classes: 'bg-emerald-50 text-emerald-700 border-emerald-100' };
  }
  if (item.approvalStatus === CASHFLOW_APPROVAL_STATUS.approved) {
    return { status: CASHFLOW_APPROVAL_STATUS.approved, label: 'Đã xác nhận', classes: 'bg-emerald-50 text-emerald-700 border-emerald-100' };
  }
  if (item.approvalStatus === CASHFLOW_APPROVAL_STATUS.rejected) {
    return { status: CASHFLOW_APPROVAL_STATUS.rejected, label: 'Không duyệt', classes: 'bg-rose-50 text-rose-700 border-rose-100' };
  }
  return { status: CASHFLOW_APPROVAL_STATUS.pending, label: 'Chờ xác nhận', classes: 'bg-amber-50 text-amber-700 border-amber-100' };
};

const readBlobAsGeminiInlineData = (blob, fallbackMimeType = 'audio/webm') => new Promise((resolve, reject) => {
  if (!blob || !(blob instanceof Blob) || blob.size <= 0) {
    reject(new Error('Thiết bị này chưa hỗ trợ lấy vị trí GPS.'));
    return;
  }

  const reader = new FileReader();
  reader.onload = () => {
    const raw = `${reader.result || ''}`;
    const [, data = ''] = raw.split(',');
    resolve({
      mimeType: blob?.type || fallbackMimeType,
      data
    });
  };
  reader.onerror = () => reject(new Error('Không thể đọc ảnh để gửi cho AI.'));
  reader.readAsDataURL(blob);
});

const extractJsonPayload = (text = '') => {
  const raw = `${text || ''}`.trim();
  if (!raw) throw new Error('AI chưa trả về nội dung nếu xử lý.');

  const fenced = raw.match(/```json\s*([\s\S]*?)```/i) || raw.match(/```\s*([\s\S]*?)```/i);
  const source = fenced ? fenced[1].trim() : raw;
  const startIndex = source.search(/[\[{]/);
  const endIndex = Math.max(source.lastIndexOf('}'), source.lastIndexOf(']'));
  const candidate = startIndex >= 0 && endIndex >= startIndex
    ? source.slice(startIndex, endIndex + 1)
    : source;

  return JSON.parse(candidate);
};

const isGeminiBillingOrQuotaError = (value = '') => /quota|rate|busy|overloaded|prepayment|prepaid|billing|credits?\s+are\s+depleted|resource[_\s-]*exhausted|429/i.test(`${value || ''}`);

const createGeminiBillingError = (message = '') => {
  const error = new Error('gemini_billing_or_quota_error');
  error.code = 'gemini_billing_or_quota_error';
  error.originalMessage = message;
  return error;
};

const normalizeVehicleOcrText = (value = '') => `${value || ''}`
  .replace(/\r/g, '\n')
  .replace(/[“”]/g, '"')
  .replace(/[‘’]/g, "'")
  .replace(/[|]/g, ' ')
  .replace(/[ \t]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const removeVietnameseDiacritics = (value = '') => `${value || ''}`
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/đ/g, 'd')
  .replace(/Đ/g, 'D');

const normalizeOcrComparable = (value = '') => removeVietnameseDiacritics(value)
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const cleanVehicleOcrValue = (value = '', maxLength = 90) => `${value || ''}`
  .replace(/^[\s:：;,\-.]+/, '')
  .replace(/\s{2,}/g, ' ')
  .trim()
  .slice(0, maxLength)
  .trim();

const parseVehicleOcrDateToInput = (value = '') => {
  const raw = `${value || ''}`;
  const dateMatch = raw.match(/\b(\d{1,2})[\/.\-](\d{1,2})[\/.\-](\d{2,4})\b/) || raw.match(/\b(\d{4})[\/.\-](\d{1,2})[\/.\-](\d{1,2})\b/);
  if (!dateMatch) return '';
  let day;
  let month;
  let year;
  if (dateMatch[1]?.length === 4) {
    year = dateMatch[1];
    month = dateMatch[2];
    day = dateMatch[3];
  } else {
    day = dateMatch[1];
    month = dateMatch[2];
    year = dateMatch[3];
  }
  if (year.length === 2) year = Number(year) > 50 ? `19${year}` : `20${year}`;
  const date = new Date(Number(year), Number(month) - 1, Number(day));
  if (Number.isNaN(date.getTime())) return '';
  return [
    String(date.getFullYear()).padStart(4, '0'),
    String(date.getMonth() + 1).padStart(2, '0'),
    String(date.getDate()).padStart(2, '0')
  ].join('-');
};

const getVehicleOcrLines = (text = '') => normalizeVehicleOcrText(text)
  .split('\n')
  .map(line => line.trim())
  .filter(Boolean);

const pickVehicleOcrValue = (text = '', labels = [], maxLength = 90) => {
  const lines = getVehicleOcrLines(text);
  const comparableLabels = labels.map(normalizeOcrComparable).filter(Boolean);
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index];
    const comparableLine = normalizeOcrComparable(line);
    const matchedLabel = comparableLabels.find(label => comparableLine.includes(label));
    if (!matchedLabel) continue;

    const colonValue = line.split(/[:：]/).slice(1).join(':');
    if (colonValue.trim()) return cleanVehicleOcrValue(colonValue, maxLength);

    const afterLabelPattern = new RegExp(`${matchedLabel.split(' ').join('[\\s:：.-]*')}[\\s:：.-]*(.+)$`, 'i');
    const asciiLine = normalizeOcrComparable(line);
    const afterLabel = asciiLine.match(afterLabelPattern)?.[1];
    if (afterLabel?.trim()) return cleanVehicleOcrValue(afterLabel, maxLength);

    for (let offset = 1; offset <= 2; offset += 1) {
      const nextLine = lines[index + offset];
      if (nextLine && !comparableLabels.some(label => normalizeOcrComparable(nextLine).includes(label))) {
        return cleanVehicleOcrValue(nextLine, maxLength);
      }
    }
  }
  return '';
};

const extractVehiclePlateFromOcr = (text = '') => {
  const compactText = removeVietnameseDiacritics(text).toUpperCase().replace(/[^\dA-Z.\-\s]/g, ' ');
  const match = compactText.match(/\b\d{2}\s*[A-Z]{1,2}\s*[-.]?\s*\d{3,5}(?:[.\-\s]?\d{2})?\b/);
  if (!match) return '';
  return match[0].replace(/\s+/g, '').replace(/(\d{2})([A-Z]{1,2})(\d)/, '$1$2-$3');
};

const extractVehicleCodeAfterLabels = (text = '', labels = []) => {
  const value = pickVehicleOcrValue(text, labels, 40);
  const match = removeVietnameseDiacritics(value).toUpperCase().match(/[A-Z0-9][A-Z0-9\-./]{3,}/);
  return match ? cleanVehicleOcrValue(match[0], 40) : value;
};

const parseVehicleDocumentOcrText = (text = '') => {
  const rawText = normalizeVehicleOcrText(text);
  const registrationDateRaw = pickVehicleOcrValue(rawText, ['Ngày cấp', 'Ngay cap', 'Ngày đăng ký lần đầu', 'Ngay dang ky lan dau'], 40);
  const inspectionExpiryRaw = pickVehicleOcrValue(rawText, ['Có hiệu lực đến', 'Co hieu luc den', 'Hạn kiểm định', 'Han kiem dinh', 'Ngày hết hạn', 'Ngay het han', 'Đến ngày', 'Den ngay'], 50);
  const draft = {
    plateNumber: extractVehiclePlateFromOcr(rawText) || extractVehicleCodeAfterLabels(rawText, ['Biển số đăng ký', 'Bien so dang ky', 'Biển số', 'Bien so', 'Registration number']),
    vehicleOwner: pickVehicleOcrValue(rawText, ['Chủ xe', 'Chu xe', 'Tên chủ xe', 'Ten chu xe', 'Chủ sở hữu', 'Chu so huu'], 80),
    vehicleBrand: pickVehicleOcrValue(rawText, ['Nhãn hiệu', 'Nhan hieu', 'Make', 'Brand'], 50),
    vehicleModel: pickVehicleOcrValue(rawText, ['Số loại', 'So loai', 'Dòng xe', 'Dong xe', 'Model', 'Kiểu loại', 'Kieu loai'], 70),
    vehicleType: pickVehicleOcrValue(rawText, ['Loại xe', 'Loai xe', 'Type of vehicle', 'Loại phương tiện', 'Loai phuong tien'], 60),
    vehicleColor: pickVehicleOcrValue(rawText, ['Màu sơn', 'Mau son', 'Màu xe', 'Mau xe', 'Color'], 40),
    chassisNumber: extractVehicleCodeAfterLabels(rawText, ['Số khung', 'So khung', 'Chassis', 'Chassis No']),
    engineNumber: extractVehicleCodeAfterLabels(rawText, ['Số máy', 'So may', 'Engine', 'Engine No']),
    registrationNumber: extractVehicleCodeAfterLabels(rawText, ['Số đăng ký', 'So dang ky', 'Số seri', 'So seri', 'Serial']),
    registrationDate: parseVehicleOcrDateToInput(registrationDateRaw),
    inspectionCertificateNo: extractVehicleCodeAfterLabels(rawText, ['Số phiếu', 'So phieu', 'Số GCN', 'So GCN', 'Certificate No', 'Số kiểm định', 'So kiem dinh']),
    inspectionExpiry: parseVehicleOcrDateToInput(inspectionExpiryRaw),
    inspectionCenter: pickVehicleOcrValue(rawText, ['Đơn vị kiểm định', 'Don vi kiem dinh', 'Trung tâm đăng kiểm', 'Trung tam dang kiem', 'Inspection center'], 90),
    confidence: 0.62
  };

  const foundCount = Object.entries(draft)
    .filter(([key, value]) => key !== 'confidence' && `${value || ''}`.trim())
    .length;
  draft.confidence = Math.min(0.92, Math.max(0.35, foundCount / 10));
  return draft;
};

const requestVehicleDocumentDraftFromLocalOcr = async (documents = []) => {
  const validDocuments = documents.filter(item => item?.file);
  if (!validDocuments.length) throw new Error('Chưa chọn ảnh đăng ký hoặc đăng kiểm xe.');
  let createWorker;
  try {
    ({ createWorker } = await import('tesseract.js'));
  } catch {
    throw new Error('Chưa tải được bộ OCR cục bộ. Bạn hãy thử lại hoặc nhập nhanh thông tin chính.');
  }

  let worker;
  const textChunks = [];
  try {
    worker = await createWorker('vie+eng', 1, {
      logger: () => {}
    });
    for (const item of validDocuments) {
      const result = await worker.recognize(item.file);
      const text = result?.data?.text || '';
      if (text.trim()) textChunks.push(text);
    }
  } finally {
    if (worker) await worker.terminate().catch(() => {});
  }

  const combinedText = textChunks.join('\n\n');
  const draft = parseVehicleDocumentOcrText(combinedText);
  const hasUsefulData = Object.entries(draft)
    .some(([key, value]) => key !== 'confidence' && `${value || ''}`.trim());
  if (!hasUsefulData) {
    throw new Error('OCR cục bộ chưa nhận diện được thông tin rõ ràng. Bạn hãy thử ảnh nét hơn hoặc nhập tay.');
  }
  return draft;
};

const requestVehicleDocumentDraftFromGemini = async (documents = []) => {
  const validDocuments = documents.filter(item => item?.file);
  if (!validDocuments.length) throw new Error('Chưa chọn ảnh đăng ký hoặc đăng kiểm xe.');
  if (!GEMINI_API_KEY) throw new Error('Chưa cấu hình AI để đọc ảnh giấy tờ xe. Bạn vẫn có thể tải ảnh lên và nhập tay.');

  const url = buildGeminiGenerateUrl();
  const inlineDocuments = await Promise.all(validDocuments.map(async item => ({
    type: item.type,
    inlineData: await readFileAsGeminiInlineData(item.file)
  })));
  const prompt = [
    'Bạn là AI đọc giấy đăng ký xe và giấy chứng nhận kiểm định xe cơ giới tại Việt Nam.',
    'Hãy trích xuất dữ liệu để điền hồ sơ xe trong app quản lý tài sản.',
    'Ưu tiên đọc thật chính xác biển số xe và dòng/nhãn hiệu xe trên giấy đăng ký hoặc đăng kiểm.',
    'vehicleModel là dòng xe/kiểu loại nếu giấy tờ có ghi, ví dụ "THACO OLLIN", "HINO", "HYUNDAI PORTER".',
    'plateNumber phải giữ đúng biển số, ví dụ "61C-123.45" hoặc "61C12345".',
    'Chỉ trả về JSON hợp lệ, không markdown, không giải thích.',
    'Nếu thông tin không thấy rõ thì để chuỗi rỗng.',
    'Schema: {"plateNumber":"","vehicleOwner":"","vehicleBrand":"","vehicleModel":"","vehicleType":"","vehicleColor":"","chassisNumber":"","engineNumber":"","registrationNumber":"","registrationDate":"","inspectionCertificateNo":"","inspectionExpiry":"","inspectionCenter":"","confidence":0.0}.',
    'Ngày trả về dạng yyyy-mm-dd nếu chắc chắn, nếu không chắc thì để đúng chuỗi đọc được.'
  ].join('\n');

  let response;
  try {
    response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{
          role: 'user',
          parts: [
            { text: prompt },
            ...inlineDocuments.flatMap(item => ([
              { text: item.type === 'registration' ? 'Ảnh giấy đăng ký xe:' : 'Ảnh giấy đăng kiểm xe:' },
              { inlineData: { mimeType: item.inlineData.mimeType, data: item.inlineData.data } }
            ]))
          ]
        }],
        generationConfig: { responseMimeType: 'application/json' }
      })
    });
  } catch {
    throw new Error('Không thể kết nối AI để đọc ảnh giấy tờ xe.');
  }

  const data = await response.json().catch(() => null);
  if (!response.ok) {
    const apiMessage = data?.error?.message || '';
    const apiStatus = data?.error?.status || '';
    if (isGeminiBillingOrQuotaError(`${response.status} ${apiStatus} ${apiMessage}`)) {
      throw createGeminiBillingError(apiMessage);
    }
    throw new Error(apiMessage || 'AI chưa đọc được ảnh giấy tờ xe. Bạn hãy thử ảnh rõ hơn.');
  }

  const rawText = (data?.candidates?.[0]?.content?.parts || [])
    .map(part => part.text || '')
    .join('\n')
    .trim();
  return extractJsonPayload(rawText);
};

const requestNotebookOrderDraftsFromGemini = async (file) => {
  if (!GEMINI_API_KEY) {
      throw new Error('permission_denied');
  }

  const inlineData = await readFileAsGeminiInlineData(file);
  const customerOptions = [];
  const productOptions = [];
  const url = buildGeminiGenerateUrl();
  const prompt = [
      '',
      '',
      '',
      '',
      '',
      '',
      '',
      '',
      '',
      'Danh sách hàng hóa:'
  ].join('\n');

  const warehouseVoicePrompt = [
    'Bạn là AI đọc phiếu xuất kho bằng tiếng Việt.',
    'Nhiệm vụ: nghe một câu ngắn rồi trích đúng tên khách hàng, loại hàng, số lượng con và số kg.',
    'Nếu câu có nhiều số kg như "50kg và 30kg", hãy trả về danh sách từng mã kg và tổng kg.',
    'Chỉ trả về JSON hợp lệ, không markdown, không giải thích.',
    'Schema: {"transcript":"","customer_name":"","product_name":"","piece_count":0,"weight_values_kg":[],"weight_kg":0,"note":""}.',
    customerOptions.length ? `Danh sách khách hàng hợp lệ: ${customerOptions.join(' | ')}` : '',
    productOptions.length ? `Danh sách loại hàng hợp lệ: ${productOptions.join(' | ')}` : '',
    customerOptions.length || productOptions.length ? 'Nếu nghe gần giống một mục trong danh sách, hãy trả về đúng tên có sẵn trong danh sách đó.' : ''
  ].filter(Boolean).join('\n');

  let response;
  try {
    response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{
          role: 'user',
          parts: [
            { text: warehouseVoicePrompt },
            { inlineData: { mimeType: inlineData.mimeType, data: inlineData.data } }
          ]
        }],
        generationConfig: {
          responseMimeType: 'application/json'
        }
      })
    });
  } catch (error) {
      throw new Error('permission_denied');
  }

  const data = await response.json().catch(() => null);
  if (!response.ok) {
    const apiMessage = data?.error?.message || '';
    const apiStatus = data?.error?.status || '';
    if (isGeminiBillingOrQuotaError(`${response.status} ${apiStatus} ${apiMessage}`)) {
      throw createGeminiBillingError(apiMessage);
    }
    throw new Error(apiMessage || 'Gemini chưa đọc được ảnh sổ sách này. Bạn hãy thử ảnh rõ hơn.');
  }

  const rawText = (data?.candidates?.[0]?.content?.parts || [])
    .map((part) => part?.text || '')
    .join('')
    .trim();
  const parsed = extractJsonPayload(rawText);
  const orders = Array.isArray(parsed) ? parsed : parsed?.orders;

  if (!Array.isArray(orders) || orders.length === 0) {
      throw new Error('permission_denied');
  }

  return orders;
};

