const toDateInputString = (date) => {
  const normalized = new Date(date.getTime() - (date.getTimezoneOffset() * 60000));
  return normalized.toISOString().split('T')[0];
};

const shiftDateString = (dateStr, days = 0) => {
  const date = parseDateInputValue(dateStr);
  date.setDate(date.getDate() + days);
  return toDateInputString(date);
};

const parseDateInputValue = (dateStr) => {
  const parsed = new Date(`${dateStr || getTodayString()}T12:00:00`);
  return Number.isNaN(parsed.getTime()) ? new Date(`${getTodayString()}T12:00:00`) : parsed;
};

const addMonthsClamped = (date, monthsToAdd = 0) => {
  const baseDate = new Date(date);
  const targetDay = baseDate.getDate();
  baseDate.setDate(1);
  baseDate.setMonth(baseDate.getMonth() + monthsToAdd);
  const lastDayOfMonth = new Date(baseDate.getFullYear(), baseDate.getMonth() + 1, 0).getDate();
  baseDate.setDate(Math.min(targetDay, lastDayOfMonth));
  return baseDate;
};

const resolveProbationEndDate = (startDate, probationDuration = 0, probationUnit = 'days') => {
  const durationValue = parseInt(probationDuration, 10);
  if (!startDate || Number.isNaN(durationValue) || durationValue <= 0) return null;

  const probationStart = parseDateInputValue(startDate);
  let probationExclusiveEnd = new Date(probationStart);

  if (probationUnit === 'days') {
    probationExclusiveEnd.setDate(probationExclusiveEnd.getDate() + durationValue);
  } else if (probationUnit === 'weeks') {
    probationExclusiveEnd.setDate(probationExclusiveEnd.getDate() + (durationValue * 7));
  } else if (probationUnit === 'months') {
    probationExclusiveEnd = addMonthsClamped(probationStart, durationValue);
  }

  const probationEndDate = new Date(probationExclusiveEnd);
  probationEndDate.setDate(probationEndDate.getDate() - 1);
  probationEndDate.setHours(23, 59, 59, 999);
  return probationEndDate;
};

const getDateRangeForPeriod = (anchorDate, period = 'day') => {
  const anchor = parseDateInputValue(anchorDate);
  let start = new Date(anchor);
  let end = new Date(anchor);

  if (period === 'week') {
    const weekday = (anchor.getDay() + 6) % 7;
    start.setDate(anchor.getDate() - weekday);
    end = new Date(start);
    end.setDate(start.getDate() + 6);
  } else if (period === 'month') {
    start = new Date(anchor.getFullYear(), anchor.getMonth(), 1, 12, 0, 0);
    end = new Date(anchor.getFullYear(), anchor.getMonth() + 1, 0, 12, 0, 0);
  } else if (period === 'year') {
    start = new Date(anchor.getFullYear(), 0, 1, 12, 0, 0);
    end = new Date(anchor.getFullYear(), 11, 31, 12, 0, 0);
  }

  return {
    anchorDate: toDateInputString(anchor),
    startDate: toDateInputString(start),
    endDate: toDateInputString(end)
  };
};

const buildPeriodLabel = (period, range) => {
  const startLabel = parseDateInputValue(range.startDate).toLocaleDateString('vi-VN');
  const endLabel = parseDateInputValue(range.endDate).toLocaleDateString('vi-VN');
  const anchor = parseDateInputValue(range.anchorDate);

  if (period === 'week') return `Tuan ${startLabel} - ${endLabel}`;
  if (period === 'month') return `Thang ${String(anchor.getMonth() + 1).padStart(2, '0')}/${anchor.getFullYear()}`;
  if (period === 'year') return `Nam ${anchor.getFullYear()}`;
  return startLabel;
};

const normalizeTimeInputValue = (timeStr = '') => {
  const raw = `${timeStr || ''}`.trim();
  const match = raw.match(/^(\d{1,2}):(\d{1,2})$/);
  if (!match) return '';
  const hours = parseInt(match[1], 10);
  const minutes = parseInt(match[2], 10);
  if (!Number.isFinite(hours) || !Number.isFinite(minutes) || hours < 0 || hours > 23 || minutes < 0 || minutes > 59) return '';
  return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;
};

const timeStringToMinutes = (timeStr = '08:00') => {
  const safeTime = normalizeTimeInputValue(timeStr) || '08:00';
  const [hours, minutes] = safeTime.split(':').map(Number);
  return (hours * 60) + minutes;
};

const isOvernightShiftRange = (shiftStart = '08:00', shiftEnd = '17:00') => (
  timeStringToMinutes(shiftEnd) <= timeStringToMinutes(shiftStart)
);

const formatShiftRangeLabel = (shiftPolicy = {}) => {
  const shiftStart = normalizeTimeInputValue(shiftPolicy.shiftStart) || '08:00';
  const shiftEnd = normalizeTimeInputValue(shiftPolicy.shiftEnd) || '17:00';
  return `${shiftStart} - ${shiftEnd}${isOvernightShiftRange(shiftStart, shiftEnd) ? ' (+1 ngày)' : ''}`;
};

const getPositionShiftDefaults = (position = '') => ({
  ...DEFAULT_SHIFT_POLICY,
  ...(POSITION_SHIFT_DEFAULTS[normalizeEmployeePosition(position)] || {})
});

const resolveEmployeeShiftPolicy = (employee = {}) => {
  const defaults = getPositionShiftDefaults(employee?.position);
  return {
    shiftName: employee?.shiftName || defaults.shiftName,
    shiftStart: normalizeTimeInputValue(employee?.shiftStart) || defaults.shiftStart,
    shiftEnd: normalizeTimeInputValue(employee?.shiftEnd) || defaults.shiftEnd,
    graceMinutes: parseMinutesInput(employee?.graceMinutes, defaults.graceMinutes),
    missingAlertMinutes: parseMinutesInput(employee?.missingAlertMinutes, defaults.missingAlertMinutes)
  };
};

const buildShiftDateTime = (dateStr, timeStr) => new Date(`${dateStr}T${normalizeTimeInputValue(timeStr) || '00:00'}:00`);

const buildShiftRangeDateTimes = (dateStr, shiftStart = '08:00', shiftEnd = '17:00') => {
  const start = buildShiftDateTime(dateStr, shiftStart);
  const end = buildShiftDateTime(dateStr, shiftEnd);
  if (!Number.isNaN(start.getTime()) && !Number.isNaN(end.getTime()) && isOvernightShiftRange(shiftStart, shiftEnd)) {
    // Ca qua dem duoc tinh vao ngay ket thuc ca: 22:00 ngay 20 -> 11:00 ngay 21 la cong ngay 21.
    start.setDate(start.getDate() - 1);
  }
  return { start, end };
};

const shouldMoveAttendanceTimeToPreviousShiftDate = (dateStr, safeTime, shiftPolicy = {}) => {
  if (!dateStr || !safeTime || !isOvernightShiftRange(shiftPolicy.shiftStart, shiftPolicy.shiftEnd)) return false;
  return timeStringToMinutes(safeTime) >= timeStringToMinutes(shiftPolicy.shiftStart);
};

const buildAttendanceDateTimeForShift = (dateStr, timeValue, employee = {}, field = 'checkIn') => {
  const safeTime = normalizeTimeInputValue(timeValue);
  if (!dateStr || !safeTime) return null;

  const dateTime = buildShiftDateTime(dateStr, safeTime);
  if (Number.isNaN(dateTime.getTime())) return null;

  const shiftPolicy = resolveEmployeeShiftPolicy(employee);
  if (shouldMoveAttendanceTimeToPreviousShiftDate(dateStr, safeTime, shiftPolicy, field)) {
    dateTime.setDate(dateTime.getDate() - 1);
  }

  return dateTime;
};

const getAttendanceLocalDateKey = (value) => {
  if (!(value instanceof Date) || Number.isNaN(value.getTime())) return '';
  const year = value.getFullYear();
  const month = `${value.getMonth() + 1}`.padStart(2, '0');
  const day = `${value.getDate()}`.padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const getAttendanceDateKeyOffset = (dateStr, days = 0) => {
  const [year, month, day] = `${dateStr || ''}`.split('-').map(Number);
  if (![year, month, day].every(Number.isFinite)) return `${dateStr || ''}`;
  const date = new Date(year, month - 1, day, 12, 0, 0, 0);
  date.setDate(date.getDate() + days);
  return getAttendanceLocalDateKey(date);
};

const normalizeAttendanceTimestampForWorkDate = (value, workDate, employee = {}, field = 'checkIn') => {
  const parsed = parseAttendanceTimestamp(value);
  if (!parsed || !workDate) return parsed;

  const shiftPolicy = resolveEmployeeShiftPolicy(employee);
  if (!isOvernightShiftRange(shiftPolicy.shiftStart, shiftPolicy.shiftEnd)) return parsed;

  const timeMinutes = parsed.getHours() * 60 + parsed.getMinutes();
  const shiftStartMinutes = timeStringToMinutes(shiftPolicy.shiftStart);
  const shiftEndMinutes = timeStringToMinutes(shiftPolicy.shiftEnd);
  const actualDateKey = getAttendanceLocalDateKey(parsed);
  const previousDateKey = getAttendanceDateKeyOffset(workDate, -1);
  const nextDateKey = getAttendanceDateKeyOffset(workDate, 1);

  // Older overnight records may contain the timestamp on the calendar day
  // the shift starts, although their attendance date is the shift end day.
  // Normalize only at read time so existing Firestore data remains untouched.
  if (field === 'checkIn' && actualDateKey === workDate && timeMinutes >= shiftStartMinutes) {
    const normalized = new Date(parsed.getTime());
    normalized.setDate(normalized.getDate() - 1);
    return normalized;
  }

  if (field === 'checkOut' && actualDateKey === nextDateKey && timeMinutes <= shiftEndMinutes) {
    const normalized = new Date(parsed.getTime());
    normalized.setDate(normalized.getDate() - 1);
    return normalized;
  }

  // Keep this explicit for readability and to document the intended range:
  // a work date of 23/07 owns 23:00 on 22/07 through 11:00 on 23/07.
  if (field === 'checkIn' && actualDateKey === previousDateKey && timeMinutes >= shiftStartMinutes) return parsed;
  return parsed;
};

const normalizeAttendanceRecordForWorkDate = (record, employee = {}, workDate = '') => {
  if (!record || !workDate) return record;
  return {
    ...record,
    checkIn: record.checkIn
      ? normalizeAttendanceTimestampForWorkDate(record.checkIn, workDate, employee, 'checkIn')
      : record.checkIn,
    checkOut: record.checkOut
      ? normalizeAttendanceTimestampForWorkDate(record.checkOut, workDate, employee, 'checkOut')
      : record.checkOut
  };
};

const formatAttendanceMomentForWorkDate = (value, workDate, employee = {}, field = 'checkIn') => (
  formatAttendanceMoment(normalizeAttendanceTimestampForWorkDate(value, workDate, employee, field))
);

const ATTENDANCE_ANOMALY_VISIBLE_AFTER_SHIFT_MS = 12 * 60 * 60 * 1000;
const ATTENDANCE_OVERNIGHT_EARLY_CHECKIN_MS = 4 * 60 * 60 * 1000;

const resolveAttendanceActionDateForShift = (employee = {}, attendance = {}, dateStr = getTodayString(), action = 'checkIn', now = new Date()) => {
  if (!employee?.id || !dateStr) return dateStr;
  const shiftPolicy = resolveEmployeeShiftPolicy(employee);
  if (!isOvernightShiftRange(shiftPolicy.shiftStart, shiftPolicy.shiftEnd)) return dateStr;

  const nowTime = now.getTime();
  const buildCandidate = (candidateDate) => {
    const record = attendance?.[`${candidateDate}_${employee.id}`];
    const { start, end } = buildShiftRangeDateTimes(candidateDate, shiftPolicy.shiftStart, shiftPolicy.shiftEnd);
    if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null;
    const windowStart = start.getTime() - ATTENDANCE_OVERNIGHT_EARLY_CHECKIN_MS;
    const windowEnd = end.getTime() + ATTENDANCE_ANOMALY_VISIBLE_AFTER_SHIFT_MS;
    return { date: candidateDate, record, start, end, isInWindow: nowTime >= windowStart && nowTime <= windowEnd };
  };

  const currentCandidate = buildCandidate(dateStr);
  const nextCandidate = buildCandidate(shiftDateString(dateStr, 1));
  const previousCandidate = buildCandidate(shiftDateString(dateStr, -1));

  if (action === 'checkOut') {
    const openRecord = [currentCandidate, previousCandidate, nextCandidate]
      .find(candidate => candidate?.isInWindow && candidate.record?.checkIn && !candidate.record?.checkOut);
    if (openRecord) return openRecord.date;
  }

  if (action === 'checkIn') {
    const nextShiftIsStarting = nextCandidate?.isInWindow && nowTime >= nextCandidate.start.getTime() - ATTENDANCE_OVERNIGHT_EARLY_CHECKIN_MS;
    if (nextShiftIsStarting && !nextCandidate.record?.checkIn) return nextCandidate.date;

    const currentShiftNeedsCheckIn = currentCandidate?.isInWindow && !currentCandidate.record?.checkIn;
    if (currentShiftNeedsCheckIn) return currentCandidate.date;
  }

  return dateStr;
};

const calculateCheckInStatus = (employee, checkInDate, referenceDateStr = getTodayString()) => {
  const shiftPolicy = resolveEmployeeShiftPolicy(employee);
  const { start: shiftStart } = buildShiftRangeDateTimes(referenceDateStr, shiftPolicy.shiftStart, shiftPolicy.shiftEnd);
  const graceMinutes = shiftPolicy.graceMinutes || 0;
  return checkInDate.getTime() > shiftStart.getTime() + (graceMinutes * 60000) ? 'late' : 'present';
};

const getAttendanceAnomaly = (employee, record, dateStr, now = new Date()) => {
  if (!employee || !dateStr) return null;
  if (isSalesCollaboratorPosition(employee.position)) return null;
  if (record?.status === 'leave') return null;

  const shiftPolicy = resolveEmployeeShiftPolicy(employee);
  const { start: shiftStart, end: shiftEnd } = buildShiftRangeDateTimes(dateStr, shiftPolicy.shiftStart, shiftPolicy.shiftEnd);
  if (Number.isNaN(shiftStart.getTime()) || Number.isNaN(shiftEnd.getTime())) return null;

  const nowTime = now.getTime();
  const visibleUntil = shiftEnd.getTime() + ATTENDANCE_ANOMALY_VISIBLE_AFTER_SHIFT_MS;
  if (nowTime < shiftStart.getTime() || nowTime > visibleUntil) return null;

  const alertDelay = shiftPolicy.missingAlertMinutes || 0;

  if (!record?.checkIn) {
    if (nowTime > shiftEnd.getTime()) return null;
    if (nowTime >= shiftStart.getTime() + ((shiftPolicy.graceMinutes + alertDelay) * 60000)) {
      return {
        type: 'missing_check_in',
        title: 'Chưa chấm vào ca',
        message: `${employee.name} chưa chấm vào ca ${shiftPolicy.shiftName} (${shiftPolicy.shiftStart}) dù đã quá giờ quy định.`,
        severity: 'warning'
      };
    }
    return null;
  }

  if (!record?.checkOut && nowTime >= shiftEnd.getTime() + (alertDelay * 60000)) {
    return {
      type: 'missing_check_out',
      title: 'Chưa chấm ra ca',
      message: `${employee.name} chưa chấm ra ca ${shiftPolicy.shiftName} (${shiftPolicy.shiftEnd}). App chỉ tự tính tăng ca khi có giờ chấm ra rõ ràng sau ca.`,
      severity: 'warning'
    };
  }

  return null;
};

const resolveAttendanceAnomalyForDate = (employee = {}, attendance = {}, dateStr = getTodayString(), now = new Date()) => {
  if (!employee?.id || !dateStr) return null;

  const currentRecord = attendance?.[`${dateStr}_${employee.id}`];
  const currentAnomaly = getAttendanceAnomaly(employee, currentRecord, dateStr, now);
  if (currentAnomaly) return { ...currentAnomaly, record: currentRecord, date: dateStr };

  const shiftPolicy = resolveEmployeeShiftPolicy(employee);
  if (!isOvernightShiftRange(shiftPolicy.shiftStart, shiftPolicy.shiftEnd)) return null;

  const nextDate = shiftDateString(dateStr, 1);
  const nextRecord = attendance?.[`${nextDate}_${employee.id}`];
  const nextAnomaly = getAttendanceAnomaly(employee, nextRecord, nextDate, now);
  return nextAnomaly ? { ...nextAnomaly, record: nextRecord, date: nextDate } : null;
};

const normalizeAttendanceMethod = (method, fallbackLabel = 'Thủ công') => {
  if (!method) return { label: fallbackLabel, meta: null };
  if (typeof method === 'string') return { label: method, meta: null };

  const { label, ...meta } = method;
  return {
    label: label || fallbackLabel,
    meta: Object.keys(meta).length > 0 ? meta : null
  };
};

const getNetworkConnectionInfo = () => {
  if (typeof navigator === 'undefined') return { online: true, effectiveType: null };
  const connection = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
  return {
    online: navigator.onLine,
    effectiveType: connection?.effectiveType || null
  };
};

const MAX_ATTENDANCE_GPS_ACCURACY_METERS = 100;
const DEFAULT_ATTENDANCE_LOCATION_RADIUS_METERS = 150;

const getGpsCoordinatesFromLocation = (location = null) => {
  if (!location) return null;
  const lat = location.lat ?? location.latitude;
  const lng = location.lng ?? location.longitude;
  if (!Number.isFinite(Number(lat)) || !Number.isFinite(Number(lng))) return null;
  return {
    lat: Number(lat),
    lng: Number(lng)
  };
};

const calculateGpsDistanceMeters = (from = {}, to = {}) => {
  const fromLat = Number(from.lat ?? from.latitude);
  const fromLng = Number(from.lng ?? from.longitude);
  const toLat = Number(to.lat ?? to.latitude);
  const toLng = Number(to.lng ?? to.longitude);
  if (![fromLat, fromLng, toLat, toLng].every(Number.isFinite)) return null;

  const earthRadiusMeters = 6371000;
  const toRadians = (value) => (value * Math.PI) / 180;
  const deltaLat = toRadians(toLat - fromLat);
  const deltaLng = toRadians(toLng - fromLng);
  const a = Math.sin(deltaLat / 2) ** 2
    + Math.cos(toRadians(fromLat)) * Math.cos(toRadians(toLat)) * Math.sin(deltaLng / 2) ** 2;
  return earthRadiusMeters * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
};

const normalizeAttendanceFixedLocation = (location = null) => {
  const coords = getGpsCoordinatesFromLocation(location);
  if (!coords) return null;
  return {
    type: 'gps',
    lat: Number(coords.lat.toFixed(6)),
    lng: Number(coords.lng.toFixed(6)),
    url: buildCustomerMapsUrlFromLocation(coords)
  };
};

const getEmployeeAttendanceLocationSettings = (employee = {}, company = {}) => {
  const location = normalizeAttendanceFixedLocation(
    employee.attendanceLocation
    || employee.fixedAttendanceLocation
    || employee.attendanceGpsLocation
    || null
  );
  const radiusMeters = Math.max(
    1,
    Math.round(Number(
      employee.attendanceLocationRadiusMeters
      || employee.attendanceGpsRadiusMeters
      || company.attendanceLocationRadiusMeters
      || DEFAULT_ATTENDANCE_LOCATION_RADIUS_METERS
    ) || DEFAULT_ATTENDANCE_LOCATION_RADIUS_METERS)
  );
  return {
    enabled: Boolean(employee.attendanceLocationEnabled || employee.fixedAttendanceLocationEnabled || employee.attendanceGpsRequired),
    label: `${employee.attendanceLocationLabel || employee.fixedAttendanceLocationLabel || employee.attendanceGpsLabel || ''}`.trim(),
    location,
    radiusMeters,
    input: employee.attendanceLocationInput || ''
  };
};

const applyAttendanceFixedLocationGuard = (methodInfo = {}, employee = {}, company = {}) => {
  const settings = getEmployeeAttendanceLocationSettings(employee, company);
  if (!settings.enabled) return methodInfo;

  if (methodInfo?.meta?.proxyAttendance || methodInfo?.meta?.type === 'proxy' || methodInfo?.label === 'Kế toán chấm hộ') {
    return {
      ...methodInfo,
      meta: {
        ...(methodInfo.meta || {}),
        fixedLocationCheckBypassed: true,
        fixedLocationBypassReason: 'accounting_proxy'
      }
    };
  }

  if (methodInfo?.meta?.type !== 'gps') {
    throw new Error('Tài khoản này bắt buộc chấm công bằng GPS tại vị trí cố định đã cài.');
  }

  if (!settings.location) {
    throw new Error('Tài khoản này chưa được cài tọa độ chấm công cố định. Chủ doanh nghiệp cần cài vị trí trong hồ sơ nhân sự.');
  }

  const currentLocation = {
    lat: methodInfo.meta.latitude,
    lng: methodInfo.meta.longitude
  };
  const distanceMeters = calculateGpsDistanceMeters(currentLocation, settings.location);
  if (!Number.isFinite(distanceMeters)) {
    throw new Error('Không kiểm tra được khoảng cách tới vị trí chấm công cố định. Hãy bật GPS chính xác rồi thử lại.');
  }

  const roundedDistance = Math.round(distanceMeters);
  if (roundedDistance > settings.radiusMeters) {
    const locationLabel = settings.label || 'vị trí chấm công cố định';
    throw new Error(`Bạn đang cách ${locationLabel} khoảng ${roundedDistance}m, vượt quá bán kính cho phép ${settings.radiusMeters}m. Hãy đến gần vị trí cố định rồi chấm công.`);
  }

  return {
    ...methodInfo,
    meta: {
      ...(methodInfo.meta || {}),
      fixedLocationLabel: settings.label || '',
      fixedLocationLatitude: settings.location.lat,
      fixedLocationLongitude: settings.location.lng,
      fixedLocationRadiusMeters: settings.radiusMeters,
      distanceToFixedLocationMeters: roundedDistance,
      fixedLocationCheckPassed: true
    }
  };
};
const normalizeWifiName = (value = '') => {
  const trimmed = `${value || ''}`.trim();
  return trimmed.replace(/^"+|"+$/g, '').trim();
};

const normalizeWifiCompareKey = (value = '') => normalizeLookupText(normalizeWifiName(value));
const getAttendanceWifiSettings = (company = {}) => {
  const wifiProfile = company?.attendanceWifi || {};
  const ssid = normalizeWifiName(
    company?.attendanceWifiSsid
    || company?.defaultAttendanceWifiSsid
    || wifiProfile.ssid
    || wifiProfile.networkLabel
    || ''
  );
  const bssid = normalizeWifiName(
    company?.attendanceWifiBssid
    || company?.defaultAttendanceWifiBssid
    || wifiProfile.bssid
    || ''
  );
  return {
    enabled: Boolean(company?.attendanceWifiEnabled ?? ssid),
    ssid,
    bssid,
    updatedAt: company?.attendanceWifiUpdatedAt || wifiProfile.updatedAt || ''
  };
};
const getAttendanceWifiDisplay = (settings = {}) => {
  if (!settings?.ssid) return 'Chưa cài WiFi mặc định';
  return settings.bssid ? `${settings.ssid} • ${settings.bssid}` : settings.ssid;
};
const getWifiPayloadName = (payload = {}) => normalizeWifiName(payload?.ssid || payload?.networkLabel || payload?.label?.replace(/^WiFi:\s*/i, '') || '');
const doesWifiMatchAttendanceDefault = (wifiPayload = {}, company = {}) => {
  const settings = getAttendanceWifiSettings(company);
  const expectedSsid = normalizeWifiCompareKey(settings.ssid);
  const actualSsid = normalizeWifiCompareKey(getWifiPayloadName(wifiPayload));
  if (!expectedSsid || !actualSsid || expectedSsid !== actualSsid) return false;

  const expectedBssid = normalizeWifiCompareKey(settings.bssid);
  const actualBssid = normalizeWifiCompareKey(wifiPayload?.bssid || '');
  if (expectedBssid && actualBssid && expectedBssid !== actualBssid) return false;
  return true;
};
const assertAttendanceWifiMatches = (wifiPayload = {}, company = {}) => {
  const settings = getAttendanceWifiSettings(company);
  if (!settings.ssid) {
    throw new Error('Chưa cài WiFi mặc định để chấm công. Kế toán hoặc chủ doanh nghiệp hãy đặt WiFi hiện tại làm mặc định trước.');
  }
  if (!doesWifiMatchAttendanceDefault(wifiPayload, company)) {
    const currentWifi = getWifiPayloadName(wifiPayload) || 'không xác định';
    throw new Error(`WiFi hiện tại (${currentWifi}) không trùng WiFi chấm công mặc định (${settings.ssid}).`);
  }
};
const validatePreciseAttendanceLocation = (position = {}) => {
  const accuracy = Math.round(position?.coords?.accuracy || 0);
  if (accuracy > MAX_ATTENDANCE_GPS_ACCURACY_METERS) {
    throw new Error(`Vị trí GPS chưa đủ chính xác (${accuracy}m). Hãy bật Vị trí chính xác trong quyền vị trí của app, đứng nơi thoáng hơn rồi thử lại.`);
  }
};

const getRuntimePlatform = () => {
  try {
    return Capacitor.getPlatform();
  } catch (error) {
    return 'web';
  }
};

const isNativeRuntime = () => getRuntimePlatform() !== 'web';
const isAndroidNativeRuntime = () => getRuntimePlatform() === 'android';

const buildSystemNotificationId = (seed = '') => {
  const rawSeed = `${seed || Date.now()}`;
  let hash = 0;
  for (let index = 0; index < rawSeed.length; index += 1) {
    hash = ((hash << 5) - hash) + rawSeed.charCodeAt(index);
    hash |= 0;
  }
  const positiveHash = Math.abs(hash);
  return positiveHash > 0 ? positiveHash : Math.max(1, Date.now() % 2147483647);
};

const requestSystemNotificationPermission = async ({ forcePrompt = false } = {}) => {
  if (typeof window === 'undefined') return 'unsupported';
  try {
    if (isNativeRuntime()) {
      const currentPermission = await LocalNotifications.checkPermissions().catch(() => ({ display: 'prompt' }));
      if (currentPermission?.display === 'granted') return 'granted';
      if (!forcePrompt || currentPermission?.display === 'denied') return currentPermission?.display || 'denied';
      const requestedPermission = await LocalNotifications.requestPermissions().catch(() => currentPermission);
      return requestedPermission?.display || currentPermission?.display || 'prompt';
    }

    if (!('Notification' in window)) return 'unsupported';
    if (window.Notification.permission === 'granted') return 'granted';
    if (window.Notification.permission === 'denied') return 'denied';
    if (!forcePrompt) return window.Notification.permission || 'default';
    return await window.Notification.requestPermission();
  } catch (error) {
    console.warn('Failed to request system notification permission.', error);
    return 'error';
  }
};

const showSystemNotificationForItem = async (item = {}) => {
  const rawTitle = `${item.title || 'HD Manager'}`.trim() || 'HD Manager';
  const rawBody = `${item.message || 'Bạn có thông báo mới.'}`.replace(/\s+/g, ' ').trim();
  const title = rawTitle.slice(0, 80);
  const body = rawBody.slice(0, 190);
  try {
    const permission = await requestSystemNotificationPermission({ forcePrompt: false });
    if (permission !== 'granted') return false;

    if (isNativeRuntime()) {
      await LocalNotifications.schedule({
        notifications: [{
          id: buildSystemNotificationId(`${item.id || title}-${item.createdAt || Date.now()}`),
          title,
          body,
          schedule: { at: new Date(Date.now() + 250) },
          extra: {
            notificationId: item.id || '',
            tab: item.tab || '',
            customerId: item.customerId || '',
            source: 'hd-manager'
          }
        }]
      });
      return true;
    }

    if ('Notification' in window && window.Notification.permission === 'granted') {
      const notification = new window.Notification(title, {
        body,
        tag: `${item.id || item.createdAt || Date.now()}`,
        silent: false
      });
      notification.onclick = () => {
        window.focus?.();
      };
      return true;
    }
  } catch (error) {
    console.warn('Failed to show system notification.', error);
  }
  return false;
};

const mapMicrophoneAccessErrorMessage = (error, source = 'web') => {
  const rawMessage = `${error?.message || ''}`.toLowerCase();
  const isNative = source === 'native';

  if (rawMessage.includes('notallowed') || rawMessage.includes('permission') || rawMessage.includes('denied')) {
    return isNative
      ? '\u1ee8ng d\u1ee5ng ch\u01b0a \u0111\u01b0\u1ee3c c\u1ea5p quy\u1ec1n micro. H\u00e3y v\u00e0o C\u00e0i \u0111\u1eb7t > \u1ee8ng d\u1ee5ng > HD Manager > Quy\u1ec1n > Micro v\u00e0 b\u1eadt l\u1ea1i.'
      : 'B\u1ea1n ch\u01b0a c\u1ea5p quy\u1ec1n micro cho tr\u00ecnh duy\u1ec7t. H\u00e3y cho ph\u00e9p Microphone r\u1ed3i th\u1eed l\u1ea1i.';
  }

  if (rawMessage.includes('notfound') || rawMessage.includes('devicesnotfound') || rawMessage.includes('found no audio input')) {
    return 'Thi\u1ebft b\u1ecb ch\u01b0a t\u00ecm th\u1ea5y micro \u0111\u1ec3 ghi \u00e2m.';
  }

  if (rawMessage.includes('notreadable') || rawMessage.includes('trackstart') || rawMessage.includes('could not start audio source')) {
    return 'Micro \u0111ang b\u1ecb \u1ee9ng d\u1ee5ng kh\u00e1c chi\u1ebfm d\u1ee5ng ho\u1eb7c thi\u1ebft b\u1ecb ch\u01b0a s\u1eb5n s\u00e0ng.';
  }

  return isNative
    ? 'Kh\u00f4ng th\u1ec3 b\u1eadt micro tr\u00ean thi\u1ebft b\u1ecb n\u00e0y. H\u00e3y th\u1eed l\u1ea1i ho\u1eb7c ki\u1ec3m tra quy\u1ec1n micro trong c\u00e0i \u0111\u1eb7t \u1ee9ng d\u1ee5ng.'
    : 'Kh\u00f4ng th\u1ec3 b\u1eadt micro cho tr\u00ecnh duy\u1ec7t. H\u00e3y th\u1eed l\u1ea1i ho\u1eb7c ki\u1ec3m tra quy\u1ec1n micro.';
};

const ensureMicrophoneAccess = async () => {
  if (!isNativeRuntime()) {
    if (typeof navigator === 'undefined' || !navigator.mediaDevices?.getUserMedia) {
      return {
        granted: false,
        source: 'web',
        message: 'Trình duyệt này chưa hỗ trợ xin quyền micro. Bạn hãy thử trên Chrome/Edge hoặc dùng APK Android.'
      };
    }

    try {
      if (navigator.permissions?.query) {
        try {
          const permissionState = await navigator.permissions.query({ name: 'microphone' });
          if (permissionState?.state === 'denied') {
            return {
              granted: false,
              source: 'web',
              state: permissionState,
              message: 'Bạn chưa cấp quyền micro cho trình duyệt. Hãy bấm biểu tượng ổ khóa/cài đặt trang và cho phép Microphone rồi thử lại.'
            };
          }
        } catch (error) {
          // Một số trình duyệt chưa hỗ trợ query quyền microphone, vẫn tiếp tục xin quyền trực tiếp.
        }
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      stream.getTracks().forEach(track => track.stop());
      return { granted: true, source: 'web' };
    } catch (error) {
      return {
        granted: false,
        source: 'web',
        error,
        message: mapMicrophoneAccessErrorMessage(error, 'web')
      };
    }
  }

  if (!MicrophonePermission?.requestMicrophonePermission || !MicrophonePermission?.getMicrophonePermissionState) {
    return { granted: true, source: 'fallback' };
  }

  try {
    const currentState = await MicrophonePermission.getMicrophonePermissionState();
    const currentValue = `${currentState?.microphone || ''}`.toLowerCase();
    if (currentState?.granted || currentValue === 'granted') {
      return { granted: true, source: 'native', state: currentState };
    }

    const requestedState = await MicrophonePermission.requestMicrophonePermission();
    const requestedValue = `${requestedState?.microphone || ''}`.toLowerCase();
    if (requestedState?.granted || requestedValue === 'granted') {
      return { granted: true, source: 'native', state: requestedState };
    }

    return {
      granted: false,
      source: 'native',
      state: requestedState,
      message: '\u1ee8ng d\u1ee5ng ch\u01b0a \u0111\u01b0\u1ee3c c\u1ea5p quy\u1ec1n micro. H\u00e3y cho ph\u00e9p quy\u1ec1n Microphone r\u1ed3i b\u1ea5m l\u1ea1i.'
    };
  } catch (error) {
    const rawMessage = `${error?.message || ''}`.toLowerCase();
    if (rawMessage.includes('not implemented') || rawMessage.includes('unimplemented')) {
      return { granted: true, source: 'fallback' };
    }

    return {
      granted: false,
      source: 'native',
      error,
      message: 'Kh\u00f4ng xin \u0111\u01b0\u1ee3c quy\u1ec1n micro tr\u00ean thi\u1ebft b\u1ecb n\u00e0y. H\u00e3y ki\u1ec3m tra l\u1ea1i quy\u1ec1n micro trong c\u00e0i \u0111\u1eb7t app.'
    };
  }
};

const mapLocationErrorMessage = (error, source = 'web') => {
  const rawMessage = `${error?.message || ''}`.toLowerCase();
  const code = error?.code;
  const isNative = source === 'native';

  if (code === 1 || rawMessage.includes('permission') || rawMessage.includes('denied')) {
    return isNative
            ? 'Chưa có'
            : 'Chưa có mặt hàng';
  }

  if (
    code === 2 ||
    rawMessage.includes('services are not enabled') ||
    rawMessage.includes('location services are disabled') ||
    (rawMessage.includes('gps') && rawMessage.includes('disabled')) ||
    rawMessage.includes('location unavailable') ||
    rawMessage.includes('unavailable')
  ) {
    return 'web';
  }

  if (code === 3 || rawMessage.includes('timeout')) {
    return 'web';
  }

  if (rawMessage.includes('not supported') || rawMessage.includes('not available')) {
    return isNative
            ? 'Chưa có'
            : 'Chưa có mặt hàng';
  }

  return isNative
            ? 'Chưa có'
            : 'Chưa có mặt hàng';
};

const getBrowserGeolocationPermissionState = async () => {
  if (typeof navigator === 'undefined' || !navigator.permissions?.query) return 'prompt';
  try {
    const status = await navigator.permissions.query({ name: 'geolocation' });
    return status?.state || 'prompt';
  } catch (error) {
    return 'prompt';
  }
};

const ensureNativeLocationPermission = async () => {
  try {
    const status = await Geolocation.checkPermissions();
    if (status?.location === 'granted') return status;

    const requested = await Geolocation.requestPermissions({ permissions: ['location'] });
    if (requested?.location !== 'granted') {
      throw new Error('permission_denied');
    }
    return requested;
  } catch (error) {
    throw new Error(mapLocationErrorMessage(error, 'native'));
  }
};

const mapWifiFailureMessage = (failureCode = '', fallbackMessage = '') => {
  switch (failureCode) {
    case 'wifi_disabled':
    return 'web';
    case 'not_connected_to_wifi':
    return 'web';
    case 'location_permission_denied':
    return 'web';
    case 'nearby_wifi_permission_denied':
    return 'web';
    case 'location_services_off':
    return 'web';
    case 'ssid_unavailable':
    return 'web';
    case 'unsupported':
      return fallbackMessage || 'Thiết bị này chưa hỗ trợ đọc WiFi nội bộ theo cách xác minh tự động.';
    default:
      return fallbackMessage || 'Thiết bị này chưa hỗ trợ đọc WiFi nội bộ theo cách xác minh tự động.';
  }
};

const isWifiAttendanceReady = (lookupState, wifiLabel) => {
  const normalizedLabel = normalizeWifiName(wifiLabel);
  if (!isAndroidNativeRuntime()) return Boolean(normalizedLabel);
  return Boolean(lookupState?.success && normalizedLabel);
};

const requestBrowserLocation = async () => {
  if (typeof navigator === 'undefined' || !navigator.geolocation) {
      throw new Error('permission_denied');
  }

  const permissionState = await getBrowserGeolocationPermissionState();
  if (permissionState === 'denied') {
      throw new Error('permission_denied');
  }

  return new Promise((resolve, reject) => {
    navigator.geolocation.getCurrentPosition(
      (position) => resolve(position),
      (error) => reject(new Error(mapLocationErrorMessage(error, 'web'))),
      { enableHighAccuracy: true, timeout: 20000, maximumAge: 0 }
    );
  });
};

const getCurrentConnectedWifi = async () => {
  if (!isAndroidNativeRuntime()) {
    return {
      supported: false,
      failureCode: 'unsupported',
      message: ''
    };
  }

  try {
    const info = await WifiInfo.getCurrentWifiInfo();
    const ssid = normalizeWifiName(info?.ssid || '');
    const failureCode = info?.failureCode || (ssid ? null : 'ssid_unavailable');
    const mappedMessage = info?.ok
      ? (info?.message || `Đã nhận WiFi hiện tại: ${ssid}`)
      : mapWifiFailureMessage(failureCode, info?.message);

    if (!info?.ok || !ssid) {
      return {
        supported: false,
        failureCode,
        message: mappedMessage,
        permissions: info?.permissions || null,
        checks: info?.checks || null
      };
    }

    return {
      supported: true,
      failureCode: null,
      ssid,
      bssid: info?.bssid || null,
      rssi: info?.rssi ?? null,
      linkSpeed: info?.linkSpeed ?? null,
      frequency: info?.frequency ?? null,
      source: info?.source || 'android-native',
      permissions: info?.permissions || null,
      checks: info?.checks || null,
      message: mappedMessage
    };
  } catch (error) {
    return {
      supported: false,
      failureCode: 'unsupported',
      message: mapWifiFailureMessage('unsupported', error?.message)
    };
  }
};

const requestCurrentLocationLegacy = () => new Promise((resolve, reject) => {
  if (typeof navigator === 'undefined' || !navigator.geolocation) {
    reject(new Error('Thiết bị này chưa hỗ trợ lấy vị trí GPS.'));
    return;
  }

  navigator.geolocation.getCurrentPosition(
    (position) => resolve(position),
    () => reject(new Error('Không lấy được vị trí GPS. Bạn hãy kiểm tra quyền truy cập vị trí.')),
    { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
  );
});

const requestCurrentLocation = async () => {
  if (isNativeRuntime()) {
    await ensureNativeLocationPermission();
    try {
      return await Geolocation.getCurrentPosition({
        enableHighAccuracy: true,
        timeout: 20000,
        maximumAge: 0,
        enableLocationFallback: true
      });
    } catch (error) {
      throw new Error(mapLocationErrorMessage(error, 'native'));
    }
  }

  return requestBrowserLocation();
};

const buildAttendanceMethodPayloadLegacy = async (methodKey = 'gps', wifiLabel = '') => {
  const trimmedWifiLabel = normalizeWifiName(wifiLabel);

  if (methodKey === 'wifi') {
    const networkInfo = getNetworkConnectionInfo();
    return {
      label: trimmedWifiLabel ? `WiFi: ${trimmedWifiLabel}` : 'WiFi nội bộ',
      type: 'wifi',
      networkLabel: trimmedWifiLabel || null,
      ...networkInfo
    };
  }

  const position = await requestCurrentLocation();
  return {
    label: 'GPS vi tri',
    type: 'gps',
    latitude: Number(position.coords.latitude.toFixed(6)),
    longitude: Number(position.coords.longitude.toFixed(6)),
    accuracy: Math.round(position.coords.accuracy || 0),
    ...getNetworkConnectionInfo()
  };
};

const buildAttendanceMethodPayload = async (methodKey = 'gps', wifiLabel = '') => {
  const trimmedWifiLabel = normalizeWifiName(wifiLabel);

  if (methodKey === 'wifi') {
    const networkInfo = getNetworkConnectionInfo();
    if (isAndroidNativeRuntime()) {
      const detectedWifi = await getCurrentConnectedWifi();
      if (!detectedWifi.supported || !detectedWifi.ssid) {
        throw new Error(detectedWifi.message || 'Không xác định được WiFi hiện tại.');
      }

      return {
        label: `WiFi: ${detectedWifi.ssid}`,
        type: 'wifi',
        networkLabel: detectedWifi.ssid,
        ssid: detectedWifi.ssid,
        bssid: detectedWifi.bssid || null,
        rssi: detectedWifi.rssi ?? null,
        linkSpeed: detectedWifi.linkSpeed ?? null,
        frequency: detectedWifi.frequency ?? null,
        source: detectedWifi.source || 'android-native',
        wifiLookupMode: 'auto',
        ...networkInfo
      };
    }

    if (!trimmedWifiLabel) {
      throw new Error('permission_denied');
    }

    return {
      label: `WiFi: ${trimmedWifiLabel}`,
      type: 'wifi',
      networkLabel: trimmedWifiLabel,
      ssid: null,
      bssid: null,
      rssi: null,
      linkSpeed: null,
      frequency: null,
      wifiLookupMode: 'manual',
      ...networkInfo
    };
  }

  const position = await requestCurrentLocation();
  return {
    label: 'GPS vi tri',
    type: 'gps',
    latitude: Number(position.coords.latitude.toFixed(6)),
    longitude: Number(position.coords.longitude.toFixed(6)),
    accuracy: Math.round(position.coords.accuracy || 0),
    ...getNetworkConnectionInfo()
  };
};

const mapPreciseAttendanceLocationErrorMessage = (error, source = 'web') => {
  const rawMessage = `${error?.message || ''}`.toLowerCase();
  const code = error?.code;
  const isNative = source === 'native';

  if (code === 1 || rawMessage.includes('permission') || rawMessage.includes('denied')) {
    return isNative
      ? 'Ứng dụng chưa được cấp quyền vị trí chính xác. Hãy vào Cài đặt > Ứng dụng > HD Manager > Quyền > Vị trí, chọn Cho phép khi dùng ứng dụng và bật Vị trí chính xác.'
      : 'Bạn chưa cấp quyền vị trí cho trình duyệt. Hãy cho phép Location/Vị trí rồi thử lại.';
  }

  if (
    code === 2 ||
    rawMessage.includes('services are not enabled') ||
    rawMessage.includes('location services are disabled') ||
    rawMessage.includes('location unavailable') ||
    rawMessage.includes('unavailable')
  ) {
    return 'Thiết bị chưa bật dịch vụ vị trí/GPS. Hãy bật Vị trí trên điện thoại rồi thử lại.';
  }

  if (code === 3 || rawMessage.includes('timeout')) {
    return 'GPS mất quá lâu để lấy vị trí chính xác. Hãy đứng nơi thoáng hơn rồi thử lại.';
  }

  return isNative
    ? 'Không thể lấy vị trí GPS chính xác. Hãy kiểm tra quyền vị trí và thử lại.'
    : 'Không thể lấy vị trí GPS trên trình duyệt. Hãy kiểm tra quyền vị trí và thử lại.';
};

const validateAttendancePositionAccuracy = (position = {}) => {
  const accuracy = Math.round(position?.coords?.accuracy || 0);
  if (accuracy > MAX_ATTENDANCE_GPS_ACCURACY_METERS) {
    throw new Error(`Vị trí GPS chưa đủ chính xác (${accuracy}m). Hãy bật Vị trí chính xác trong quyền vị trí của app, đứng nơi thoáng hơn rồi thử lại.`);
  }
  return position;
};

const requestPreciseAttendanceLocation = async () => {
  if (isNativeRuntime()) {
    try {
      const status = await Geolocation.checkPermissions();
      if (status?.location !== 'granted') {
        const requested = await Geolocation.requestPermissions({ permissions: ['location'] });
        if (requested?.location !== 'granted') throw new Error('permission_denied');
      }
      const position = await Geolocation.getCurrentPosition({
        enableHighAccuracy: true,
        timeout: 20000,
        maximumAge: 0,
        enableLocationFallback: true
      });
      return validateAttendancePositionAccuracy(position);
    } catch (error) {
      throw new Error(mapPreciseAttendanceLocationErrorMessage(error, 'native'));
    }
  }

  if (typeof navigator === 'undefined' || !navigator.geolocation) {
    throw new Error('Trình duyệt này chưa hỗ trợ lấy vị trí GPS để chấm công.');
  }

  const permissionState = await getBrowserGeolocationPermissionState();
  if (permissionState === 'denied') {
    throw new Error(mapPreciseAttendanceLocationErrorMessage({ code: 1 }, 'web'));
  }

  return new Promise((resolve, reject) => {
    navigator.geolocation.getCurrentPosition(
      (position) => {
        try {
          resolve(validateAttendancePositionAccuracy(position));
        } catch (error) {
          reject(error);
        }
      },
      (error) => reject(new Error(mapPreciseAttendanceLocationErrorMessage(error, 'web'))),
      { enableHighAccuracy: true, timeout: 20000, maximumAge: 0 }
    );
  });
};

const mapAttendanceWifiFailureMessage = (failureCode = '', fallbackMessage = '') => {
  switch (failureCode) {
    case 'wifi_disabled':
      return 'WiFi đang tắt. Hãy bật WiFi và kết nối đúng mạng chấm công.';
    case 'not_connected_to_wifi':
      return 'Thiết bị chưa kết nối WiFi. Hãy kết nối WiFi mặc định rồi chấm vào ca.';
    case 'location_permission_denied':
      return 'Android cần quyền vị trí để đọc tên WiFi. Hãy cấp quyền Vị trí cho app rồi thử lại.';
    case 'nearby_wifi_permission_denied':
      return 'Thiết bị chưa cấp quyền WiFi lân cận. Hãy cấp quyền trong cài đặt app rồi thử lại.';
    case 'location_services_off':
      return 'Dịch vụ vị trí đang tắt nên Android không đọc được WiFi. Hãy bật Vị trí rồi thử lại.';
    case 'ssid_unavailable':
      return 'Chưa đọc được tên WiFi hiện tại. Hãy kiểm tra kết nối WiFi và quyền vị trí.';
    case 'scan_empty':
      return fallbackMessage || 'Chưa dò thấy WiFi nào. Hãy bật WiFi, bật Vị trí chính xác và thử lại.';
    case 'unsupported':
      return fallbackMessage || 'Thiết bị này chưa hỗ trợ đọc WiFi nội bộ theo cách xác minh tự động.';
    default:
      return fallbackMessage || 'Không đọc được WiFi hiện tại. Hãy kiểm tra kết nối WiFi rồi thử lại.';
  }
};

const getCurrentConnectedWifiForAttendance = async () => {
  if (!isAndroidNativeRuntime()) {
    return {
      supported: false,
      failureCode: 'unsupported',
      message: 'Trên web không đọc được WiFi thật. Tính năng xác minh WiFi chính xác chỉ dùng trên APK Android.'
    };
  }

  try {
    const info = await WifiInfo.getCurrentWifiInfo();
    const ssid = normalizeWifiName(info?.ssid || '');
    const failureCode = info?.failureCode || (ssid ? null : 'ssid_unavailable');
    if (!info?.ok || !ssid) {
      return {
        supported: false,
        failureCode,
        message: mapAttendanceWifiFailureMessage(failureCode, info?.message),
        permissions: info?.permissions || null,
        checks: info?.checks || null
      };
    }

    return {
      supported: true,
      failureCode: null,
      ssid,
      bssid: info?.bssid || null,
      rssi: info?.rssi ?? null,
      linkSpeed: info?.linkSpeed ?? null,
      frequency: info?.frequency ?? null,
      source: info?.source || 'android-native',
      permissions: info?.permissions || null,
      checks: info?.checks || null,
      message: info?.message || `Đã nhận WiFi hiện tại: ${ssid}`
    };
  } catch (error) {
    return {
      supported: false,
      failureCode: 'unsupported',
      message: mapAttendanceWifiFailureMessage('unsupported', error?.message)
    };
  }
};

const normalizeWifiNetworkItem = (network = {}) => ({
  ssid: normalizeWifiName(network?.ssid || network?.networkLabel || ''),
  bssid: normalizeWifiName(network?.bssid || ''),
  rssi: network?.rssi ?? network?.level ?? null,
  frequency: network?.frequency ?? null,
  capabilities: network?.capabilities || '',
  connected: Boolean(network?.connected),
  source: network?.source || 'android-native-scan'
});

const scanNearbyWifiNetworksForAttendance = async () => {
  if (!isAndroidNativeRuntime()) {
    return {
      supported: false,
      success: false,
      failureCode: 'unsupported',
      networks: [],
      message: 'Trên web không thể quét danh sách WiFi thật. Tính năng này chỉ dùng trên APK Android.'
    };
  }

  try {
    const result = await WifiInfo.scanWifiNetworks();
    const networks = Array.isArray(result?.networks)
      ? result.networks.map(normalizeWifiNetworkItem).filter(network => network.ssid)
      : [];
    const failureCode = result?.failureCode || (networks.length ? null : 'scan_empty');
    return {
      supported: result?.supported !== false,
      success: Boolean(result?.ok && networks.length),
      failureCode,
      networks,
      connectedSsid: normalizeWifiName(result?.connectedSsid || ''),
      connectedBssid: normalizeWifiName(result?.connectedBssid || ''),
      permissions: result?.permissions || null,
      checks: result?.checks || null,
      message: result?.ok
        ? (result?.message || `Đã dò thấy ${networks.length} WiFi gần đây.`)
        : mapAttendanceWifiFailureMessage(failureCode, result?.message)
    };
  } catch (error) {
    return {
      supported: false,
      success: false,
      failureCode: 'unsupported',
      networks: [],
      message: mapAttendanceWifiFailureMessage('unsupported', error?.message)
    };
  }
};

const assertAttendanceWifiMatchesDefault = (wifiPayload = {}, company = {}) => {
  const settings = getAttendanceWifiSettings(company);
  if (!settings.ssid) {
    throw new Error('Chưa cài WiFi mặc định để chấm công. Kế toán hoặc chủ doanh nghiệp hãy đặt WiFi hiện tại làm mặc định trước.');
  }
  if (!doesWifiMatchAttendanceDefault(wifiPayload, company)) {
    const currentWifi = getWifiPayloadName(wifiPayload) || 'không xác định';
    throw new Error(`WiFi hiện tại (${currentWifi}) không trùng WiFi chấm công mặc định (${settings.ssid}).`);
  }
};

const buildVerifiedAttendanceMethodPayload = async (methodKey = 'gps', wifiLabel = '') => {
  const networkInfo = getNetworkConnectionInfo();
  if (methodKey === 'wifi') {
    if (isAndroidNativeRuntime()) {
      const detectedWifi = await getCurrentConnectedWifiForAttendance();
      if (!detectedWifi.supported || !detectedWifi.ssid) {
        throw new Error(detectedWifi.message || 'Không xác định được WiFi hiện tại.');
      }
      return {
        label: `WiFi: ${detectedWifi.ssid}`,
        type: 'wifi',
        networkLabel: detectedWifi.ssid,
        ssid: detectedWifi.ssid,
        bssid: detectedWifi.bssid || null,
        rssi: detectedWifi.rssi ?? null,
        linkSpeed: detectedWifi.linkSpeed ?? null,
        frequency: detectedWifi.frequency ?? null,
        source: detectedWifi.source || 'android-native',
        wifiLookupMode: 'auto',
        ...networkInfo
      };
    }

    const trimmedWifiLabel = normalizeWifiName(wifiLabel);
    if (!trimmedWifiLabel) {
      throw new Error('Chưa nhập WiFi để chấm công.');
    }
    return {
      label: `WiFi: ${trimmedWifiLabel}`,
      type: 'wifi',
      networkLabel: trimmedWifiLabel,
      ssid: trimmedWifiLabel,
      bssid: null,
      wifiLookupMode: 'manual',
      ...networkInfo
    };
  }

  const position = await requestPreciseAttendanceLocation();
  return {
    label: 'GPS vị trí',
    type: 'gps',
    latitude: Number(position.coords.latitude.toFixed(6)),
    longitude: Number(position.coords.longitude.toFixed(6)),
    accuracy: Math.round(position.coords.accuracy || 0),
    ...networkInfo
  };
};

const hasAttendanceGpsMeta = (meta = {}) => meta?.type === 'gps'
  && Number.isFinite(Number(meta.latitude))
  && Number.isFinite(Number(meta.longitude));

const buildAttendanceGpsMapUrl = (meta = {}) => {
  if (!hasAttendanceGpsMeta(meta)) return '';
  const latitude = Number(meta.latitude);
  const longitude = Number(meta.longitude);
  return `https://www.google.com/maps/search/?api=1&query=${latitude},${longitude}`;
};

const formatAttendanceGpsSummary = (meta = {}) => {
  if (!hasAttendanceGpsMeta(meta)) return '';
  const accuracy = Math.round(Number(meta.accuracy || 0));
  return `${Number(meta.latitude).toFixed(6)}, ${Number(meta.longitude).toFixed(6)}${accuracy ? ` • sai số ${accuracy}m` : ''}`;
};

const buildSimpleCheckOutPayload = () => ({
  label: 'Ra ca',
  type: 'simple_checkout',
  source: 'one-tap',
  ...getNetworkConnectionInfo()
});

const CUSTOMER_LOGIN_MODE_KEY = 'hd-manager-preferred-login-mode';

const savePreferredLoginMode = (mode = 'staff') => {
  if (typeof window === 'undefined') return;
  const normalizedMode = mode === 'customer' ? 'customer' : 'staff';
  try {
    window.localStorage.setItem(CUSTOMER_LOGIN_MODE_KEY, normalizedMode);
    window.sessionStorage.setItem(CUSTOMER_LOGIN_MODE_KEY, normalizedMode);
  } catch (error) {
    console.warn('Failed to save preferred login mode.', error);
  }
};

const loadAppSession = () => {
  const defaultSession = { currentUser: null, currentCompany: null, activeTab: 'home' };
  if (typeof window === 'undefined') return defaultSession;

  try {
    const params = new URLSearchParams(window.location.search || '');
    if (params.get('customerLogin') === '1') {
      window.localStorage.removeItem(APP_SESSION_KEY);
      savePreferredLoginMode('customer');
      return defaultSession;
    }
    if (params.get('clearSession') === '1' || params.get('resetSession') === '1') {
      window.localStorage.removeItem(APP_SESSION_KEY);
      return defaultSession;
    }

    const raw = window.localStorage.getItem(APP_SESSION_KEY);
    if (!raw) return defaultSession;

    const parsed = JSON.parse(raw);
    return {
      currentUser: parsed.currentUser || null,
      currentCompany: parsed.currentCompany || null,
      activeTab: parsed.activeTab || 'home'
    };
  } catch (error) {
    console.warn('Failed to restore app session.', error);
    return defaultSession;
  }
};

const saveAppSession = (session) => {
  if (typeof window === 'undefined') return;

  try {
    if (!session?.currentUser?.id || !session?.currentUser?.companyId) {
      window.localStorage.removeItem(APP_SESSION_KEY);
      return;
    }

    window.localStorage.setItem(APP_SESSION_KEY, JSON.stringify({
      currentUser: session.currentUser,
      currentCompany: session.currentCompany || null,
      activeTab: session.activeTab || 'home',
      savedAt: new Date().toISOString()
    }));
  } catch (error) {
    console.warn('Failed to save app session.', error);
  }
};

const clearAppSession = () => {
  if (typeof window === 'undefined') return;
  try {
    window.localStorage.removeItem(APP_SESSION_KEY);
  } catch (error) {
    console.warn('Failed to clear app session.', error);
  }
};

const getInitialLoginMode = () => {
  if (typeof window === 'undefined') return 'staff';
  try {
    const params = new URLSearchParams(window.location.search || '');
    if (params.get('customerLogin') === '1') return 'customer';
    const preferredMode = window.localStorage.getItem(CUSTOMER_LOGIN_MODE_KEY)
      || window.sessionStorage.getItem(CUSTOMER_LOGIN_MODE_KEY);
    if (preferredMode) return preferredMode === 'customer' ? 'customer' : 'staff';
    return 'staff';
  } catch (error) {
    return 'staff';
  }
};

const setPreferredCustomerLoginMode = () => {
  savePreferredLoginMode('customer');
};

const calculateTieredBonus = (revenue, target) => {
  if (!target || revenue <= target) return 0;
  const excess = revenue - target;
  if (excess <= 20000000) return excess * 0.02;
  if (excess <= 50000000) return (20000000 * 0.02) + ((excess - 20000000) * 0.05);
  return (20000000 * 0.02) + (30000000 * 0.05) + ((excess - 50000000) * 0.1);
};

const calculateCommission = (revenue, target, rate) => {
  const actualRevenue = revenue || 0;
  const targetRevenue = target || 0;
  const commissionRate = rate || 0;
  const exceededRevenue = Math.max(0, actualRevenue - targetRevenue);
  return exceededRevenue * commissionRate;
};
const parseCommissionPercentInput = (value) => {
  const parsed = parseFloat(`${value ?? ''}`.replace(',', '.'));
  return Number.isFinite(parsed) && parsed > 0 ? parsed / 100 : 0;
};
const formatCommissionPercentInput = (rate) => {
  const parsed = parseFloat(rate || 0);
  if (!Number.isFinite(parsed) || parsed <= 0) return '';
  return (parsed * 100).toFixed(4).replace(/0+$/, '').replace(/\.$/, '');
};
const formatCommissionPercentLabel = (rate) => {
  const parsed = parseFloat(rate || 0);
  if (!Number.isFinite(parsed) || parsed <= 0) return '0%';
  return `${(parsed * 100).toFixed(2).replace(/\.00$/, '').replace(/0$/, '')}%`;
};
const shouldUseTotalRevenueCommission = (employee = {}) => (
  isSalesCollaboratorPosition(employee?.position)
  || employee?.commissionBaseMode === 'total_revenue'
);
const calculateDirectSalesCommission = (employee = {}, revenue = 0) => {
  const commissionRate = parseFloat(employee?.commissionRate) || 0;
  if (!commissionRate) return 0;
  return roundMoneyValue(calculateCommission(revenue || 0, employee?.targetRevenue || 0, commissionRate));
};
const buildSalesDownlineCommissionRows = (leaderEmpId, employees = [], orders = [], customers = [], monthKey = getTodayString().substring(0, 7)) => {
  const leaderKey = `${leaderEmpId || ''}`.trim();
  if (!leaderKey) return [];
  return (employees || [])
    .filter(employee => !employee?.isArchived && employee.id !== leaderKey && isEmployeeSalesPosition(employee) && getSalesLeaderId(employee) === leaderKey)
    .map(employee => {
      const revenue = calculateRevenueForMonth(employee.id, orders, customers, monthKey);
      const commissionPercent = getSalesLeaderCommissionPercent(employee);
      const commission = roundMoneyValue(revenue * (commissionPercent / 100));
      return {
        employeeId: employee.id,
        employeeName: employee.name || 'Nhân sự kinh doanh',
        revenue: roundMoneyValue(revenue),
        commissionPercent,
        commission
      };
    })
    .filter(row => row.revenue > 0 || row.commissionPercent > 0);
};

const getExperienceCycleMeta = (period = 'months') => {
  if (period === 'quarters') return { monthsPerCycle: 3, label: 'quý' };
  if (period === 'years') return { monthsPerCycle: 12, label: 'năm' };
  return { monthsPerCycle: 1, label: 'tháng' };
};

const getMonthEndDateInputValue = (monthKey = getTodayString().substring(0, 7)) => {
  const safeMonthKey = /^\d{4}-\d{2}$/.test(`${monthKey}`) ? `${monthKey}` : getTodayString().substring(0, 7);
  const [year, month] = safeMonthKey.split('-').map(Number);
  const lastDay = new Date(year, month, 0).getDate();
  return `${safeMonthKey}-${String(lastDay).padStart(2, '0')}`;
};

const getActualCalendarDaysInMonth = (monthKey = getTodayString().substring(0, 7)) => {
  const safeMonthKey = /^\d{4}-\d{2}$/.test(`${monthKey}`) ? `${monthKey}` : getTodayString().substring(0, 7);
  const [year, month] = safeMonthKey.split('-').map(Number);
  return new Date(year, month, 0).getDate();
};

const calculateExperienceSalaryAtDate = (startDate, amount, period = 'months', referenceDate = getTodayString()) => {
  const cycleMeta = getExperienceCycleMeta(period);
  if (!startDate) {
    return { total: 0, expMonths: 0, experienceCycles: 0, experienceCycleLabel: cycleMeta.label };
  }

  const start = parseDateInputValue(startDate);
  const now = parseDateInputValue(referenceDate);
  let expMonths = (now.getFullYear() - start.getFullYear()) * 12 + (now.getMonth() - start.getMonth());

  if (now.getDate() < start.getDate()) expMonths -= 1;
  if (expMonths < 0) expMonths = 0;

  const experienceCycles = amount > 0 ? Math.floor(expMonths / cycleMeta.monthsPerCycle) : 0;

  return {
    total: experienceCycles * (amount || 0),
    expMonths,
    experienceCycles,
    experienceCycleLabel: cycleMeta.label
  };
};

const calculateExperienceSalary = (startDate, amount, period = 'months') => (
  calculateExperienceSalaryAtDate(startDate, amount, period, getTodayString())
);

const isWorkingAttendanceStatus = (status = '') => status === 'present' || status === 'late';

const calculateDailyPayrollExpenseForEmployee = (employee = {}, attendanceRecord = null, targetDate = getTodayString(), holidays = []) => {
  if (!employee?.id || employee?.isArchived || isSalesCollaboratorPosition(employee?.position) || !isWorkingAttendanceStatus(attendanceRecord?.status)) {
    return {
      baseComponent: 0,
      supportComponent: 0,
      responsibilityComponent: 0,
      experienceComponent: 0,
      holidayComponent: 0,
      total: 0
    };
  }
  const attendanceTiming = calculateAttendanceTiming(employee, {
    date: targetDate,
    status: attendanceRecord?.status,
    checkIn: attendanceRecord?.checkIn || null,
    checkOut: attendanceRecord?.checkOut || null
  });
  if (attendanceTiming.noSalaryDay) {
    return {
      baseComponent: 0,
      supportComponent: 0,
      responsibilityComponent: 0,
      experienceComponent: 0,
      holidayComponent: 0,
      total: 0
    };
  }

  const workDate = parseDateInputValue(targetDate);
  const probationEndDate = resolveProbationEndDate(employee.startDate, employee.probationDuration, employee.probationUnit);
  const salaryMonthDays = resolveSalaryMonthDays(employee, `${targetDate || getTodayString()}`.substring(0, 7));
  const basicSalaryMonthDays = salaryMonthDays;
  const supportSalaryMonthDays = basicSalaryMonthDays;
  const basicSalary = parseLooseMoneyValue(employee.basicSalary);
  const supportSalary = parseLooseMoneyValue(employee.supportSalary);
  const responsibilitySalary = parseLooseMoneyValue(employee.responsibilitySalary);
  const experienceSalary = parseLooseMoneyValue(employee.experienceSalary);
  const dailyBaseWage = basicSalary / basicSalaryMonthDays;
  const dailySupportWage = supportSalary / supportSalaryMonthDays;
  const probationRate = (employee.probationRate !== undefined ? employee.probationRate : 100) / 100;
  const isProbationDay = probationEndDate && workDate <= probationEndDate;
  const baseComponent = isProbationDay ? dailyBaseWage * probationRate : dailyBaseWage;
  const supportComponent = isProbationDay ? dailySupportWage * probationRate : dailySupportWage;
  const responsibilityComponent = responsibilitySalary / basicSalaryMonthDays;
  const experienceMonthlyAmount = calculateExperienceSalaryAtDate(
    employee.startDate,
    experienceSalary,
    employee.experienceSalaryPeriod || 'months',
    targetDate
  ).total;
  const experienceComponent = experienceMonthlyAmount > 0 ? experienceMonthlyAmount / salaryMonthDays : 0;

  let holidayComponent = 0;
  const matchedHolidays = holidays.filter(holiday => holiday.date === targetDate && !holiday.isArchived);
  matchedHolidays.forEach(matchedHoliday => {
    const holidayValue = parseLooseMoneyValue(matchedHoliday.value);
    if (matchedHoliday.type === 'fixed') holidayComponent += holidayValue;
    else if (matchedHoliday.type === 'percentage') holidayComponent += dailyBaseWage * (holidayValue / 100);
  });

  return {
    baseComponent,
    supportComponent,
    responsibilityComponent,
    experienceComponent,
    holidayComponent,
    total: baseComponent + supportComponent + responsibilityComponent + experienceComponent + holidayComponent
  };
};

const calculateDailyPayrollExpense = (employees = [], attendance = {}, targetDate = getTodayString(), holidays = []) => (
  employees.reduce((sum, employee) => {
    const attendanceRecord = attendance[`${targetDate}_${employee.id}`];
    return sum + calculateDailyPayrollExpenseForEmployee(employee, attendanceRecord, targetDate, holidays).total;
  }, 0)
);

const buildPositiveDailyPayrollRowsFromSalary = ({
  employees = [],
  attendance = {},
  financials = [],
  performance = {},
  customers = [],
  orders = [],
  payments = [],
  holidays = [],
  targetDate = getTodayString()
} = {}) => {
  const monthKey = `${targetDate || getTodayString()}`.substring(0, 7);

  return (employees || [])
    .filter(emp => emp?.id && !emp?.isArchived)
    .filter(emp => emp?.role !== 'super_admin' && !isOwnerPosition(emp?.position))
    .map(emp => {
      const details = buildSalaryDetails(emp.id, employees, attendance, financials, performance, customers, orders, payments, holidays, monthKey);
      const netSalary = parseLooseMoneyValue(details?.netSalary);
      if (netSalary <= 0) return null;
      const salaryMonthDays = resolveSalaryMonthDays(emp, monthKey);
      const dailyAmount = netSalary / Math.max(1, salaryMonthDays);
      const attendanceRecord = attendance?.[`${targetDate}_${emp.id}`] || null;
      return {
        employee: emp,
        details,
        netSalary,
        salaryMonthDays,
        dailyAmount,
        attendanceRecord
      };
    })
    .filter(Boolean);
};

const calculatePositiveDailyPayrollExpenseFromSalary = (options = {}) => (
  buildPositiveDailyPayrollRowsFromSalary(options)
    .reduce((sum, row) => sum + (row.dailyAmount || 0), 0)
);

const compareLedgerItems = (a, b) => {
  const aDateKey = getPaymentDateKey(a) || getDateKeyFromAnyValue(a?.paymentDate || a?.transactionDate || a?.transactionDateTime || a?.paidAt || a?.transactionAt || a?.date || a?.createdAt || getEntityTimestamp(a));
  const bDateKey = getPaymentDateKey(b) || getDateKeyFromAnyValue(b?.paymentDate || b?.transactionDate || b?.transactionDateTime || b?.paidAt || b?.transactionAt || b?.date || b?.createdAt || getEntityTimestamp(b));
  const dateCompare = new Date(`${aDateKey || '1970-01-01'}T00:00:00`).getTime() - new Date(`${bDateKey || '1970-01-01'}T00:00:00`).getTime();
  if (dateCompare !== 0) return dateCompare;
  const timestampCompare = (getPaymentTimestamp(a) || getEntityTimestamp(a) || 0) - (getPaymentTimestamp(b) || getEntityTimestamp(b) || 0);
  if (timestampCompare !== 0) return timestampCompare;
  return (a.id || '').localeCompare(b.id || '');
};

const sortLedgerOrdersNewestFirst = (orders = []) => (
  [...(orders || [])].sort((a, b) => compareLedgerItems(b, a))
);

const REPORT_TIME_BUCKETS = ['00h', '03h', '06h', '09h', '12h', '15h', '18h', '21h'];

const parseVietnameseDateTimeString = (value = '') => {
  const raw = `${value || ''}`.trim();
  if (!raw) return null;
  const match = raw.match(/\b(\d{1,2})[\/-](\d{1,2})[\/-](\d{4})(?:[,\s]+(\d{1,2}):(\d{2})(?::(\d{2}))?)?/);
  if (!match) return null;
  const day = Number(match[1]);
  const month = Number(match[2]);
  const year = Number(match[3]);
  const hour = Number(match[4] || 0);
  const minute = Number(match[5] || 0);
  const second = Number(match[6] || 0);
  if (!Number.isInteger(day) || !Number.isInteger(month) || !Number.isInteger(year)) return null;
  if (day < 1 || day > 31 || month < 1 || month > 12 || year < 1900) return null;
  if (hour < 0 || hour > 23 || minute < 0 || minute > 59 || second < 0 || second > 59) return null;
  const parsed = new Date(year, month - 1, day, hour, minute, second);
  if (Number.isNaN(parsed.getTime())) return null;
  if (parsed.getFullYear() !== year || parsed.getMonth() !== month - 1 || parsed.getDate() !== day) return null;
  return parsed.getTime();
};

const parseEntityTimestampValue = (rawValue) => {
  if (!rawValue) return null;

  if (typeof rawValue === 'number') {
    if (!Number.isFinite(rawValue) || rawValue <= 0) return null;
    return rawValue < 10000000000 ? rawValue * 1000 : rawValue;
  }

  if (typeof rawValue?.toDate === 'function') {
    const parsedDate = rawValue.toDate();
    if (parsedDate instanceof Date && !Number.isNaN(parsedDate.getTime())) return parsedDate.getTime();
  }

  if (typeof rawValue === 'object') {
    const seconds = rawValue.seconds ?? rawValue._seconds;
    const nanos = rawValue.nanoseconds ?? rawValue._nanoseconds ?? 0;
    if (seconds !== undefined && seconds !== null) {
      const parsedSeconds = Number(seconds);
      const parsedNanos = Number(nanos);
      if (Number.isFinite(parsedSeconds)) {
        return (parsedSeconds * 1000) + Math.floor((Number.isFinite(parsedNanos) ? parsedNanos : 0) / 1000000);
      }
    }

    const nestedValue = rawValue.timestampValue
      ?? rawValue.stringValue
      ?? rawValue.integerValue
      ?? rawValue.doubleValue
      ?? rawValue.value;
    if (nestedValue !== undefined && nestedValue !== rawValue) {
      return parseEntityTimestampValue(nestedValue);
    }
  }

  if (typeof rawValue === 'string') {
    const normalized = rawValue.trim();
    if (!normalized) return null;
    if (/^\d{10,13}$/.test(normalized)) {
      const parsedNumeric = Number(normalized);
      if (Number.isFinite(parsedNumeric)) return normalized.length === 10 ? parsedNumeric * 1000 : parsedNumeric;
    }
    const vietnameseTimestamp = parseVietnameseDateTimeString(normalized);
    if (vietnameseTimestamp) return vietnameseTimestamp;
    const parsed = new Date(normalized).getTime();
    if (!Number.isNaN(parsed)) return parsed;
  }

  return null;
};

const getEntityTimestamp = (entity = {}) => {
  if (!entity || typeof entity !== 'object') return parseEntityTimestampValue(entity);

  const timestampFields = [
    entity.createdAt,
    entity.updatedAt,
    entity.timestamp,
    entity.receivedAt,
    entity.sentAt,
    entity.approvedAt,
    entity.paidAt,
    entity.lastMessageAt,
    entity.lastActivityAt
  ];

  for (const rawValue of timestampFields) {
    const parsed = parseEntityTimestampValue(rawValue);
    if (parsed) return parsed;
  }

  if (typeof entity.date === 'string' && entity.date.includes('T')) {
    const parsed = new Date(entity.date).getTime();
    if (!Number.isNaN(parsed)) return parsed;
  }

  const idMatch = `${entity.id || ''}`.match(/_(\d{10,13})$/);
  if (idMatch) {
    const rawTimestamp = parseInt(idMatch[1], 10);
    if (!Number.isNaN(rawTimestamp)) {
      return idMatch[1].length === 10 ? rawTimestamp * 1000 : rawTimestamp;
    }
  }

  const embeddedIdTimestampMatch = `${entity.id || ''}`.match(/(?:^|_)(\d{13})(?:_|$)/);
  if (embeddedIdTimestampMatch) {
    const rawTimestamp = parseInt(embeddedIdTimestampMatch[1], 10);
    if (!Number.isNaN(rawTimestamp)) return rawTimestamp;
  }

  return null;
};

const getOrderPlacedAtLabel = (entity = {}) => {
  const placedAt = entity.createdAt
    || entity.requestedAt
    || entity.orderCreatedAt
    || entity.sourceCreatedAt
    || entity.timestamp
    || getEntityTimestamp(entity)
    || entity.date
    || entity.requestDateKey
    || entity.requestDate;
  return formatDateTimeLabel(placedAt);
};

const getOrderPlacedAtTimeLabel = (entity = {}) => {
  const placedAt = entity.createdAt
    || entity.requestedAt
    || entity.orderCreatedAt
    || entity.sourceCreatedAt
    || entity.timestamp;

  if (typeof placedAt?.toDate === 'function') return formatTime(placedAt.toDate());
  if (typeof placedAt === 'number') return formatTime(new Date(placedAt));
  if (placedAt && !(typeof placedAt === 'string' && isDateOnlyString(placedAt))) return formatTime(placedAt);

  const fallbackTimestamp = getEntityTimestamp(entity);
  return fallbackTimestamp ? formatTime(new Date(fallbackTimestamp)) : '--:--';
};

const resolveEntityDateKey = (entity = {}, fallbackDate = getTodayString()) => {
  const rawDate = `${entity?.date
    || entity?.requestDate
    || entity?.requestDateKey
    || entity?.orderRequestDate
    || entity?.sourceOrderRequestDate
    || entity?.dispatchDate
    || entity?.deliveryDate
    || ''}`.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(rawDate)) return rawDate;
  if (rawDate) {
    const parsedRawDate = new Date(rawDate);
    if (!Number.isNaN(parsedRawDate.getTime())) {
      return `${parsedRawDate.getFullYear()}-${String(parsedRawDate.getMonth() + 1).padStart(2, '0')}-${String(parsedRawDate.getDate()).padStart(2, '0')}`;
    }
  }

  const timestamp = getEntityTimestamp(entity);
  if (!timestamp) return fallbackDate;
  const parsedTimestamp = new Date(timestamp);
  return `${parsedTimestamp.getFullYear()}-${String(parsedTimestamp.getMonth() + 1).padStart(2, '0')}-${String(parsedTimestamp.getDate()).padStart(2, '0')}`;
};

const buildDuplicateOrderItemKey = (item = {}) => {
  const productKey = `${item.productId || item.product_id || ''}`.trim()
    || normalizeLookupText(item.description || item.productName || item.productNameSnapshot || item.name || '');
  const attributeKey = normalizeLookupText(item.attributeLabel || item.productAttribute || item.attribute || '');
  const sizeKey = normalizeLookupText(item.sizeLabel || item.weightKg || item.size || '');
  const quantity = parseLooseQuantityValue(item.quantity ?? item.qty ?? item.quantityKg);
  const unitKey = normalizeLookupText(item.quantityUnit || item.unit || item.unitLabel || '');
  const unitPrice = parseLooseMoneyValue(item.unitPrice ?? item.price ?? item.unit_price_vnd ?? item.unit_price);

  if (!productKey && quantity <= 0 && unitPrice <= 0) return '';
  return [productKey, attributeKey, sizeKey, quantity.toFixed(3), unitKey, Math.round(unitPrice)].join(':');
};

const buildDuplicateOrderItemsKey = (items = []) => (Array.isArray(items) ? items : [])
  .map(buildDuplicateOrderItemKey)
  .filter(Boolean)
  .sort()
  .join('|');

const buildOrderDuplicateSignature = (order = {}) => {
  const dispatchIds = Array.isArray(order.sourceDispatchIds)
    ? order.sourceDispatchIds.map(item => `${item || ''}`.trim()).filter(Boolean).sort()
    : [];
  if (dispatchIds.length > 0) return `dispatch::${dispatchIds.join('|')}`;

  const customerKey = `${order.customerId || ''}`.trim()
    || normalizeLookupText(order.customerName || order.customerNameSnapshot || order.customer?.name || '');
  const branchKey = `${order.branchId || order.customerBranchId || ''}`.trim()
    || normalizeLookupText(order.branchName || order.customerBranchName || '');
  const dateKey = resolveEntityDateKey(order, order.date || getTodayString());
  const itemKey = buildDuplicateOrderItemsKey(order.items || []);
  const amountKey = Math.round(parseLooseMoneyValue(order.amount ?? order.totalAmount ?? order.grandTotal));

  return customerKey && itemKey ? `order::${dateKey}::${customerKey}::${branchKey || 'main'}::${itemKey}::${amountKey}` : '';
};

const buildOrderRequestDuplicateSignature = (request = {}) => {
  const customerKey = `${request.customerId || ''}`.trim()
    || normalizeLookupText(request.customerName || request.customerNameSnapshot || request.customer?.name || '');
  const firstRequestItem = Array.isArray(request.items) && request.items.length > 0
    ? request.items[0]
    : (request.primaryItem || {});
  const branchKey = `${request.branchId || request.customerBranchId || firstRequestItem.branchId || firstRequestItem.customerBranchId || ''}`.trim()
    || normalizeLookupText(request.branchName || request.customerBranchName || firstRequestItem.branchName || firstRequestItem.customerBranchName || '');
  const dateKey = resolveEntityDateKey(request, request.date || getTodayString());
  const requestItems = Array.isArray(request.items) && request.items.length > 0
    ? request.items
    : (request.primaryItem ? [request.primaryItem] : []);
  const itemKey = buildDuplicateOrderItemsKey(requestItems);
  const depositKey = Math.round(parseLooseMoneyValue(request.upfrontPayment ?? request.depositAmount ?? request.prepaidAmount));

  return customerKey && itemKey ? `request::${dateKey}::${customerKey}::${branchKey || 'main'}::${itemKey}::${depositKey}` : '';
};

const isKgQuantityUnit = (unit = '') => {
  const normalizedUnit = normalizeLookupText(unit || '');
  return ['kg', 'kgs', 'kilogram', 'kilograms'].includes(normalizedUnit);
};

const formatWarehouseShortageQuantityLabel = (quantityByUnit = {}) => {
  const labels = Object.entries(quantityByUnit)
    .filter(([, value]) => (value || 0) > 0)
    .map(([unit, value]) => `${formatNumber(value)} ${unit || 'đơn vị'}`);
  return labels.length ? labels.join(' + ') : 'Chưa rõ số lượng';
};

const addWarehouseShortageQuantity = (quantityByUnit = {}, unit = '', value = 0) => {
  const quantityValue = parseLooseQuantityValue(value);
  if (quantityValue <= 0) return quantityByUnit;
  const normalizedUnit = normalizeWarehouseMeasureUnit(unit || 'Đơn vị');
  quantityByUnit[normalizedUnit] = (quantityByUnit[normalizedUnit] || 0) + quantityValue;
  return quantityByUnit;
};

const getWarehouseShortageQuantityValue = (quantityByUnit = {}, unit = '') => {
  const unitKey = normalizeLookupText(unit || '');
  const matchedEntry = Object.entries(quantityByUnit || {}).find(([entryUnit]) => normalizeLookupText(entryUnit) === unitKey);
  return matchedEntry ? parseLooseQuantityValue(matchedEntry[1]) : 0;
};

const buildWarehouseDispatchShortageSummary = ({
  orderRequests = [],
  warehouseDispatches = [],
  customers = [],
  products = [],
  dateKey = getTodayString(),
  dispatchDateKey = dateKey,
  autoCancelAfterDays = 0,
  includePreviousOpenOrders = false,
  fromDateKey = ''
} = {}) => {
  const customerLookup = new Map((customers || []).map(customer => [customer.id, customer]));
  const productLookup = new Map((products || []).map(product => [product.id, product]));
  const normalizedAutoCancelDays = Math.max(0, parseInt(autoCancelAfterDays, 10) || 0);
  const normalizedDateKey = dateKey || getTodayString();
  const normalizedDispatchDateKey = dispatchDateKey || normalizedDateKey;
  const normalizedFromDateKey = /^\d{4}-\d{2}-\d{2}$/.test(`${fromDateKey || ''}`) ? fromDateKey : '';
  const shouldUseBacklog = Boolean(includePreviousOpenOrders);
  const buildLineKeyVariants = ({
    customerId = '',
    customerName = '',
    productId = '',
    productName = '',
    productShortName = ''
  } = {}) => {
    const customerKeys = Array.from(new Set([
      customerId,
      normalizeLookupText(customerName || '')
    ].filter(Boolean)));
    const productKeys = Array.from(new Set([
      productId,
      normalizeLookupText(productName || ''),
      normalizeLookupText(productShortName || '')
    ].filter(Boolean)));
    const variants = [];
    customerKeys.forEach(customerKey => {
      productKeys.forEach(productKey => {
        variants.push([customerKey, productKey].join('__'));
      });
    });
    return variants.length > 0 ? Array.from(new Set(variants)) : ['__'];
  };
  const buildLineKey = (customerId, customerName, productId, productName, productShortName = '') => (
    buildLineKeyVariants({ customerId, customerName, productId, productName, productShortName })[0]
  );
  const shouldIncludeOrderRequestDate = (requestDate = '') => {
    const targetDate = requestDate || normalizedDateKey;
    if (!shouldUseBacklog) {
      if (targetDate !== normalizedDateKey) return false;
      if (normalizedAutoCancelDays <= 0) return true;
      return getDaysBetweenDateKeys(targetDate, normalizedDispatchDateKey) <= normalizedAutoCancelDays;
    }
    if (targetDate > normalizedDispatchDateKey) return false;
    if (normalizedFromDateKey && targetDate < normalizedFromDateKey) return false;
    if (normalizedAutoCancelDays <= 0) return true;
    return getDaysBetweenDateKeys(targetDate, normalizedDispatchDateKey) <= normalizedAutoCancelDays;
  };
  const resolveDispatchSourceOrderDate = (dispatch = {}) => `${dispatch.sourceOrderRequestDate
    || dispatch.orderRequestDate
    || dispatch.requestDate
    || dispatch.requestDateKey
    || dispatch.sourceOrderDate
    || ''}`.trim();
  const shouldIncludeDispatchForShortage = (dispatch = {}) => {
    const sourceOrderDate = resolveDispatchSourceOrderDate(dispatch);
    const dispatchDate = resolveEntityDateKey(dispatch, normalizedDispatchDateKey);
    if (dispatchDate && dispatchDate > normalizedDispatchDateKey) return false;
    if (sourceOrderDate) return shouldIncludeOrderRequestDate(sourceOrderDate);
    if (shouldUseBacklog) {
      if (dispatchDate > normalizedDispatchDateKey) return false;
      if (normalizedFromDateKey && dispatchDate < normalizedFromDateKey) return false;
      return true;
    }
    return dispatchDate === normalizedDateKey;
  };
  const buildShortageDateTimestamp = (targetDate = '', endOfDay = false) => {
    const dateValue = /^\d{4}-\d{2}-\d{2}$/.test(`${targetDate || ''}`) ? targetDate : '';
    if (!dateValue) return 0;
    const parsed = new Date(`${dateValue}T${endOfDay ? '23:59:59.999' : '00:00:00.000'}`).getTime();
    return Number.isFinite(parsed) ? parsed : 0;
  };
  const resolveRequestLineTimestamp = (request = {}, requestDate = '') => (
    getEntityTimestamp(request) || buildShortageDateTimestamp(requestDate || normalizedDateKey, false)
  );
  const resolveDispatchLineTimestamp = (dispatch = {}, dispatchDate = '') => (
    getEntityTimestamp(dispatch) || buildShortageDateTimestamp(dispatchDate || normalizedDispatchDateKey, true)
  );

  const requestedLineMap = new Map();
  (orderRequests || [])
    .filter(request => !request?.isArchived)
    .filter(request => {
      const requestDate = resolveEntityDateKey(request, normalizedDateKey);
      return shouldIncludeOrderRequestDate(requestDate);
    })
    .forEach(request => {
      const requestDate = resolveEntityDateKey(request, normalizedDateKey);
      const requestTimestamp = resolveRequestLineTimestamp(request, requestDate);
      const customer = customerLookup.get(request.customerId);
      const customerName = customer?.name || request.customerName || request.customerNameSnapshot || 'Khách hàng';
      const items = Array.isArray(request.items) && request.items.length > 0
        ? request.items
        : (request.primaryItem ? [request.primaryItem] : []);
      const closedShortItems = request.closedShortItems && typeof request.closedShortItems === 'object' && !Array.isArray(request.closedShortItems)
        ? request.closedShortItems
        : {};
      const closedShortItemKeys = new Set([
        ...(Array.isArray(request.closedShortItemKeys) ? request.closedShortItemKeys : []),
        ...Object.keys(closedShortItems)
      ].filter(Boolean));

      items.forEach((item, itemIndex) => {
        const product = productLookup.get(item.productId);
        const productName = product?.name || item.description || item.productName || item.productNameSnapshot || 'Hàng hóa';
        const productShortName = getProductShortName(product) || `${item.productShortName || item.shortName || item.productCode || ''}`.trim().toUpperCase();
        const itemRowKey = item.rowKey
          || item.id
          || item.lineId
          || item.itemId
          || `${request.id || 'request'}_${item.productId || normalizeLookupText(productName) || itemIndex}_${itemIndex}`;
        const closedShortMeta = closedShortItems[itemRowKey] || closedShortItems[item.productId] || closedShortItems[normalizeLookupText(productName)] || null;
        if (
          item.status === 'closed_short'
          || item.dispatchStatus === 'closed_short'
          || Boolean(closedShortMeta)
          || closedShortItemKeys.has(itemRowKey)
          || closedShortItemKeys.has(item.productId)
          || closedShortItemKeys.has(normalizeLookupText(productName))
        ) {
          return;
        }
        const lineKeyVariants = buildLineKeyVariants({
          customerId: request.customerId,
          customerName,
          productId: item.productId,
          productName,
          productShortName
        });
        const lineKey = lineKeyVariants[0];
        const quantityValue = parseLooseQuantityValue(item.quantity ?? item.quantityValue ?? item.qty);
        const quantityUnit = `${item.quantityUnit || product?.unit || ''}`.trim();
        const normalizedDisplayUnit = normalizeWarehouseMeasureUnit(quantityUnit || 'Đơn vị');
        const current = requestedLineMap.get(lineKey) || {
          key: lineKey,
          aliasKeys: lineKeyVariants,
          customerId: request.customerId || '',
          productId: item.productId || '',
          customerName,
          productName,
          productShortName,
          requestCount: 0,
          requiredKg: 0,
          quantityByUnit: {},
          requestLines: [],
          latestTimestamp: 0
        };

        current.aliasKeys = Array.from(new Set([...(current.aliasKeys || []), ...lineKeyVariants]));
        current.requestCount += 1;
        current.latestTimestamp = Math.max(current.latestTimestamp || 0, requestTimestamp || 0);
        if (quantityValue > 0) {
          addWarehouseShortageQuantity(current.quantityByUnit, normalizedDisplayUnit, quantityValue);
          if (isKgQuantityUnit(quantityUnit)) current.requiredKg += quantityValue;
        }
        current.requestLines.push({
          rowKey: itemRowKey,
          itemIndex,
          requestId: request.id || '',
          requestDate,
          requestTimestamp,
          customerId: request.customerId || '',
          customerName,
          productId: item.productId || '',
          productName,
          productShortName,
          attributeLabel: `${item.attributeLabel || item.productAttribute || item.attribute || ''}`.trim(),
          sizeLabel: `${item.sizeLabel || item.weightKg || item.size || ''}`.trim(),
          quantity: quantityValue,
          quantityUnit: normalizedDisplayUnit,
          unitPrice: parseLooseMoneyValue(item.unitPrice ?? item.unit_price_vnd ?? item.price),
          note: request.note || '',
          totalAmount: request.totalAmount || 0,
          salesEmpId: request.salesEmpId || '',
          createdByEmpId: request.createdByEmpId || request.empId || ''
        });
        requestedLineMap.set(lineKey, current);
      });
    });

  const dispatchedLineMap = new Map();
  (warehouseDispatches || [])
    .filter(dispatch => !dispatch?.isArchived)
    .filter(dispatch => shouldIncludeDispatchForShortage(dispatch))
    .forEach(dispatch => {
      const customer = customerLookup.get(dispatch.customerId);
      const product = productLookup.get(dispatch.productId);
      const customerName = customer?.name || dispatch.customerNameSnapshot || 'Khách hàng';
      const productName = product?.name || dispatch.productNameSnapshot || 'Hàng hóa';
      const productShortName = getProductShortName(product) || `${dispatch.productShortName || dispatch.shortName || dispatch.productCode || ''}`.trim().toUpperCase();
      const lineKeyVariants = buildLineKeyVariants({
        customerId: dispatch.customerId,
        customerName,
        productId: dispatch.productId,
        productName,
        productShortName
      });
      const dispatchDate = resolveEntityDateKey(dispatch, normalizedDispatchDateKey);
      const dispatchTimestamp = resolveDispatchLineTimestamp(dispatch, dispatchDate);
      const dispatchMeasures = buildWarehouseDispatchMeasureEntries(dispatch, product);
      const dispatchQuantityByUnit = {};
      dispatchMeasures.forEach(measure => {
        addWarehouseShortageQuantity(dispatchQuantityByUnit, measure.unit, measure.quantity);
      });
      const dispatchLine = {
        dispatchId: dispatch.id || '',
        dispatchDate,
        dispatchTimestamp,
        sourceOrderRequestId: `${dispatch.sourceOrderRequestId || dispatch.orderRequestId || ''}`.trim(),
        sourceOrderRequestRowKey: `${dispatch.sourceOrderRequestRowKey || dispatch.orderRequestRowKey || dispatch.requestRowKey || ''}`.trim(),
        aliasKeys: lineKeyVariants,
        quantityByUnit: dispatchQuantityByUnit
      };
      lineKeyVariants.forEach(lineKey => {
        const current = dispatchedLineMap.get(lineKey) || { dispatchLines: [] };
        current.dispatchLines.push(dispatchLine);
        dispatchedLineMap.set(lineKey, current);
      });
    });

  const lines = Array.from(requestedLineMap.values()).map(line => {
    const requestLinesSorted = (line.requestLines || [])
      .slice()
      .sort((a, b) => (a.requestTimestamp || 0) - (b.requestTimestamp || 0) || (a.itemIndex || 0) - (b.itemIndex || 0));
    const dispatchLineCandidateMap = new Map();
    (line.aliasKeys || [line.key]).forEach(aliasKey => {
      const dispatched = dispatchedLineMap.get(aliasKey);
      (dispatched?.dispatchLines || []).forEach((dispatchLine, index) => {
        const candidateKey = dispatchLine.dispatchId
          || [
            aliasKey,
            dispatchLine.dispatchDate || '',
            dispatchLine.sourceOrderRequestId || '',
            dispatchLine.sourceOrderRequestRowKey || '',
            index
          ].join('__');
        if (!dispatchLineCandidateMap.has(candidateKey)) {
          dispatchLineCandidateMap.set(candidateKey, dispatchLine);
        }
      });
    });
    const dispatchLinesSorted = Array.from(dispatchLineCandidateMap.values())
      .slice()
      .sort((a, b) => (a.dispatchTimestamp || 0) - (b.dispatchTimestamp || 0));
    const dispatchedQuantityByUnit = dispatchLinesSorted.reduce((acc, dispatchLine) => {
      Object.entries(dispatchLine.quantityByUnit || {}).forEach(([unit, value]) => {
        addWarehouseShortageQuantity(acc, unit, value);
      });
      return acc;
    }, {});
    const dispatchedKg = getWarehouseShortageQuantityValue(dispatchedQuantityByUnit, 'Kg');
    const buildRequestMatchKey = (requestLine, index) => [
      requestLine.requestId || 'request',
      requestLine.rowKey || requestLine.productId || 'line',
      index
    ].join('__');
    const coveredRequestLineKeys = new Set(requestLinesSorted
      .map((requestLine, index) => {
        const requestTimestamp = requestLine.requestTimestamp || 0;
        const hasMatchingDispatchAfterRequest = dispatchLinesSorted.some(dispatchLine => {
          const dispatchTimestamp = dispatchLine.dispatchTimestamp || 0;
          return !(requestTimestamp && dispatchTimestamp && requestTimestamp > dispatchTimestamp);
        });
        return hasMatchingDispatchAfterRequest ? buildRequestMatchKey(requestLine, index) : '';
      })
      .filter(Boolean));

    const requestLineStatuses = requestLinesSorted.map((requestLine, index) => {
      const matchKey = buildRequestMatchKey(requestLine, index);
      const matchedDispatchLines = dispatchLinesSorted.filter(dispatchLine => {
        const dispatchTimestamp = dispatchLine.dispatchTimestamp || 0;
        const requestTimestamp = requestLine.requestTimestamp || 0;
        return !(requestTimestamp && dispatchTimestamp && requestTimestamp > dispatchTimestamp);
      });
      const latestDispatchLine = matchedDispatchLines
        .slice()
        .sort((a, b) => (b.dispatchTimestamp || 0) - (a.dispatchTimestamp || 0))[0] || null;
      return {
        ...requestLine,
        status: coveredRequestLineKeys.has(matchKey) ? 'dispatched' : 'missing',
        dispatchedAt: latestDispatchLine?.dispatchTimestamp || 0,
        dispatchedDate: latestDispatchLine?.dispatchDate || '',
        dispatchIds: matchedDispatchLines.map(dispatchLine => dispatchLine.dispatchId).filter(Boolean)
      };
    });

    const missingRequestLines = requestLineStatuses.filter(requestLine => requestLine.status !== 'dispatched');
    const latestMissingTimestamp = Math.max(...missingRequestLines.map(requestLine => requestLine.requestTimestamp || 0), 0);
    const remainingQuantityByUnit = missingRequestLines.reduce((acc, requestLine) => {
      if (requestLine.quantity > 0) addWarehouseShortageQuantity(acc, requestLine.quantityUnit || 'Đơn vị', requestLine.quantity);
      return acc;
    }, {});
    const remainingKg = getWarehouseShortageQuantityValue(remainingQuantityByUnit, 'Kg');
    const isMissing = missingRequestLines.length > 0;
    return {
      ...line,
      allRequestLines: line.requestLines || [],
      requestLineStatuses,
      requestLines: missingRequestLines,
      requestCount: missingRequestLines.length,
      requestedLabel: formatWarehouseShortageQuantityLabel(line.quantityByUnit),
      latestMissingTimestamp,
      dispatchedLineCount: dispatchLinesSorted.length,
      dispatchedKg,
      dispatchedQuantityByUnit,
      remainingQuantityByUnit,
      remainingLabel: formatWarehouseShortageQuantityLabel(remainingQuantityByUnit),
      remainingKg,
      status: isMissing ? 'missing' : 'done'
    };
  });

  const issueLines = lines
    .filter(line => line.status !== 'done')
    .sort((a, b) => {
      const statusScore = (status) => (status === 'missing' ? 0 : 1);
      return statusScore(a.status) - statusScore(b.status)
        || (b.latestMissingTimestamp || 0) - (a.latestMissingTimestamp || 0)
        || a.customerName.localeCompare(b.customerName, 'vi')
        || (a.productShortName || a.productName).localeCompare(b.productShortName || b.productName, 'vi');
    });

  return {
    dateKey: normalizedDateKey,
    dispatchDateKey: normalizedDispatchDateKey,
    fromDateKey: normalizedFromDateKey,
    includePreviousOpenOrders: shouldUseBacklog,
    totalRequiredLines: lines.length,
    coveredLines: lines.filter(line => line.status === 'done').length,
    missingLines: issueLines.filter(line => line.status === 'missing'),
    partialLines: issueLines.filter(line => line.status === 'partial'),
    issueLines,
    requestLineStatuses: lines.flatMap(line => line.requestLineStatuses || []),
    latestTimestamp: Math.max(...lines.map(line => line.latestTimestamp || 0), 0)
  };
};

const buildTimeBucketSeries = (items = [], valueGetter = (item) => item?.amount || 0) => {
  const buckets = REPORT_TIME_BUCKETS.map(label => ({ label, value: 0 }));
  const unresolved = [];
  const sortedItems = [...items].sort((a, b) => {
    const aStamp = getEntityTimestamp(a) || new Date(`${a?.date || getTodayString()}T12:00:00`).getTime();
    const bStamp = getEntityTimestamp(b) || new Date(`${b?.date || getTodayString()}T12:00:00`).getTime();
    return aStamp - bStamp;
  });

  sortedItems.forEach(item => {
    const timestamp = getEntityTimestamp(item);
    if (timestamp) {
      const date = new Date(timestamp);
      const hour = date.getHours();
      const bucketIndex = Math.max(0, Math.min(REPORT_TIME_BUCKETS.length - 1, Math.floor(hour / 3)));
      buckets[bucketIndex].value += valueGetter(item) || 0;
      return;
    }

    unresolved.push(item);
  });

  if (unresolved.length > 0) {
    unresolved.forEach((item, index) => {
      const bucketIndex = unresolved.length === 1
        ? Math.floor(REPORT_TIME_BUCKETS.length / 2)
        : Math.round((index / (unresolved.length - 1)) * (REPORT_TIME_BUCKETS.length - 1));
      buckets[bucketIndex].value += valueGetter(item) || 0;
    });
  }

  return buckets;
};

const buildLedgerSnapshot = (customers = [], orders = [], payments = [], targetDate = getTodayString()) => {
  const filteredOrders = orders.filter(order => !order.isArchived && (order.date || '') <= targetDate);
  const filteredPayments = payments.filter(payment => !payment.isArchived && (getPaymentDateKey(payment) || payment.date || '') <= targetDate);
  const customerLedgerMap = {};
  const orderLedgerMap = {};

  customers.forEach(customer => {
    const ledger = buildCustomerLedger(customer, filteredOrders, filteredPayments);
    customerLedgerMap[customer.id] = ledger;
    ledger.orders.forEach(order => {
      orderLedgerMap[order.id] = order;
    });
  });

  return { customerLedgerMap, orderLedgerMap };
};

const normalizeCustomerOpeningDebtAmount = (value) => Math.max(0, roundMoneyValue(parseLooseMoneyValue(value)));
const normalizeCustomerOpeningPayableAmount = (value) => Math.max(0, roundMoneyValue(parseLooseMoneyValue(value)));

const getCustomerOpeningDebtAmount = (customer = {}) => normalizeCustomerOpeningDebtAmount(
  customer?.openingDebtAmount
    ?? customer?.oldDebtAmount
    ?? customer?.legacyDebtAmount
    ?? 0
);

const getCustomerOpeningDebtDate = (customer = {}) => {
  const rawDate = customer?.openingDebtDate || customer?.oldDebtDate || customer?.legacyDebtDate || customer?.createdAt || '';
  if (typeof rawDate === 'string' && rawDate.trim()) return rawDate.trim().slice(0, 10);
  return getTodayString();
};

const getCustomerOpeningPayableAmount = (customer = {}) => normalizeCustomerOpeningPayableAmount(
  customer?.openingPayableAmount
    ?? customer?.oldPayableAmount
    ?? customer?.legacyPayableAmount
    ?? customer?.companyOpeningDebtAmount
    ?? customer?.companyOldDebtAmount
    ?? 0
);

const getCustomerOpeningPayableDate = (customer = {}) => {
  const rawDate = customer?.openingPayableDate
    || customer?.oldPayableDate
    || customer?.legacyPayableDate
    || customer?.companyOpeningDebtDate
    || customer?.createdAt
    || '';
  if (typeof rawDate === 'string' && rawDate.trim()) return rawDate.trim().slice(0, 10);
  return getTodayString();
};

const buildCustomerOpeningDebtOrder = (customer = null) => {
  if (!customer?.id) return null;
  const amount = getCustomerOpeningDebtAmount(customer);
  if (amount <= 0) return null;
  const date = getCustomerOpeningDebtDate(customer);

  return {
    id: `opening_debt_${customer.id}`,
    code: 'Nợ cũ',
    orderCode: 'Nợ cũ',
    customerId: customer.id,
    customerName: getCustomerDisplayName(customer) || customer.name || '',
    date,
    createdAt: customer.openingDebtCreatedAt || date,
    amount,
    totalAmount: amount,
    paidAmount: 0,
    appliedAmount: 0,
    creditApplied: 0,
    outstandingAmount: amount,
    allocations: [],
    items: [{ description: 'Nợ cũ', productName: 'Nợ cũ', quantity: 1, unitPrice: amount, total: amount }],
    note: customer.openingDebtNote || 'Nợ cũ trước khi sử dụng hệ thống',
    isOpeningDebt: true,
    sourceType: 'opening_debt'
  };
};

const buildCustomerLedger = (customerOrId, allOrders = [], allPayments = []) => {
  const customerRecord = typeof customerOrId === 'object' && customerOrId !== null ? customerOrId : null;
  const customerId = customerRecord?.id || customerOrId || '';
  const openingDebtOrder = buildCustomerOpeningDebtOrder(customerRecord);
  const orders = [
    ...(openingDebtOrder ? [openingDebtOrder] : []),
    ...allOrders
    .filter(order => order.customerId === customerId && !order.isArchived)
    .map(order => ({
      ...order,
      appliedAmount: 0,
      creditApplied: 0,
      outstandingAmount: Math.max(0, order.amount || 0),
      allocations: []
    }))
  ]
    .sort(compareLedgerItems);

  const payments = allPayments
    .filter(payment => payment.customerId === customerId && !payment.isArchived && isCashflowOfficial(payment))
    .map(payment => ({
      ...payment,
      appliedAmount: 0,
      overpaidAmount: 0,
      allocations: []
    }))
    .sort(compareLedgerItems);

  const timeline = [
    ...orders.map(order => ({ type: 'order', date: order.date, id: `order_${order.id}`, ref: order })),
    ...payments.map(payment => ({ type: 'payment', date: getPaymentDateKey(payment) || payment.date, id: `payment_${payment.id}`, ref: payment }))
  ].sort((a, b) => {
    const baseCompare = compareLedgerItems(a, b);
    if (baseCompare !== 0) return baseCompare;
    if (a.type === b.type) return 0;
    return a.type === 'order' ? -1 : 1;
  });

  const openOrders = [];
  let customerCredit = 0;

  timeline.forEach(item => {
    if (item.type === 'order') {
      const order = item.ref;
      if (customerCredit > 0) {
        const covered = Math.min(customerCredit, order.outstandingAmount);
        order.appliedAmount += covered;
        order.creditApplied += covered;
        order.outstandingAmount -= covered;
        customerCredit -= covered;
      }

      if (order.outstandingAmount > 0) {
        openOrders.push(order);
      }
      return;
    }

    const payment = item.ref;
    let remaining = Math.max(0, payment.amount || 0);
    const shouldPrioritizeMatchedOrder = payment.matchedOrderId
      && !payment.allocateOldestFirst
      && payment.allocationMode !== 'oldest_first';
    const prioritizedOrder = shouldPrioritizeMatchedOrder
      ? orders.find(order => order.id === payment.matchedOrderId)
      : null;

    if (prioritizedOrder && prioritizedOrder.outstandingAmount > 0 && remaining > 0) {
      const prioritizedAmount = Math.min(prioritizedOrder.outstandingAmount, remaining);
      prioritizedOrder.outstandingAmount -= prioritizedAmount;
      prioritizedOrder.appliedAmount += prioritizedAmount;
      prioritizedOrder.allocations.push({ paymentId: payment.id, amount: prioritizedAmount, date: getPaymentDateKey(payment) || payment.date, matchType: 'order_code' });
      payment.appliedAmount += prioritizedAmount;
      payment.allocations.push({ orderId: prioritizedOrder.id, amount: prioritizedAmount, date: prioritizedOrder.date, matchType: 'order_code' });
      remaining -= prioritizedAmount;
    }

    for (const order of openOrders) {
      if (remaining <= 0) break;
      if (prioritizedOrder && order.id === prioritizedOrder.id) continue;
      if (order.outstandingAmount <= 0) continue;

      const applied = Math.min(order.outstandingAmount, remaining);
      order.outstandingAmount -= applied;
      order.appliedAmount += applied;
      order.allocations.push({ paymentId: payment.id, amount: applied, date: getPaymentDateKey(payment) || payment.date });
      payment.appliedAmount += applied;
      payment.allocations.push({ orderId: order.id, amount: applied, date: order.date });
      remaining -= applied;
    }

    if (remaining > 0) {
      payment.overpaidAmount = remaining;
      customerCredit += remaining;
    }
  });

  const orderDetails = orders.map(order => ({
    ...order,
    outstandingAmount: Math.max(0, order.outstandingAmount),
    status: order.outstandingAmount <= 0 ? 'paid' : order.appliedAmount > 0 ? 'partial' : 'unpaid'
  }));

  const totalRevenue = orderDetails.reduce((sum, order) => sum + (order.isOpeningDebt ? 0 : (order.amount || 0)), 0);
  const totalPaid = payments.reduce((sum, payment) => sum + (payment.amount || 0), 0);
  const currentDebt = orderDetails.reduce((sum, order) => sum + (order.outstandingAmount || 0), 0);

  return {
    orders: orderDetails,
    payments,
    totalRevenue,
    totalPaid,
    currentDebt,
    creditBalance: Math.max(0, customerCredit)
  };
};

const buildCustomerSupplierPurchaseLedger = (customerOrId, warehouseImports = []) => {
  const customerRecord = typeof customerOrId === 'object' && customerOrId !== null ? customerOrId : null;
  const customerId = `${customerRecord?.id || (typeof customerOrId === 'string' ? customerOrId : '') || ''}`.trim();
  const customerPhone = normalizeCustomerPhone(customerRecord?.phone || customerRecord?.phoneNumber || '');
  const customerNameKey = normalizeLookupText(getCustomerDisplayName(customerRecord) || customerRecord?.name || '');
  const openingPayableAmount = getCustomerOpeningPayableAmount(customerRecord || {});
  const openingPayableDate = getCustomerOpeningPayableDate(customerRecord || {});
  const openingPayableNote = `${customerRecord?.openingPayableNote || customerRecord?.oldPayableNote || customerRecord?.companyOpeningDebtNote || ''}`.trim();
  const imports = (Array.isArray(warehouseImports) ? warehouseImports : [])
    .filter(item => item && !item.isArchived)
    .filter(item => {
      const supplierCustomerId = `${item.supplierCustomerId || item.linkedCustomerId || item.customerId || ''}`.trim();
      if (customerId && supplierCustomerId && supplierCustomerId === customerId) return true;

      const supplierPhone = normalizeCustomerPhone(item.supplierPhone || item.phone || item.customerPhone || '');
      if (customerPhone && supplierPhone && supplierPhone === customerPhone) return true;

      const supplierNameKey = normalizeLookupText(item.supplier || item.supplierName || item.customerName || item.customerNameSnapshot || '');
      return Boolean(customerNameKey && supplierNameKey && supplierNameKey === customerNameKey);
    })
    .map(item => {
      const totalKg = parseLooseQuantityValue(item.totalKg ?? item.weightKg ?? item.kg);
      const unitPrice = parseLooseMoneyValue(item.unitPrice ?? item.price);
      const rawAmount = parseLooseMoneyValue(item.amount ?? item.totalAmount ?? item.value ?? item.total);
      const amount = roundMoneyValue(rawAmount || (totalKg > 0 && unitPrice > 0 ? totalKg * unitPrice : 0));
      return { ...item, amount };
    })
    .filter(item => item.amount > 0)
    .sort(compareLedgerItems);
  const purchaseImportAmount = roundMoneyValue(imports.reduce((sum, item) => sum + parseLooseMoneyValue(item.amount), 0));
  const totalPurchaseDebt = roundMoneyValue(openingPayableAmount + purchaseImportAmount);
  return {
    imports,
    purchaseImportAmount,
    openingPayableAmount,
    openingPayableDate,
    openingPayableNote,
    hasOpeningPayable: openingPayableAmount > 0,
    totalPurchaseDebt
  };
};

const applyCustomerSupplierReconciliation = (ledger = {}, purchaseLedger = {}) => {
  const salesDebtBeforeReconcile = Math.max(0, roundMoneyValue(parseLooseMoneyValue(ledger.currentDebt)));
  const customerCreditBeforeReconcile = Math.max(0, roundMoneyValue(parseLooseMoneyValue(ledger.creditBalance)));
  const purchaseDebt = Math.max(0, roundMoneyValue(parseLooseMoneyValue(purchaseLedger.totalPurchaseDebt)));
  const companyOwesBeforeReconcile = roundMoneyValue(customerCreditBeforeReconcile + purchaseDebt);
  const reconciliationOffset = roundMoneyValue(Math.min(salesDebtBeforeReconcile, companyOwesBeforeReconcile));
  const currentDebt = Math.max(0, roundMoneyValue(salesDebtBeforeReconcile - companyOwesBeforeReconcile));
  const creditBalance = Math.max(0, roundMoneyValue(companyOwesBeforeReconcile - salesDebtBeforeReconcile));

  return {
    ...ledger,
    currentDebt,
    creditBalance,
    hasPurchaseReconciliation: (purchaseLedger.imports || []).length > 0 || purchaseDebt > 0,
    salesDebtBeforeReconcile,
    customerCreditBeforeReconcile,
    openingPayableAmount: purchaseLedger.openingPayableAmount || 0,
    openingPayableDate: purchaseLedger.openingPayableDate || '',
    openingPayableNote: purchaseLedger.openingPayableNote || '',
    purchaseImportAmount: purchaseLedger.purchaseImportAmount || 0,
    purchaseDebt,
    purchaseImports: purchaseLedger.imports || [],
    companyOwesBeforeReconcile,
    reconciliationOffset,
    reconciliationNetAmount: currentDebt || creditBalance,
    reconciliationStatus: currentDebt > 0
      ? 'customer_owes_company'
      : creditBalance > 0
        ? 'company_owes_customer'
        : 'balanced'
  };
};

const buildCustomerReconciledLedger = (customerOrId, allOrders = [], allPayments = [], warehouseImports = []) => {
  const ledger = buildCustomerLedger(customerOrId, allOrders, allPayments);
  const purchaseLedger = buildCustomerSupplierPurchaseLedger(customerOrId, warehouseImports);
  return applyCustomerSupplierReconciliation(ledger, purchaseLedger);
};

const getCustomerDebt = (customerOrId, allOrders, allPayments, warehouseImports = []) => buildCustomerReconciledLedger(customerOrId, allOrders, allPayments, warehouseImports).currentDebt;
const getCustomerCredit = (customerOrId, allOrders, allPayments, warehouseImports = []) => buildCustomerReconciledLedger(customerOrId, allOrders, allPayments, warehouseImports).creditBalance;

const normalizeCustomerDebtLimitAmount = (value) => Math.max(0, roundMoneyValue(parseLooseMoneyValue(value)));

const getCustomerDebtLimitConfig = (customer = {}) => {
  const rawMode = `${customer?.debtLimitMode || customer?.creditLimitMode || ''}`.trim();
  const legacyLimit = customer?.debtLimitAmount ?? customer?.creditLimit ?? customer?.maxDebtAmount;
  const limitAmount = normalizeCustomerDebtLimitAmount(legacyLimit);

  if (rawMode === 'no_debt' || customer?.allowDebt === false) {
    return { mode: 'no_debt', limitAmount: 0 };
  }

  if (rawMode === 'limited' || (limitAmount > 0 && rawMode !== 'unlimited')) {
    return { mode: 'limited', limitAmount };
  }

  if (rawMode === 'unlimited') {
    return { mode: 'unlimited', limitAmount: 0 };
  }

  return { mode: 'no_debt', limitAmount: 0 };
};

const buildCustomerDebtLimitStatus = (customer = {}, ledgerOrDebt = null) => {
  const config = getCustomerDebtLimitConfig(customer);
  const currentDebt = typeof ledgerOrDebt === 'number'
    ? Math.max(0, roundMoneyValue(ledgerOrDebt))
    : Math.max(0, roundMoneyValue(ledgerOrDebt?.currentDebt ?? customer?.currentDebt ?? 0));

  if (config.mode === 'unlimited') {
    return {
      mode: config.mode,
      enabled: false,
      limitAmount: 0,
      currentDebt,
      exceeded: false,
      overAmount: 0,
      remainingAmount: null,
      isNoDebt: false,
      label: 'Không giới hạn',
      shortLabel: 'Không giới hạn',
      message: 'Khách hàng chưa cài hạn mức công nợ.',
      actionLabel: '',
      tone: 'slate'
    };
  }

  const limitAmount = config.mode === 'no_debt' ? 0 : config.limitAmount;
  const exceeded = currentDebt > limitAmount;
  const overAmount = Math.max(0, currentDebt - limitAmount);
  const remainingAmount = Math.max(0, limitAmount - currentDebt);
  const isNoDebt = config.mode === 'no_debt';

  return {
    mode: config.mode,
    enabled: true,
    limitAmount,
    currentDebt,
    exceeded,
    overAmount,
    remainingAmount,
    isNoDebt,
    label: isNoDebt ? 'Không cho nợ' : `Cho nợ tối đa ${formatCurrency(limitAmount)} đ`,
    shortLabel: isNoDebt ? 'Không nợ' : `HM ${formatCurrency(limitAmount)} đ`,
    message: exceeded
      ? (isNoDebt
        ? `Khách này không được nợ nhưng hiện còn ${formatCurrency(currentDebt)} đ. Cần nhắc thu nợ hoặc tạm ngưng bán hàng.`
        : `Công nợ đã vượt ${formatCurrency(overAmount)} đ so với hạn mức ${formatCurrency(limitAmount)} đ. Cần nhắc nợ, thu nợ hoặc tạm ngưng bán thêm.`)
      : (isNoDebt
        ? 'Khách này đang đúng chính sách không cho nợ.'
        : `Còn có thể cho nợ thêm ${formatCurrency(remainingAmount)} đ trong hạn mức.`),
    actionLabel: exceeded ? 'Nhắc nợ / tạm ngưng bán' : 'Trong hạn mức',
    tone: exceeded ? 'rose' : 'emerald'
  };
};

const shouldCollectCustomerDebtImmediately = (debtLimitStatus = {}) => (
  Boolean(debtLimitStatus?.enabled && (debtLimitStatus.isNoDebt || debtLimitStatus.exceeded))
);

const DEFAULT_CUSTOMER_LOYALTY_SETTINGS = {
  enabled: false,
  earnAmountPerPoint: 100000,
  redeemValuePerPoint: 1000
};

const getCustomerLoyaltySettings = (company = null) => {
  const earnAmountPerPoint = parseInt(company?.loyaltyEarnAmountPerPoint, 10);
  const redeemValuePerPoint = parseInt(company?.loyaltyRedeemValuePerPoint, 10);

  return {
    enabled: company?.customerLoyaltyEnabled === true,
    earnAmountPerPoint: earnAmountPerPoint > 0 ? earnAmountPerPoint : DEFAULT_CUSTOMER_LOYALTY_SETTINGS.earnAmountPerPoint,
    redeemValuePerPoint: redeemValuePerPoint > 0 ? redeemValuePerPoint : DEFAULT_CUSTOMER_LOYALTY_SETTINGS.redeemValuePerPoint
  };
};

const getEffectiveCustomerLoyaltySettings = (customer = {}, company = null) => {
  const companySettings = getCustomerLoyaltySettings(company);
  const rawOverride = customer?.customerLoyaltyEnabledOverride ?? customer?.loyaltyEnabledOverride ?? null;
  const customerOverrideEnabled = rawOverride === true || rawOverride === 'enabled' || rawOverride === 'true';
  const customerOverrideDisabled = rawOverride === false || rawOverride === 'disabled' || rawOverride === 'false';
  return {
    ...companySettings,
    enabled: customerOverrideEnabled ? true : customerOverrideDisabled ? false : companySettings.enabled,
    companyEnabled: companySettings.enabled,
    customerOverrideEnabled,
    customerOverrideDisabled
  };
};

const DEFAULT_CUSTOMER_CARE_SETTINGS = {
  enabled: true,
  inactiveDays: 7
};

const getCustomerCareSettings = (company = null) => {
  const inactiveDays = parseInt(company?.customerCareInactiveDays ?? company?.customerCareReminderDays, 10);
  return {
    enabled: company?.customerCareReminderEnabled !== false,
    inactiveDays: inactiveDays > 0 ? inactiveDays : DEFAULT_CUSTOMER_CARE_SETTINGS.inactiveDays
  };
};

const getDateKeyFromAnyValue = (value = '') => {
  if (!value) return '';
  if (typeof value === 'number' && Number.isFinite(value)) return toDateInputString(new Date(value));
  if (typeof value?.toDate === 'function') {
    const parsedDate = value.toDate();
    return parsedDate instanceof Date && !Number.isNaN(parsedDate.getTime()) ? toDateInputString(parsedDate) : '';
  }
  if (typeof value === 'object') {
    const timestamp = parseEntityTimestampValue(value);
    return timestamp ? toDateInputString(new Date(timestamp)) : '';
  }
  const raw = `${value || ''}`.trim();
  const directDate = raw.match(/\d{4}-\d{2}-\d{2}/)?.[0] || '';
  if (directDate) return directDate;
  const vietnameseTimestamp = parseVietnameseDateTimeString(raw);
  if (vietnameseTimestamp) return toDateInputString(new Date(vietnameseTimestamp));
  const parsed = new Date(raw);
  return Number.isNaN(parsed.getTime()) ? '' : toDateInputString(parsed);
};

const getDaysBetweenDateKeys = (fromDate = '', toDate = getTodayString()) => {
  if (!fromDate) return 0;
  const from = parseDateInputValue(fromDate);
  const to = parseDateInputValue(toDate);
  return Math.max(0, Math.floor((to.getTime() - from.getTime()) / (24 * 60 * 60 * 1000)));
};

const buildCustomerCareReminderRows = ({
  customers = [],
  orders = [],
  employees = [],
  settings = DEFAULT_CUSTOMER_CARE_SETTINGS,
  currentDate = getTodayString(),
  isOwnerAccount = false,
  isAccounting = false,
  isSales = false,
  salesEmployeeIdSet = new Set()
} = {}) => {
  if (!settings?.enabled) return [];
  const inactiveDays = settings.inactiveDays || DEFAULT_CUSTOMER_CARE_SETTINGS.inactiveDays;
  const latestOrderByCustomerId = new Map();

  (orders || [])
    .filter(order => !order?.isArchived)
    .forEach(order => {
      const customerId = order.customerId || '';
      if (!customerId) return;
      const orderDate = getDateKeyFromAnyValue(order.date || order.createdAt || getEntityTimestamp(order));
      if (!orderDate) return;
      const currentLatest = latestOrderByCustomerId.get(customerId);
      if (!currentLatest || orderDate > currentLatest.date) {
        latestOrderByCustomerId.set(customerId, { date: orderDate, order });
      }
    });

  return (customers || [])
    .filter(customer => !customer?.isArchived)
    .filter(customer => {
      if (isOwnerAccount || isAccounting) return true;
      if (isSales) return salesEmployeeIdSet.has(customer.empId);
      return false;
    })
    .map(customer => {
      const latest = latestOrderByCustomerId.get(customer.id) || null;
      const createdDate = getDateKeyFromAnyValue(customer.createdAt || customer.date || customer.createdDate || customer.updatedAt || getEntityTimestamp(customer));
      const referenceDate = latest?.date || createdDate;
      if (!referenceDate) return null;
      const daysWithoutOrder = getDaysBetweenDateKeys(referenceDate, currentDate);
      if (daysWithoutOrder < inactiveDays) return null;
      const manager = employees.find(item => item.id === customer.empId);
      return {
        customer,
        manager,
        lastOrderDate: latest?.date || '',
        daysWithoutOrder,
        inactiveDays,
        hasAnyOrder: Boolean(latest)
      };
    })
    .filter(Boolean)
    .sort((a, b) => b.daysWithoutOrder - a.daysWithoutOrder);
};

const calculateCustomerLoyaltySummary = ({ customer = {}, ledger = null, company = null, pointsRecord = null } = {}) => {
  const loyaltySettings = getEffectiveCustomerLoyaltySettings(customer, company);
  const eligibleAmount = Math.max(0, roundMoneyValue(
    pointsRecord?.eligible_amount
    ?? pointsRecord?.eligibleAmount
    ?? ledger?.totalPaid
    ?? customer?.totalPaid
    ?? 0
  ));
  const manualBonusPoints = Math.max(0, Math.floor(parseLooseMoneyValue(
    pointsRecord?.bonus_points
    ?? pointsRecord?.bonusPoints
    ?? customer?.bonusLoyaltyPoints
    ?? 0
  )));
  const usedPoints = Math.max(0, Math.floor(parseLooseMoneyValue(
    pointsRecord?.used_points
    ?? pointsRecord?.usedPoints
    ?? customer?.usedLoyaltyPoints
    ?? 0
  )));
  const computedEarnedPoints = loyaltySettings.enabled ? Math.floor(eligibleAmount / loyaltySettings.earnAmountPerPoint) : 0;
  const earnedPoints = Math.max(0, Math.floor(parseLooseMoneyValue(
    pointsRecord?.earned_points
    ?? pointsRecord?.earnedPoints
    ?? computedEarnedPoints
  )));
  const computedCurrentPoints = Math.max(0, earnedPoints + manualBonusPoints - usedPoints);
  const currentPoints = Math.max(0, Math.floor(parseLooseMoneyValue(
    pointsRecord?.available_points
    ?? pointsRecord?.availablePoints
    ?? pointsRecord?.available
    ?? pointsRecord?.total_points
    ?? pointsRecord?.totalPoints
    ?? computedCurrentPoints
  )));

  return {
    ...loyaltySettings,
    eligibleAmount,
    earnedPoints,
    manualBonusPoints,
    usedPoints,
    currentPoints,
    cloudSynced: Boolean(pointsRecord),
    updatedAt: pointsRecord?.updatedAt || pointsRecord?.lastSyncedAt || '',
    redeemValue: roundMoneyValue(currentPoints * loyaltySettings.redeemValuePerPoint)
  };
};

const isPayosPaymentRecord = (payment = {}) => {
  const providerText = `${payment.paymentProvider || payment.sourceType || payment.method || payment.paymentMethod || payment.sourceLabel || ''}`.toLowerCase();
  return providerText.includes('sepay') || providerText.includes('payos');
};

const getPaymentReceivingBankLabel = (payment = {}) => {
  const payosTechnicalLabels = new Set(['sepay', 'sepay webhook', 'sepay sync', 'sepay_webhook', 'sepay_sync', 'sepay tu dong', 'sepay tự động', 'payos', 'payos webhook', 'payos sync', 'payos_webhook', 'payos_sync', 'payos tu dong', 'payos tự động']);
  const candidates = [
    payment.receivingBankName,
    payment.bankName,
    payment.receivingBankCode,
    payment.bankCode,
    payment.bankId,
    payment.sourceLabel,
    payment.method,
    payment.paymentMethod
  ];

  for (const candidate of candidates) {
    const text = `${candidate || ''}`.trim();
    if (!text) continue;
    const lookup = text.toLowerCase();
    if (payosTechnicalLabels.has(lookup)) continue;
    if (lookup.includes('webhook') || lookup.includes('sync')) continue;
    if (lookup.includes('bidv') || lookup === '970418') return 'BIDV';
    return text;
  }

  return isPayosPaymentRecord(payment) ? (DEFAULT_INVOICE_TRANSFER_PROFILE.bankName || DEFAULT_INVOICE_TRANSFER_PROFILE.bankId || 'Ngân hàng') : '';
};

const getPaymentMethodLabel = (payment = {}) => (
  isPayosPaymentRecord(payment)
    ? 'SePay tự động'
    : (payment.method || payment.paymentMethod || 'Tiền mặt')
);
const getPaymentSourceLabel = (payment = {}) => (
  isPayosPaymentRecord(payment)
    ? (getPaymentReceivingBankLabel(payment) || 'Ngân hàng')
    : (payment.sourceLabel || payment.sourceType || 'Thu công nợ')
);

const getPaymentRawPayosData = (payment = {}) => {
  const rawWebhook = payment.rawWebhook || payment.rawPayload || {};
  const data = rawWebhook?.data || {};
  const paymentLink = rawWebhook?.paymentLink || data?.paymentLink || {};
  const latestTransaction = rawWebhook?.latestTransaction || data?.latestTransaction || {};
  const transactions = Array.isArray(paymentLink?.transactions) ? paymentLink.transactions : [];
  const latestLinkedTransaction = transactions
    .slice()
    .sort((a, b) => `${b?.transactionDateTime || b?.transactionDate || b?.createdAt || ''}`.localeCompare(`${a?.transactionDateTime || a?.transactionDate || a?.createdAt || ''}`))[0] || {};

  return {
    rawWebhook,
    data,
    paymentLink,
    latestTransaction,
    latestLinkedTransaction
  };
};

const getPaymentDateCandidates = (payment = {}) => {
  const { rawWebhook, data, paymentLink, latestTransaction, latestLinkedTransaction } = getPaymentRawPayosData(payment);
  return [
    payment.paymentDate,
    payment.transactionDate,
    payment.transactionDateTime,
    payment.bankTransactionDate,
    data.transactionDateTime,
    data.transactionDate,
    data.paymentTime,
    data.completedTime,
    data.paidAt,
    latestTransaction.transactionDateTime,
    latestTransaction.transactionDate,
    latestTransaction.paymentTime,
    latestTransaction.completedTime,
    latestTransaction.paidAt,
    latestTransaction.createdAt,
    latestLinkedTransaction.transactionDateTime,
    latestLinkedTransaction.transactionDate,
    latestLinkedTransaction.paymentTime,
    latestLinkedTransaction.completedTime,
    latestLinkedTransaction.paidAt,
    latestLinkedTransaction.createdAt,
    paymentLink.transactionDateTime,
    paymentLink.transactionDate,
    paymentLink.paymentTime,
    paymentLink.completedTime,
    paymentLink.paidAt,
    paymentLink.createdAt,
    rawWebhook.transactionDateTime,
    rawWebhook.transactionDate,
    rawWebhook.paymentTime,
    rawWebhook.completedTime,
    rawWebhook.paidAt,
    payment.paidAt,
    payment.transactionAt,
    payment.transactedAt,
    payment.paymentTime,
    payment.completedTime,
    payment.completedAt,
    data.createdAt,
    rawWebhook.createdAt,
    payment.date,
    payment.createdAt,
    payment.updatedAt,
    getEntityTimestamp(payment)
  ];
};

const getPaymentDateSource = (payment = {}) => (
  getPaymentDateCandidates(payment).find(candidate => getDateKeyFromAnyValue(candidate)) || ''
);

const getPaymentDateKey = (payment = {}) => getDateKeyFromAnyValue(getPaymentDateSource(payment));

const getPaymentTimestamp = (payment = {}) => (
  parseEntityTimestampValue(getPaymentDateSource(payment))
    || getEntityTimestamp(payment)
    || (getPaymentDateKey(payment) ? new Date(`${getPaymentDateKey(payment)}T12:00:00`).getTime() : 0)
);

const getPaymentCollectorLabel = (payment = {}, employees = []) => {
  const collectorId = payment.collectorEmpId || payment.collectedByEmpId || payment.empId || payment.createdByEmpId || '';
  const collector = employees.find(emp => emp.id === collectorId);
  return payment.collectorName
    || payment.collectedByName
    || collector?.name
    || collector?.displayName
    || payment.employeeName
    || '';
};

const getOrderSalesEmpId = (order, customers = []) => {
  const customer = customers.find(c => c.id === order?.customerId);
  return order?.salesEmpId || customer?.empId || order?.createdByEmpId || order?.empId || null;
};

const calculateRevenueForMonth = (empId, orders, customers = [], monthKey = getTodayString().substring(0, 7)) => {
  return orders
    .filter(o => getOrderSalesEmpId(o, customers) === empId && (o.date || '').startsWith(monthKey) && !o.isArchived)
    .reduce((sum, o) => sum + (o.amount||0), 0);
};

const calculateMonthRevenue = (empId, orders, customers = []) => {
  const currentMonth = getTodayString().substring(0, 7);
  return calculateRevenueForMonth(empId, orders, customers, currentMonth);
};

