function SmartAIAssistant({ employee, company, activeTab, customers, orders, expenses, employees = [], attendance = {}, holidays = [], products = [] }) {
  const hasCloudAi = Boolean(GEMINI_API_KEY);
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([{ role: 'model', text: `Chào ${employee?.name || 'bạn'}! Mình là Trợ lý AI của công ty. Bạn cần hỗ trợ phân tích số liệu, hướng dẫn sử dụng app hay tư vấn công việc hôm nay?` }]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSend = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const newMessages = [...messages, { role: 'user', text: capitalizeFirst(input) }];
    setMessages(newMessages);
    setInput('');
    setIsLoading(true);

    const todaysOrders = orders.filter(o => o.date === getTodayString() && !o.isArchived);
    const revenueToday = todaysOrders.reduce((s, o) => s + (o.amount || 0), 0);
    const contextStr = `Bạn là Trợ lý AI thông minh của công ty ${company?.name || 'HD'}.
Người dùng hiện tại: ${employee?.name || 'Chưa rõ'}.
Vai trò hiện tại: ${getEmployeePositionLabel(employee?.position) || 'Chưa rõ'}.
Màn hình đang thao tác: ${activeTab}.
Doanh thu hôm nay: ${new Intl.NumberFormat('vi-VN').format(revenueToday)} VNĐ.
Đơn hàng hôm nay: ${todaysOrders.length}.
Tổng số khách hàng đang có: ${customers.length}.
Hãy trả lời ngắn gọn, hữu ích, đúng nghiệp vụ, ưu tiên hướng dẫn thao tác thực tế trong ứng dụng này.`;

    if (!hasCloudAi) {
      await new Promise(resolve => setTimeout(resolve, 350));
      setMessages([
        ...newMessages,
        {
          role: 'model',
          text: buildLocalAssistantReply({ input, activeTab, employee, company, customers, orders, expenses, employees, attendance, holidays, products, warehouseImports })
        }
      ]);
      setIsLoading(false);
      return;
    }

    const url = buildGeminiGenerateUrl();
    
    const payload = {
      contents: newMessages.map(m => ({ role: m.role === 'model' ? 'model' : 'user', parts: [{ text: m.text }] })),
      systemInstruction: { parts: [{ text: contextStr }] }
    };

    const delays = [1000, 2000, 4000, 8000, 16000];
    let attempt = 0;
    let aiResponseText = "Xin lỗi, hệ thống AI đang bận xử lý. Vui lòng thử lại sau giây lát.";

    while (attempt < 6) {
      try {
        const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        if (!res.ok) throw new Error('API Error');
        const data = await res.json();
        aiResponseText = data.candidates?.[0]?.content?.parts?.[0]?.text || "Mình chưa hiểu rõ ý bạn, hãy thử diễn đạt lại nhé.";
        break;
      } catch (err) {
        if (attempt >= 5) break;
        await new Promise(r => setTimeout(r, delays[attempt]));
        attempt++;
      }
    }

    setMessages([...newMessages, { role: 'model', text: aiResponseText }]);
    setIsLoading(false);
  };

  return (
    <>
      <div className="fixed bottom-[80px] left-3 z-50">
        <button onClick={() => setIsOpen(true)} className="bg-gradient-to-r from-emerald-500 to-teal-500 text-white p-3.5 rounded-full shadow-[0_4px_20px_rgba(16,185,129,0.5)] flex items-center justify-center hover:scale-105 transition-transform active:scale-95 border-2 border-white">
          <Sparkles size={24} className="animate-pulse" />
        </button>
      </div>

      {isOpen && (
        <div className="fixed inset-0 bg-black/50 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4 backdrop-blur-sm">
          <div className="bg-gray-50 w-full h-[85vh] sm:h-[600px] sm:max-w-md sm:rounded-2xl rounded-t-3xl shadow-2xl flex flex-col animate-in slide-in-from-bottom-full duration-300 overflow-hidden border border-gray-200">
            <div className="bg-gradient-to-r from-emerald-600 to-emerald-500 text-white p-4 flex justify-between items-center shrink-0 shadow-sm">
              <div className="flex items-center gap-3">
                <div className="bg-white/20 p-2 rounded-full shadow-inner"><Bot size={22} /></div>
                <div>
                  <h3 className="font-bold text-sm flex items-center gap-1">Trợ lý AI <span className="bg-emerald-400 text-[9px] px-1.5 py-0.5 rounded-full uppercase tracking-wider">Pro</span></h3>
        <p className="text-[10px] text-emerald-100 font-medium">{hasCloudAi ? 'Trực tuyến' : 'Demo local'} • Hỗ trợ {getEmployeePositionLabel(employee?.position)}</p>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-1.5 rounded-full transition-colors"><X size={20} /></button>
            </div>
            
            <div className="flex-1 overflow-y-auto p-4 space-y-5 flex flex-col">
              {messages.map((msg, idx) => (
                <div key={idx} className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm leading-relaxed ${msg.role === 'model' ? 'bg-white border border-gray-100 text-gray-800 self-start shadow-sm rounded-tl-sm' : 'bg-emerald-500 text-white self-end shadow-md rounded-tr-sm'}`}>
                  {msg.text}
                </div>
              ))}
              {isLoading && (
                <div className="bg-white border border-gray-100 text-gray-500 self-start shadow-sm rounded-2xl rounded-tl-sm px-4 py-3 flex items-center gap-2 text-sm font-medium">
                  <Loader2 size={16} className="animate-spin text-emerald-500" /> AI đang phân tích dữ liệu...
                </div>
              )}
            </div>

            <div className="p-3 bg-white border-t border-gray-100 shrink-0 pb-safe">
              <form onSubmit={handleSend} className="flex items-center gap-2 bg-gray-50 border border-gray-200 rounded-full p-1.5 pl-4 focus-within:border-emerald-400 focus-within:ring-2 focus-within:ring-emerald-100 transition-all">
                <input type="text" value={input} onChange={e => setInput(capitalizeFirst(e.target.value))} placeholder="Nhập câu hỏi tại đây..." className="flex-1 bg-transparent border-none outline-none text-sm text-gray-700 placeholder-gray-400" />
                <button type="submit" disabled={isLoading || !input.trim()} className="bg-emerald-500 text-white p-2.5 rounded-full hover:bg-emerald-600 disabled:opacity-50 transition-colors shadow-sm">
                  <Send size={16} className="ml-0.5" />
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

const useMobileKeyboardViewportGuard = () => {
  useEffect(() => {
    if (typeof window === 'undefined' || typeof document === 'undefined') return undefined;

    const editableSelector = 'input, textarea, select, [contenteditable="true"]';
    const isEditableElement = (target) => target instanceof Element && target.matches(editableSelector);
    const nativeRuntime = isNativeRuntime();
    const timers = new Set();
    let frameId = 0;

    const scrollFocusedInputIntoView = () => {
      window.cancelAnimationFrame(frameId);
      frameId = window.requestAnimationFrame(() => {
        const activeElement = document.activeElement;
        if (!isEditableElement(activeElement)) return;
        if (activeElement.closest('[data-keyboard-guard="off"]')) return;

        activeElement.scrollIntoView({
          behavior: nativeRuntime ? 'auto' : 'smooth',
          block: nativeRuntime ? 'nearest' : 'center',
          inline: 'nearest'
        });
      });
    };

    const scheduleScroll = (delay = 0) => {
      const timerId = window.setTimeout(() => {
        timers.delete(timerId);
        scrollFocusedInputIntoView();
      }, delay);
      timers.add(timerId);
    };

    const handleFocusIn = (event) => {
      if (!isEditableElement(event.target)) return;
      if (nativeRuntime) {
        scheduleScroll(120);
        return;
      }
      scheduleScroll(60);
      scheduleScroll(260);
      scheduleScroll(520);
    };

    const handleViewportChange = () => {
      if (nativeRuntime && !isEditableElement(document.activeElement)) return;
      scheduleScroll(nativeRuntime ? 120 : 30);
    };

    document.addEventListener('focusin', handleFocusIn, true);
    window.visualViewport?.addEventListener('resize', handleViewportChange);
    if (!nativeRuntime) {
      window.visualViewport?.addEventListener('scroll', handleViewportChange);
    }
    window.addEventListener('resize', handleViewportChange);

    return () => {
      document.removeEventListener('focusin', handleFocusIn, true);
      window.visualViewport?.removeEventListener('resize', handleViewportChange);
      if (!nativeRuntime) {
        window.visualViewport?.removeEventListener('scroll', handleViewportChange);
      }
      window.removeEventListener('resize', handleViewportChange);
      window.cancelAnimationFrame(frameId);
      timers.forEach(timerId => window.clearTimeout(timerId));
      timers.clear();
    };
  }, []);
};

const useDismissModalOnBackdropClick = () => {
  useEffect(() => {
    if (typeof document === 'undefined' || typeof HTMLElement === 'undefined') return undefined;

    const isBackdropElement = (element) => {
      if (!(element instanceof HTMLElement)) return false;
      const className = `${element.getAttribute('class') || ''}`;
      if (!className.includes('fixed') || !className.includes('inset-0')) return false;
      return /\bbg-(black|slate)-[^\s]*\/\d+/.test(className) || className.includes('backdrop-blur');
    };

    const getButtonText = (button) => normalizeLookupText([
      button.getAttribute('aria-label'),
      button.getAttribute('title'),
      button.textContent
    ].filter(Boolean).join(' '));

    const isDismissButton = (button) => {
      const buttonText = getButtonText(button);
      if (/\b(dong|close|huy|cancel)\b/.test(buttonText)) return true;
      return Boolean(button.querySelector('svg.lucide-x, svg[class*="lucide-x"], svg[class*="lucide-circle-x"]'));
    };

    const handleBackdropClick = (event) => {
      const target = event.target;
      if (!isBackdropElement(target)) return;
      const dismissButton = Array.from(target.querySelectorAll('button')).find(isDismissButton);
      if (!dismissButton) return;
      event.preventDefault();
      event.stopPropagation();
      dismissButton.click();
    };

    document.addEventListener('click', handleBackdropClick, true);
    return () => document.removeEventListener('click', handleBackdropClick, true);
  }, []);
};

const SEARCH_ZONE_SELECTOR = '[data-search-zone="true"]';

const isInsideSearchZone = (target) => {
  if (typeof Element === 'undefined' || !(target instanceof Element)) return false;
  return Boolean(target.closest(SEARCH_ZONE_SELECTOR));
};

const useDismissSearchOnOutsideClick = (isOpen, onClose) => {
  useEffect(() => {
    if (!isOpen || typeof document === 'undefined') return undefined;

    const handlePointerDown = (event) => {
      if (isInsideSearchZone(event.target)) return;
      onClose?.();
    };

    document.addEventListener('pointerdown', handlePointerDown, true);
    return () => document.removeEventListener('pointerdown', handlePointerDown, true);
  }, [isOpen, onClose]);
};

const useAutoDismissMessage = (message, setMessage, { delay = 5200, disabled = false, keepWhile = null } = {}) => {
  useEffect(() => {
    if (!message || disabled || typeof setMessage !== 'function') return undefined;
    if (typeof keepWhile === 'function' && keepWhile(message)) return undefined;

    const timerApi = typeof window !== 'undefined' ? window : globalThis;
    const timerId = timerApi.setTimeout(() => {
      setMessage(prev => (prev === message ? '' : prev));
    }, delay);

    return () => timerApi.clearTimeout(timerId);
  }, [message, setMessage, delay, disabled, keepWhile]);
};

