const NavigationIntentService = {
  create(tab, intent = {}) {
    const requestedAt = Date.now();
    return {
      ...intent,
      id: intent.id || `guided_${tab}_${requestedAt}`,
      requestedAt,
      source: intent.source || 'workflow_guide'
    };
  },
  returnTo(tab, intent = null) {
    return {
      tab,
      intent: intent ? { ...intent } : null
    };
  },
  resume(tab, intent = null) {
    const requestedAt = Date.now();
    return {
      ...(intent || {}),
      id: `guided_return_${tab}_${requestedAt}`,
      requestedAt,
      source: 'workflow_return'
    };
  }
};

