const hasEmployeePayrollCompensationConfig = (employee = {}) => {
  if (!employee || employee.isArchived) return false;
  // Cộng tác viên chỉ hưởng hoa hồng theo doanh thu, không bắt buộc có lương cơ bản.
  if (isSalesCollaboratorPosition(employee.position)) return true;
  const salaryCandidates = [
    employee.salary,
    employee.baseSalary,
    employee.monthlySalary,
    employee.basicSalary,
    employee.dailySalary,
    employee.hourlySalary,
    employee.supportSalary,
    employee.responsibilitySalary,
    employee.experienceSalary,
    employee.overtimeRate,
    employee.roleSalary,
    employee.salaryByRole,
    employee.positionSalary
  ].flatMap(value => (value && typeof value === 'object' && !Array.isArray(value) ? Object.values(value) : [value]));
  const hasDirectSalary = salaryCandidates.some(value => parseEmployeeRoleSalaryAmount(value) > 0);
  const hasRoleSalary = normalizeEmployeeRoleSalaryComponents(
    employee.roleSalaryComponents || employee.departmentSalaryComponents || employee.salaryByDepartment
  ).some(row => parseEmployeeRoleSalaryAmount(row.amount) > 0);
  const commissionRate = parseFloat(employee.commissionRate || 0);
  const hasSalesCommission = isEmployeeSalesPosition(employee) && Number.isFinite(commissionRate) && commissionRate > 0;
  return hasDirectSalary || hasRoleSalary || hasSalesCommission;
};

const ModuleDependencyService = {
  hasCustomers(customers = []) {
    return (customers || []).some(customer => !customer?.isArchived && normalizeLookupText(customer?.name || customer?.phone || ''));
  },
  hasProducts(products = []) {
    return (products || []).some(product => !product?.isArchived && normalizeLookupText(product?.name || product?.shortName || product?.category || ''));
  },
  hasEmployees(employees = []) {
    return (employees || []).some(item => !item?.isArchived && normalizeLookupText(item?.name || item?.phone || ''));
  },
  hasPayrollConfig(employees = []) {
    return (employees || []).some(item => hasEmployeePayrollCompensationConfig(item));
  },
  getEmployeesMissingPayrollConfig(employees = []) {
    return (employees || []).filter(item => item?.id && !item?.isArchived && !hasEmployeePayrollCompensationConfig(item));
  },
  getSalesSetupSteps({ hasCustomers = false, hasProducts = false } = {}) {
    return [
      { label: 'Có ít nhất 1 khách hàng', done: hasCustomers, hint: 'Dùng để chọn người mua và theo dõi công nợ.' },
      { label: 'Có ít nhất 1 sản phẩm', done: hasProducts, hint: 'Dùng để lên đơn, xuất kho và tính doanh thu.' }
    ];
  },
  getTodayDispatches(dispatches = [], targetDate = getTodayString()) {
    return (dispatches || []).filter(dispatch => {
      if (!dispatch || dispatch.isArchived || dispatch.deleted || dispatch.status === 'deleted') return false;
      return resolveEntityDateKey(dispatch, targetDate) === targetDate;
    });
  },
  getDispatchesForUser(dispatches = [], employee = null, shouldRestrict = false) {
    if (!shouldRestrict || !employee?.id) return dispatches || [];
    const employeeId = `${employee.id}`;
    return (dispatches || []).filter(dispatch => getDeliveryAssignmentIds(dispatch).includes(employeeId));
  },
  getDispatchCustomerIds(dispatches = []) {
    return Array.from(new Set((dispatches || [])
      .map(dispatch => `${dispatch?.customerId || dispatch?.customer?.id || dispatch?.customer_id || ''}`.trim())
      .filter(Boolean)));
  },
  getCustomerGpsStats(customers = [], customerIds = []) {
    const idSet = new Set((customerIds || []).map(id => `${id}`));
    const scopedCustomers = (customers || []).filter(customer => {
      if (!customer || customer.isArchived) return false;
      if (!idSet.size) return true;
      return idSet.has(`${customer.id}`);
    });
    const withGps = scopedCustomers.filter(customer => Boolean(extractCustomerCoordinates(customer)));
    return {
      total: scopedCustomers.length,
      withGps: withGps.length,
      missing: Math.max(0, scopedCustomers.length - withGps.length)
    };
  },
  hasSepayConfig(company = {}) {
    const profile = getInvoiceTransferProfile(company || {});
    return Boolean(profile?.bankId && profile?.accountName && profile?.sepayReceivingAccountNumber);
  },
  hasPaymentWork(orders = [], payments = []) {
    return (orders || []).some(order => Number(order?.total || order?.totalAmount || order?.amount || 0) > 0)
      || (payments || []).some(payment => Number(payment?.amount || payment?.paidAmount || 0) > 0);
  }
};

