  const selectedProductDisplayName = selectedProductShortLabel || selectedProduct?.name || selectedDispatch?.productNameSnapshot || 'Hàng hóa';
  const expectedWeightKg = parseLooseQuantityValue(selectedDispatch?.weightKg);
