  const updateDraft = (localId, patch) => {
    setRequestDrafts(prev => prev.map(draft => {
      if (draft.localId !== localId) return draft;
      const nextPatch = typeof patch === 'function' ? patch(draft) : patch;
      return { ...draft, ...nextPatch };
    }));
  };

