const EMPLOYEE_DOCUMENT_TYPES = [
  { id: 'id_card', label: 'Can cuoc' },
  { id: 'driver_license', label: 'Bang lai' },
  { id: 'labor_contract', label: 'Hop dong lao dong' },
  { id: 'job_application', label: 'Don xin viec' },
  { id: 'health_certificate', label: 'Giay kham suc khoe' },
  { id: 'other', label: 'Khac' }
];
const EMPLOYEE_DOCUMENT_MAX_BYTES = 450 * 1024;
const EMPLOYEE_DOCUMENT_TOTAL_MAX_BYTES = 700 * 1024;
const normalizeEmployeeDocuments = (documents = []) => (
  Array.isArray(documents)
    ? documents
      .filter(Boolean)
      .map((doc, index) => ({
        id: doc.id || `employee_doc_${index}_${doc.uploadedAt || Date.now()}`,
        type: doc.type || 'other',
        typeLabel: doc.typeLabel || EMPLOYEE_DOCUMENT_TYPES.find(item => item.id === doc.type)?.label || 'Khac',
        fileName: doc.fileName || doc.name || `giay-to-${index + 1}`,
        mimeType: doc.mimeType || doc.typeMime || 'application/octet-stream',
        size: Number(doc.size || 0),
        dataUrl: doc.dataUrl || doc.url || '',
        uploadedAt: doc.uploadedAt || doc.createdAt || new Date().toISOString()
      }))
    : []
);
const getEmployeeDocumentTypeLabel = (type = 'other') => (
  EMPLOYEE_DOCUMENT_TYPES.find(item => item.id === type)?.label || 'Khac'
);
const formatEmployeeDocumentSize = (size = 0) => {
  const bytes = Number(size || 0);
  if (!bytes) return '';
  if (bytes < 1024 * 1024) return `${Math.max(1, Math.round(bytes / 1024))} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
};

const EMPLOYEE_REVIEW_BONUS_BY_CRITERIA_STAR = {
  0: 0,
  1: 10000,
  2: 20000,
  3: 30000,
  4: 50000,
  5: 100000
};

const normalizeEmployeeReviewMonthKey = (value) => {
  const raw = `${value || ''}`.trim();
  if (/^\d{4}-\d{2}$/.test(raw)) return raw;
  const dateKey = getDateKeyFromAnyValue(raw) || getTodayString();
  return `${dateKey}`.slice(0, 7);
};

const getEmployeeReviewDateKey = (item = {}) => (
  getDateKeyFromAnyValue(item.date || item.createdAt || item.updatedAt || getEntityTimestamp(item)) || getTodayString()
);

const getMinutesFromTimeString = (value = '') => {
  const match = `${value || ''}`.match(/(\d{1,2}):(\d{2})/);
  if (!match) return null;
  return (parseInt(match[1], 10) * 60) + parseInt(match[2], 10);
};

const getCheckTimeMinutes = (value) => {
  if (!value) return null;
  if (value instanceof Date && !Number.isNaN(value.getTime())) return (value.getHours() * 60) + value.getMinutes();
  if (typeof value === 'string') {
    const parsed = new Date(value);
    if (!Number.isNaN(parsed.getTime())) return (parsed.getHours() * 60) + parsed.getMinutes();
    return getMinutesFromTimeString(value);
  }
  if (typeof value === 'object') {
    const seconds = Number(value.seconds || value._seconds || 0);
    if (seconds > 0) {
      const parsed = new Date(seconds * 1000);
      return (parsed.getHours() * 60) + parsed.getMinutes();
    }
  }
  return null;
};

const getEmployeeReviewStars = (score = 0) => {
  const value = Math.max(0, Math.min(100, Number(score || 0)));
  if (value <= 0) return 0;
  if (value >= 90) return 5;
  if (value >= 80) return 4;
  if (value >= 65) return 3;
  if (value >= 50) return 2;
  return 1;
};

const getEmployeeAttendanceEntriesForMonth = (attendance = {}, empId = '', monthKey = '') => (
  Object.values(attendance || {}).filter(record => (
    `${record?.empId || record?.employeeId || ''}` === `${empId || ''}` &&
    normalizeEmployeeReviewMonthKey(record?.date || record?.dateKey || record?.createdAt || getEntityTimestamp(record)) === monthKey
  ))
);

const getEmployeeReviewOrderAmount = (order = {}) => (
  parseLooseMoneyValue(order.totalAmount ?? order.total ?? order.amount ?? order.finalAmount ?? order.grandTotal ?? order.revenue ?? 0)
);

const isOrderRelatedToEmployeeReview = (order = {}, empId = '') => {
  const employeeId = `${empId || ''}`;
  if (!employeeId) return false;
  return [
    order.empId,
    order.employeeId,
    order.salesEmployeeId,
    order.createdByEmpId,
    order.createdBy,
    order.ownerEmpId,
    order.salesPersonId
  ].some(id => `${id || ''}` === employeeId);
};

const isDeliveryReportRelatedToEmployeeReview = (report = {}, empId = '') => {
  const employeeId = `${empId || ''}`;
  if (!employeeId) return false;
  return [
    report.empId,
    report.employeeId,
    report.driverId,
    report.createdByEmpId,
    report.createdBy
  ].some(id => `${id || ''}` === employeeId);
};

